var TOPICS_DATA = TOPICS_DATA || {};
TOPICS_DATA["cdn"] = TOPICS_DATA["cdn"] || {};
TOPICS_DATA["cdn"]["cdn-fundamentals"] = {"id":"cdn-fundamentals","title":"CDN Fundamentals","difficulty":"beginner","estimatedMinutes":20,"tldr":["A CDN (Content Delivery Network) is a distributed network of servers that delivers web content to users based on their geographic location.","CDNs reduce latency by caching content on edge servers closer to end users, minimizing the distance data must travel.","Key benefits: faster page loads, reduced bandwidth costs, increased content availability and redundancy, improved security against DDoS attacks.","CDNs handle both static content (images, CSS, JS) and dynamic content (API responses, HTML pages) through various optimization techniques."],"laymanDefinition":"A CDN is like a chain of neighborhood grocery stores instead of one giant supermarket downtown. Instead of everyone traveling to the city center for milk, you walk to your local store. The store keeps the popular items stocked locally, and if you need something rare, it fetches it from the central warehouse. Everyone gets their milk faster.","deepDive":[{"heading":"How CDNs Work","text":"When a user requests content, the CDN routes the request to the nearest edge server. If the edge server has the content cached, it serves it directly (cache hit). If not, it fetches from the origin server, caches it, and serves it. This reduces latency by 50-80% for users far from the origin."},{"heading":"CDN Architecture Components","text":"Origin server: the source of truth where original content lives. Edge servers: distributed cache nodes at Points of Presence (PoPs) worldwide. Request routing: DNS-based or Anycast routing directs users to the nearest edge. Caching layer: stores copies of content with configurable TTLs."},{"heading":"CDN Benefits Beyond Speed","text":"DDoS mitigation: CDNs absorb large traffic spikes across their distributed infrastructure. SSL/TLS termination: edge servers handle encryption, reducing load on origin. Traffic analytics: detailed insights into global traffic patterns. Origin offload: caches can serve 90%+ of traffic, dramatically reducing origin server load."},{"heading":"CDN vs Web Hosting","text":"A CDN is not a replacement for web hosting. The origin server still hosts the authoritative content. The CDN sits in front as a caching and acceleration layer. Web hosting stores your site; a CDN accelerates delivery of that site globally. Many cloud providers offer integrated hosting + CDN solutions (e.g., AWS S3 + CloudFront)."},{"heading":"Global Reach and Scaling","text":"Major CDNs have 100-300+ PoPs worldwide. Cloudflare: 330+ cities in 120+ countries. Akamai: 4100+ locations. AWS CloudFront: 600+ PoPs. This global footprint ensures consistent performance regardless of user location. CDNs automatically scale to handle traffic spikes without provisioning additional origin capacity."}],"interviewAnswer":"A CDN is a globally distributed network of proxy servers that caches content closer to users, reducing latency, offloading origin servers, and providing DDoS protection. It is essential for modern web applications serving a global audience.","interviewQuestions":[{"question":"What is a CDN?","answer":"A Content Delivery Network — a distributed network of servers that delivers web content to users based on their geographic location."},{"question":"What are the main benefits of using a CDN?","answer":"Reduced latency, lower bandwidth costs, increased availability, improved security (DDoS mitigation), and origin server offloading."},{"question":"How does a CDN reduce latency?","answer":"By caching content on edge servers closer to users, reducing the physical distance data must travel."},{"question":"What is the difference between an edge server and an origin server?","answer":"The origin server is the source of truth; edge servers are distributed cache nodes that store copies of content closer to users."},{"question":"What is origin offload?","answer":"When a CDN serves cached content, reducing the number of requests that reach the origin server — often 90%+ of requests."},{"question":"Does a CDN replace web hosting?","answer":"No. A CDN is a caching and acceleration layer in front of your origin server. You still need an origin server."},{"question":"What is a Point of Presence (PoP)?","answer":"A physical location where the CDN has edge servers. More PoPs means better global coverage."},{"question":"How does a CDN protect against DDoS?","answer":"By absorbing attack traffic across its distributed infrastructure, preventing it from overwhelming the origin server."},{"question":"What types of content can a CDN accelerate?","answer":"Both static (images, CSS, JS) and dynamic (API responses, HTML) content."},{"question":"What is Anycast routing?","answer":"A networking technique where multiple servers share the same IP address; traffic routes to the nearest server automatically."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">CDN Fundamentals</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Origin Server</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Source of truth</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"225\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Edge Servers</text><text x=\"225\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Distributed cache</text><line x1=\"290\" y1=\"48\" x2=\"320\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"330\" y=\"35\" width=\"150\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"405\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">End Users</text><text x=\"405\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Nearest edge</text><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DNS Routing</text><text x=\"65\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Nearest PoP</text><rect x=\"10\" y=\"100\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Caching</text><text x=\"65\" y=\"119\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">TTL-based</text><rect x=\"10\" y=\"130\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DDoS Shield</text><text x=\"65\" y=\"149\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Absorb attacks</text><rect x=\"10\" y=\"160\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"65\" y=\"176\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Analytics</text><text x=\"65\" y=\"179\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Traffic insights</text><line x1=\"120\" y1=\"83\" x2=\"150\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"113\" x2=\"150\" y2=\"113\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"143\" x2=\"150\" y2=\"143\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"173\" x2=\"150\" y2=\"173\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"70\" width=\"310\" height=\"140\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"315\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CDN (Content Delivery Network)</text><text x=\"315\" y=\"193\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Distributed network that accelerates content delivery by</text><text x=\"315\" y=\"204\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\"> caching at edge servers near users.</text><text x=\"240\" y=\"225\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">CDN Fundamentals: Global network of edge servers c</text><text x=\"240\" y=\"237\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">aching content closer to users for faster, more re</text><text x=\"240\" y=\"249\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">liable delivery.</text></svg>","codeExamples":[{"title":"CDN Cache Configuration (CloudFront)","useCase":"Setting up a basic CloudFront distribution.","code":"aws cloudfront create-distribution \\\n  --origin-domain-name mybucket.s3.amazonaws.com \\\n  --default-root-object index.html \\\n  --enabled \\\n  --default-cache-behavior \\\n    \"TargetOriginId=myOrigin,\n     ViewerProtocolPolicy=redirect-to-https,\n     MinTTL=0,DefaultTTL=86400,MaxTTL=31536000,\n     AllowedMethods=[GET,HEAD],\n     CachedMethods=[GET,HEAD],\n     ForwardedValues={QueryString=false}\"\n  --price-class PriceClass_All","description":"AWS CLI command to create a CloudFront distribution with standard caching settings."},{"title":"CDN Headers (Response Headers)","useCase":"Common CDN-related response headers.","code":"# Server response headers showing CDN usage\nHTTP/1.1 200 OK\nContent-Type: text/html\nContent-Length: 4523\nCache-Control: public, max-age=3600\nx-cache: HIT from cloudfront\nx-amz-cf-pop: JFK50-P1\nx-amz-cf-id: abc123def456\nAge: 234\nVia: 1.1 varnish-v4\nCF-Cache-Status: HIT\nCF-Ray: 4a5b6c7d8e9f-JFK","description":"Response headers indicating CDN activity — the x-cache, Age, and CF-Cache-Status headers show caching behavior."},{"title":"CDN with Nginx Reverse Proxy Cache","useCase":"Using Nginx as a caching layer.","code":"proxy_cache_path /var/cache/nginx levels=1:2\n  keys_zone=mycache:10m max_size=1g\n  inactive=60m use_temp_path=off;\n\nserver {\n  listen 80;\n  server_name cdn.example.com;\n\n  location / {\n    proxy_cache mycache;\n    proxy_cache_valid 200 302 60m;\n    proxy_cache_valid 404 1m;\n    proxy_cache_use_stale error timeout updating;\n    add_header X-Cache-Status $upstream_cache_status;\n\n    proxy_pass http://origin-server:8080;\n    proxy_set_header Host $host;\n    proxy_set_header X-Real-IP $remote_addr;\n  }\n}","description":"Nginx configured as a caching reverse proxy with cache status headers."},{"title":"CDN Integration with HTML","useCase":"Loading resources via CDN.","code":"<!DOCTYPE html>\n<html>\n<head>\n  <!-- CSS via CDN -->\n  <link rel=\"stylesheet\"\n    href=\"https://cdn.example.com/css/app.abc123.css\">\n\n  <!-- Font via CDN -->\n  <link rel=\"stylesheet\"\n    href=\"https://fonts.cdnfonts.com/css/inter\">\n</head>\n<body>\n  <!-- Image via CDN -->\n  <img src=\"https://cdn.example.com/img/hero.webp\"\n       alt=\"Hero\" loading=\"lazy\">\n\n  <!-- JS via CDN -->\n  <script\n    src=\"https://cdn.example.com/js/bundle.xyz789.js\"\n    defer></script>\n</body>\n</html>","description":"HTML page loading all static assets through a CDN for optimal performance."},{"title":"Flush CDN Cache (CloudFront)","useCase":"Invalidating cached content.","code":"# Invalidate specific paths\naws cloudfront create-invalidation \\\n  --distribution-id E123456789ABCD \\\n  --paths \"/images/*\" \"/css/*\"\n\n# Invalidate entire distribution\naws cloudfront create-invalidation \\\n  --distribution-id E123456789ABCD \\\n  --paths \"/*\"\n\n# Note: invalidation costs money ($0.005 per path)\n# Use versioned filenames to avoid invalidations:\n#   style.abc123.css instead of style.css\n#   script.xyz789.js instead of script.js","description":"CloudFront invalidation commands to purge cached content."},{"title":"CDN Performance Testing with Curl","useCase":"Measure CDN response times.","code":"# Check cache headers and response time\ncurl -s -o /dev/null -w \"\\n\n  HTTP Code: %{http_code}\\n\n  DNS Lookup: %{time_namelookup}s\\n\n  Connect: %{time_connect}s\\n\n  TLS Handshake: %{time_appconnect}s\\n\n  TTFB: %{time_starttransfer}s\\n\n  Total: %{time_total}s\\n\n  Speed: %{speed_download} B/s\\n\" \\\n  -H \"Cache-Control: no-cache\" \\\n  https://cdn.example.com/image.jpg\n\n# Compare with direct origin access\ncurl -s -o /dev/null -w \"Time: %{time_total}s\"\n  https://origin.example.com/image.jpg","description":"Curl commands to measure CDN performance and compare with direct origin access."}],"mcqQuestions":[{"question":"What does CDN stand for?","options":["Content Distribution Network","Content Delivery Network","Central Data Network","Cache Distribution Node"],"answer":1,"explanation":"CDN = Content Delivery Network."},{"question":"What is the primary purpose of a CDN?","options":["Store backups","Reduce latency by caching content near users","Host websites","Manage databases"],"answer":1,"explanation":"CDNs primarily reduce latency by caching content on edge servers closer to users."},{"question":"What is a Point of Presence (PoP)?","options":["A DNS record type","A physical location with edge servers","A compression algorithm","A caching policy"],"answer":1,"explanation":"A PoP is a physical location where a CDN has edge servers."},{"question":"How does a CDN protect against DDoS?","options":["By blocking all traffic","By absorbing attacks across distributed infrastructure","By rate limiting only","By shutting down the server"],"answer":1,"explanation":"CDNs absorb DDoS traffic across their globally distributed network."},{"question":"What does origin offload mean?","options":["Removing the origin server","Serving cached content reduces origin load","Offloading data to tape storage","Migrating to a new host"],"answer":1,"explanation":"Origin offload means the CDN serves most requests, reducing load on the origin server."},{"question":"Which header indicates a cache hit?","options":["Cache-Control","x-cache: HIT","Content-Type","Accept-Encoding"],"answer":1,"explanation":"Headers like x-cache: HIT or CF-Cache-Status: HIT indicate a cache hit from the CDN."},{"question":"What is Anycast routing?","options":["Traffic goes to a random server","Multiple servers share one IP, traffic routes to nearest","Traffic is broadcast to all servers","DNS-based routing only"],"answer":1,"explanation":"Anycast allows multiple servers to share the same IP, automatically routing to the nearest one."},{"question":"Does a CDN replace web hosting?","options":["Yes","No, it is an acceleration layer","Only for static sites","Only for video streaming"],"answer":1,"explanation":"A CDN is an acceleration layer in front of an origin server, not a replacement for hosting."},{"question":"What is a common method to avoid cache invalidation?","options":["Delete the cache daily","Use versioned filenames (fingerprinting)","Disable caching","Increase TTL forever"],"answer":1,"explanation":"Versioned filenames (like style.abc123.css) allow permanent caching and avoid the need for invalidation."},{"question":"What percentage of traffic can a CDN typically offload?","options":["About 10%","About 50%","90% or more","100%"],"answer":2,"explanation":"CDNs can offload 90%+ of traffic from origin servers for cacheable content."}]};
TOPICS_DATA["cdn"]["cdn-edge-servers"] = {"id":"cdn-edge-servers","title":"Edge Servers","difficulty":"beginner","estimatedMinutes":15,"tldr":["Edge servers are the distributed cache nodes in a CDN that store and serve content to end users from locations close to them.","They are deployed at Points of Presence (PoPs) worldwide — physical data centers with compute, storage, and networking equipment.","Edge servers handle: content caching, SSL termination, request routing, compression, image optimization, and security filtering.","Modern edge servers also support serverless computing (edge functions/workers) allowing code execution at the edge."],"laymanDefinition":"Edge servers are like local food trucks stationed in different neighborhoods. Instead of everyone driving to the central restaurant (origin server), each neighborhood has its own truck stocked with popular menu items. If your neighborhood truck doesn't have what you want, it calls the central kitchen to get it and adds it to its menu for next time.","deepDive":[{"heading":"Edge Server Architecture","text":"Each edge server runs a caching engine (Varnish, Nginx, Apache Traffic Server) configured with origin addresses and caching rules. They maintain a local disk/memory cache, connection pools to origins, and health-checking mechanisms. Modern edge servers use SSD storage for fast content retrieval."},{"heading":"Request Flow Through Edge","text":"1. User DNS lookup resolves to nearest edge PoP. 2. Edge server receives HTTP request. 3. Checks local cache. 4. Cache hit: serve immediately. 5. Cache miss: forward to origin (or parent cache tier), cache response, serve to user. 6. Response headers include x-cache: HIT/MISS and Age header."},{"heading":"Edge Cache Tiering","text":"Multi-tier caching: edge (L1) to regional (L2) to origin. L1 edge servers cache popular content. Misses go to L2 regional cache (larger, serves a region). L2 misses go to origin. This reduces origin load while keeping edge storage efficient. CloudFront, Akamai, and Fastly all use multi-tier architectures."},{"heading":"Edge Compute (Workers/Functions)","text":"CDNs like Cloudflare Workers, Fastly Compute@Edge, and CloudFront Functions allow running JavaScript/WASM at the edge. Use cases: A/B testing, geo-based redirects, authentication checks, header modification, API aggregation — all served from the edge without touching the origin."},{"heading":"Edge Server Hardware","text":"Typical edge servers: high-core-count CPUs, 256GB-1TB RAM, multiple NVMe SSDs (2-8TB), 10-100Gbps network interfaces. They sit in carrier-neutral data centers with direct peering to ISPs. Power redundancy (dual power feeds), multiple network uplinks, and hardware security modules (HSMs) for key storage."}],"interviewAnswer":"Edge servers are the distributed nodes in a CDN that cache and serve content from locations close to end users. They handle caching, SSL, compression, security filtering, and increasingly support serverless compute workloads at the network edge.","interviewQuestions":[{"question":"What is an edge server?","answer":"A distributed cache node in a CDN deployed at Points of Presence worldwide that serves content to nearby users."},{"question":"Where are edge servers located?","answer":"At Points of Presence (PoPs) — physical data centers distributed globally."},{"question":"What is multi-tier caching?","answer":"A hierarchical cache architecture: edge (L1) to regional (L2) to origin. Reduces origin load while keeping edge storage efficient."},{"question":"What is edge compute?","answer":"Running code (JavaScript/WASM) on edge servers for A/B testing, geo-redirects, authentication, and API aggregation."},{"question":"What is a cache hit vs miss at the edge?","answer":"Hit: edge server has content cached and serves it directly. Miss: edge must fetch from origin or parent cache tier."},{"question":"What are common caching engines used on edge servers?","answer":"Varnish Cache, Nginx, Apache Traffic Server, and custom proprietary engines."},{"question":"What is the Age header?","answer":"Indicates how many seconds the cached response has been stored on the edge server since it was fetched from the origin."},{"question":"What hardware do edge servers use?","answer":"High-core CPUs, 256GB-1TB RAM, NVMe SSDs, 10-100Gbps networking, redundant power and network."},{"question":"What is origin shielding?","answer":"A dedicated edge tier that aggregates requests to the origin, preventing cache stampedes."},{"question":"How do edge servers handle SSL?","answer":"They terminate SSL/TLS connections, decrypt requests, and re-encrypt when forwarding to origin (or use HTTPS throughout)."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Edge Servers</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">User Request</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">DNS to nearest</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"230\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Edge Server (L1)</text><text x=\"230\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Check cache</text><line x1=\"300\" y1=\"48\" x2=\"330\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"310\" y1=\"60\" x2=\"310\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"340\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"410\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cache Hit?</text><text x=\"410\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Serve to user</text><rect x=\"10\" y=\"75\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cache Miss</text><text x=\"65\" y=\"94\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fetch from L2</text><line x1=\"120\" y1=\"88\" x2=\"150\" y2=\"88\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"75\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"230\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Regional Cache (L2)</text><text x=\"230\" y=\"94\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Larger cache pool</text><line x1=\"300\" y1=\"88\" x2=\"330\" y2=\"88\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"340\" y=\"75\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"410\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Origin Server</text><text x=\"410\" y=\"94\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Source of truth</text><text x=\"240\" y=\"180\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Edge Servers: Distributed cache nodes at PoPs worl</text><text x=\"240\" y=\"192\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">dwide that serve content from locations close to u</text><text x=\"240\" y=\"204\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">sers.</text></svg>","codeExamples":[{"title":"Edge Server Cache Status Check","useCase":"Using curl to see CDN edge behavior.","code":"# Check if a CDN is being used and cache status\ncurl -I https://cdn.example.com/style.css\n\n# Look for these headers:\n# x-cache: HIT from cloudfront\n# x-cache: Miss from cloudfront\n# CF-Cache-Status: HIT\n# CF-Cache-Status: MISS\n# CF-Cache-Status: DYNAMIC\n# Age: 1234 (seconds since cached)\n# x-served-by: cache-jfk1234","description":"Use curl to check cache status headers from edge servers."},{"title":"CloudFront Regional Edge Caches","useCase":"Configuring multi-tier caching.","code":"# By default CloudFront uses regional edge caches\n# They are automatically enabled\n\n# Regional caches sit between edge locations\n# and your origin server\n\n# When an edge location misses:\n# 1. Edge fetches from regional cache\n# 2. Regional cache serves if it has content\n# 3. Regional cache fetches from origin if needed\n\n# Benefits:\n# - Reduces load on origin server\n# - Improves cache hit ratio\n# - Lowers egress costs\n# - No additional configuration needed","description":"CloudFront automatically uses regional edge caches as a middle tier between edge locations and origin."},{"title":"Edge Worker (Cloudflare Workers)","useCase":"Running code at the CDN edge.","code":"// Cloudflare Worker - runs on every edge server\nexport default {\n  async fetch(request) {\n    const url = new URL(request.url);\n    const country = request.cf.country;\n\n    // Geo-based redirect at edge\n    if (country === \"GB\" &&\n        url.pathname.startsWith(\"/us/\")) {\n      return Response.redirect(\n        \"https://uk.example.com\" + url.pathname.replace(\"/us/\", \"/uk/\")\n      );\n    }\n\n    // Cache API response at edge\n    const cache = caches.default;\n    let response = await cache.match(request);\n    if (!response) {\n      response = await fetch(request);\n      if (response.status === 200) {\n        const headers = new Headers(response.headers);\n        headers.set(\"Cache-Control\", \"public, max-age=3600\");\n        response = new Response(response.body, {\n          headers, status: response.status\n        });\n        ctx.waitUntil(cache.put(request, response.clone()));\n      }\n    }\n    return response;\n  }\n}","description":"Cloudflare Worker running geolocation logic at the edge server without hitting the origin."},{"title":"Varnish Edge Cache Configuration","useCase":"Open-source edge caching engine.","code":"# Varnish Cache Configuration (default.vcl)\nvcl 4.1;\n\nbackend origin {\n  .host = \"origin.example.com\";\n  .port = \"8080\";\n}\n\nsub vcl_recv {\n  # Remove cookies for static files\n  if (req.url ~ \"\\.(css|js|png|jpg|webp|woff2)$\") {\n    unset req.http.Cookie;\n  }\n\n  # Cache GET and HEAD only\n  if (req.method != \"GET\" && req.method != \"HEAD\") {\n    return (pass);\n  }\n}\n\nsub vcl_backend_response {\n  # Set longer TTL for static assets\n  if (bereq.url ~ \"\\.(css|js|png|jpg)$\") {\n    set beresp.ttl = 24h;\n  }\n}\n\nsub vcl_deliver {\n  # Add cache status header\n  if (obj.hits > 0) {\n    set resp.http.X-Cache = \"HIT\";\n  } else {\n    set resp.http.X-Cache = \"MISS\";\n  }\n}","description":"Varnish configuration for edge server caching with cache status headers."},{"title":"Fastly Edge Dictionary","useCase":"Edge data store for lookups.","code":"# Fastly VCL using edge dictionary for config\n\n# Create a dictionary in Fastly UI:\n# Name: redirect_map\n# Items:\n#   /old-page -> /new-page\n#   /about -> /company/about\n#   /contact -> /get-in-touch\n\nsub vcl_recv {\n  # Look up redirect in edge dictionary\n  declare local var.target STRING;\n  set var.target = table.lookup(\n    redirect_map, req.url.path, \"\"\n  );\n\n  if (var.target != \"\") {\n    # Perform redirect at edge - no origin hit\n    error 750 var.target;\n  }\n}\n\nsub vcl_error {\n  if (obj.status == 750) {\n    set obj.status = 302;\n    set obj.http.Location = obj.response;\n    return (deliver);\n  }\n}","description":"Fastly edge dictionaries allow low-latency data lookups at the edge server."}],"mcqQuestions":[{"question":"What is an edge server?","options":["A database server","A distributed CDN cache node near users","A DNS server","An email server"],"answer":1,"explanation":"Edge servers are CDN cache nodes located near end users."},{"question":"Where are edge servers deployed?","options":["In the origin data center","At Points of Presence worldwide","On user devices","In a single location"],"answer":1,"explanation":"Edge servers are deployed at PoPs worldwide."},{"question":"What is multi-tier caching?","options":["Multiple cache types","A hierarchical cache: edge to regional to origin","Caching multiple file types","Parallel cache servers"],"answer":1,"explanation":"Multi-tier caching uses a hierarchy of edge (L1) and regional (L2) caches before the origin."},{"question":"What is edge compute?","options":["Database queries at the edge","Running code on edge servers (workers/functions)","Caching compute results","Load balancing"],"answer":1,"explanation":"Edge compute allows running code like Cloudflare Workers on edge servers."},{"question":"What header indicates a cache hit?","options":["Cache-Control","Age","X-Cache: HIT","Content-Length"],"answer":2,"explanation":"Headers like X-Cache: HIT or CF-Cache-Status: HIT show a cache hit at the edge."},{"question":"What is origin shielding?","options":["Encrypting origin data","A cache tier that aggregates requests to origin","Firewall for origin","Backup origin server"],"answer":1,"explanation":"Origin shielding uses a dedicated cache tier to aggregate requests and protect the origin."}]};
TOPICS_DATA["cdn"]["cdn-edge-locations"] = {"id":"cdn-edge-locations","title":"Edge Locations","difficulty":"beginner","estimatedMinutes":15,"tldr":["Edge locations are the physical data center sites where CDN edge servers are deployed — the geographic Points of Presence (PoPs).","Major CDNs have hundreds to thousands of edge locations worldwide. Cloudflare has 330+ cities, AWS CloudFront has 600+ PoPs, Akamai has 4100+ locations.","More edge locations means shorter distances between users and content, resulting in lower latency and faster load times.","Edge locations are strategically placed in major internet hubs with direct peering to ISPs and internet exchanges for optimal connectivity."],"laymanDefinition":"Edge locations are like Amazon fulfillment centers. Amazon doesn't ship every package from one central warehouse — they have fulfillment centers near major cities. If you live in Chicago, your package comes from a nearby warehouse, not from across the country. More fulfillment centers means faster delivery for everyone.","deepDive":[{"heading":"Strategic Placement","text":"Edge locations are placed in major metropolitan areas with high population density, near internet exchange points (IXPs), and in carrier-neutral data centers. Providers peer directly with major ISPs to minimize network hops. Locations are chosen based on traffic patterns, latency measurements, and population distribution."},{"heading":"Coverage Maps","text":"CDNs publish their edge location maps. Cloudflare: 330+ cities across 120+ countries. AWS CloudFront: 600+ PoPs across 90+ cities. Fastly: 60+ PoPs. Smaller CDNs may have 20-50 PoPs. Global coverage is not uniform — North America, Europe, and Asia have dense coverage; Africa and South America have fewer locations."},{"heading":"How Locations Impact Performance","text":"Each additional edge location reduces the average distance between users and content. Metric: 95th percentile latency. Adding a PoP in a region can reduce latency from 200ms to 20ms for users in that region. CDNs use real-time monitoring to optimize traffic routing across edge locations."},{"heading":"Edge Location Selection","text":"When a user requests content, the CDN selects the best edge location based on: geographic proximity (lowest latency), current server load, cache availability, and origin health. If the nearest edge location is overloaded, traffic is routed to the next closest. This dynamic routing improves reliability."},{"heading":"Regional Coverage Differences","text":"North America: dense coverage with PoPs in every major city. Europe: excellent coverage across all countries. Asia Pacific: good coverage in developed countries, expanding in developing markets. Middle East and Africa: limited coverage, often served from European PoPs. South America: coverage in major cities, expanding."}],"interviewAnswer":"Edge locations are the physical data center sites (PoPs) where CDN edge servers are deployed. More locations mean lower latency for users worldwide. CDNs strategically place them near internet exchanges and major population centers for optimal performance.","interviewQuestions":[{"question":"What are edge locations?","answer":"Physical data center sites where CDN edge servers are deployed — also called Points of Presence (PoPs)."},{"question":"How many edge locations does a typical CDN have?","answer":"Varies widely: Cloudflare 330+, CloudFront 600+, Akamai 4100+. Smaller CDNs may have 20-50."},{"question":"Why do more edge locations improve performance?","answer":"More locations mean shorter distances between users and content, reducing latency."},{"question":"Where are edge locations typically placed?","answer":"In major metropolitan areas near internet exchange points and carrier-neutral data centers."},{"question":"How does a CDN select which edge location to use?","answer":"Based on geographic proximity, current server load, cache availability, and origin health."},{"question":"What is an internet exchange point (IXP)?","answer":"A physical infrastructure where ISPs and CDNs connect to exchange traffic directly."},{"question":"Which continent has the most CDN edge locations?","answer":"North America and Europe have the densest coverage; Africa and South America have fewer."},{"question":"What happens if the nearest edge location is overloaded?","answer":"Traffic is automatically routed to the next closest available edge location."},{"question":"What metric measures CDN performance improvement?","answer":"95th percentile latency reduction — adding a local PoP can reduce latency from 200ms to 20ms."},{"question":"Do all CDNs have the same number of edge locations?","answer":"No — it varies greatly. More locations generally means better performance but higher cost."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Edge Locations</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">User in NY</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Requests content</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"225\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">NY Edge PoP</text><text x=\"225\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Nearest location</text><line x1=\"290\" y1=\"48\" x2=\"320\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"330\" y=\"35\" width=\"150\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"405\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">User in Sydney</text><text x=\"405\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Far from NY PoP</text><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Sydney User</text><text x=\"65\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">High latency >200ms</text><line x1=\"120\" y1=\"83\" x2=\"150\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"70\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"225\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">No Sydney PoP</text><text x=\"225\" y=\"78\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Served from Singapore o</text><text x=\"225\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">r LA</text><rect x=\"10\" y=\"100\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Ideal: Sydney PoP</text><text x=\"65\" y=\"119\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Latency <20ms</text><rect x=\"160\" y=\"100\" width=\"310\" height=\"25\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"315\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">More Edge Locations = Lower Latency</text><text x=\"315\" y=\"119\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Strategically placed near users for optimal delivery.</text><text x=\"240\" y=\"195\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Edge Locations: Physical PoPs worldwide where CDN </text><text x=\"240\" y=\"207\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">servers live — more locations = faster content del</text><text x=\"240\" y=\"219\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ivery.</text></svg>","codeExamples":[{"title":"Listing CloudFront Edge Locations","useCase":"Programmatic access to edge locations.","code":"# AWS CloudFront global edge locations (partial list)\n# North America:\n#   Ashburn, VA (x1-e) | Atlanta, GA (x1-f)\n#   Chicago, IL (x1-g) | Dallas, TX (x1-h)\n#   Los Angeles, CA (x1-l) | Miami, FL (x1-m)\n#   New York, NY (x1-n) | Seattle, WA (x1-s)\n#   San Jose, CA (x1-r) | Toronto, CA (x1-c)\n\n# Europe:\n#   Amsterdam, NL (x2-a) | Berlin, DE (x2-b)\n#   Frankfurt, DE (x2-f) | London, GB (x2-l)\n#   Madrid, ES (x2-m) | Milan, IT (x2-i)\n#   Paris, FR (x2-p) | Stockholm, SE (x2-s)\n\n# Asia Pacific:\n#   Hong Kong (x3-h) | Mumbai, IN (x3-m)\n#   Osaka, JP (x3-o) | Seoul, KR (x3-s)\n#   Singapore (x3-g) | Sydney, AU (x3-y)\n#   Tokyo, JP (x3-t)","description":"Partial list of AWS CloudFront edge locations showing global distribution."},{"title":"Checking Edge Location from Response Headers","useCase":"Identifying which PoP served the request.","code":"# Check which edge location served your request\ncurl -I https://d123.cloudfront.net/image.jpg\n\n# Look for the x-amz-cf-pop header:\n# x-amz-cf-pop: JFK50-P1\n#   JFK = New York (airport code)\n#   50 = specific edge location ID\n#   P1 = point of presence identifier\n\n# Cloudflare shows:\n# CF-Ray: 4a5b6c7d8e9f-JFK\n#   The last 3 letters = edge location code\n\n# Fastly shows:\n# x-served-by: cache-jfk1234-JFK","description":"Response headers reveal which specific edge location handled the request."},{"title":"Latency Test to Different CDNs","useCase":"Compare edge location performance.","code":"# Compare latency to different CDN edge locations\n# using mtr or ping from different regions\n\n# Test from US East\nping -c 5 d1g1p1e8n0a1.cloudfront.net\n\n# Test from Europe (use a tool or VPS)\n# ping cloudflare.com - routes to nearest edge\n\n# Use curl to measure TTFB\ncurl -s -o /dev/null -w \"TTFB: %{time_starttransfer}s \\n\" \\\n  -H \"Cache-Control: no-cache\" \\\n  https://cdn.example.com/\n\n# Key metric: time_starttransfer = Time To First Byte\n# Lower TTFB = closer edge location","description":"Commands to measure latency and identify which edge location serves your requests."},{"title":"CloudFront Origin Request Policy","useCase":"Forwarding client location to origin.","code":"# CloudFront adds headers that reveal edge location\n# These headers are automatically added:\n\n# CloudFront-Viewer-Country: US\n# CloudFront-Viewer-City: New York\n# CloudFront-Viewer-ASN: 14618\n# CloudFront-Viewer-Latitude: 40.7128\n# CloudFront-Viewer-Longitude: -74.0060\n\n# Configure in CloudFront behavior settings:\n# Forward these headers to origin\n# Origin reads them for geo-personalization\n\n# The x-amz-cf-pop header in response\n# shows which edge location served:\n# x-amz-cf-pop: JFK50-P1","description":"CloudFront forwards viewer location headers from the edge location to the origin server."},{"title":"CDN PoP Coverage Map File","useCase":"JSON-based coverage configuration.","code":"// CDN edge location data structure\nconst edgeLocations = {\n  \"north-america\": {\n    \"us-east\": [\"IAD\", \"JFK\", \"ATL\", \"MIA\"],\n    \"us-west\": [\"LAX\", \"SFO\", \"SEA\", \"PHX\"],\n    \"us-central\": [\"ORD\", \"DFW\", \"DEN\"],\n    \"canada\": [\"YYZ\", \"YVR\"]\n  },\n  \"europe\": {\n    \"western\": [\"LHR\", \"AMS\", \"CDG\", \"FRA\"],\n    \"nordic\": [\"ARN\", \"CPH\", \"OSL\"],\n    \"southern\": [\"MAD\", \"MIL\", \"FCO\"]\n  },\n  \"asia-pacific\": {\n    \"east-asia\": [\"NRT\", \"ICN\", \"HKG\", \"TPE\"],\n    \"southeast\": [\"SIN\", \"KUL\", \"BKK\"],\n    \"oceania\": [\"SYD\", \"AKL\"]\n  }\n};\n\n// Each code represents a physical PoP\n// IAD = Ashburn, VA; LHR = London; NRT = Tokyo","description":"JSON structure showing CDN edge location distribution by region."}],"mcqQuestions":[{"question":"What is an edge location?","options":["A database server location","A physical PoP where CDN servers are deployed","A user device","A DNS server"],"answer":1,"explanation":"Edge locations are physical data centers where CDN edge servers live."},{"question":"What determines the best edge location for a user?","options":["Random selection","Geographic proximity and server load","Alphabetical order","User preference"],"answer":1,"explanation":"The closest edge location with available capacity handles the request."},{"question":"Which CDN has the most edge locations?","options":["Cloudflare","Fastly","Akamai","Azure CDN"],"answer":2,"explanation":"Akamai has 4100+ locations, the most of any CDN."},{"question":"What is an IXP?","options":["Internet exchange point for direct ISP peering","Internal XML processor","Indexed data format","Input eXchange Protocol"],"answer":0,"explanation":"Internet exchange points allow ISPs and CDNs to exchange traffic directly."},{"question":"What header shows which edge location served the request?","options":["Cache-Control","x-amz-cf-pop","Content-Type","Accept-Encoding"],"answer":1,"explanation":"Headers like x-amz-cf-pop show which specific edge location handled the request."}]};
TOPICS_DATA["cdn"]["cdn-origin-server"] = {"id":"cdn-origin-server","title":"Origin Server","difficulty":"beginner","estimatedMinutes":15,"tldr":["The origin server is the authoritative source of original content — the primary server where the website or application is hosted.","The CDN pulls content from the origin server when it is not cached at the edge. The origin is the fallback for cache misses.","Origin servers can be: web servers (Nginx, Apache), cloud storage (S3 bucket, Google Cloud Storage), or application servers.","Best practices: configure appropriate Cache-Control headers on the origin, implement health checks, use origin shielding, and ensure the origin can handle CDN fetch traffic."],"laymanDefinition":"The origin server is the central kitchen in a restaurant chain. Local branches (edge servers) keep popular dishes ready to serve. But if someone orders something unusual, the branch calls the central kitchen to prepare it fresh. The central kitchen is the source of truth for all recipes and ingredients — without it, no branch can make anything new.","deepDive":[{"heading":"Origin Server Responsibilities","text":"The origin hosts the authoritative version of all content. When a CDN edge misses the cache, it makes a request to the origin. The origin responds with the content and Cache-Control headers that tell the CDN how long to cache it. The origin must be available, fast, and correctly configured for CDN usage."},{"heading":"Types of Origin Servers","text":"Web servers (Nginx, Apache, Caddy): serve dynamic and static content. Cloud storage (AWS S3, GCS, Azure Blob): serve static files directly. Application servers (Node.js, Python/WSGI, Ruby/Puma): generate dynamic responses. Load balancers (ELB, HAProxy): distribute traffic across multiple origin instances."},{"heading":"Origin Health and Monitoring","text":"CDNs continuously monitor origin health through health checks (HTTP GET to a configured path). If the origin is unhealthy, the CDN serves stale content from cache (stale-while-revalidate) or routes to a backup origin. Configure origin timeout, connection attempts, and health check intervals."},{"heading":"Origin Shielding","text":"A dedicated cache tier that sits between edge servers and the origin. All edge location misses go through the shield, which caches content and serves subsequent requests without hitting the origin. Prevents cache stampede (thundering herd) where many edges all miss simultaneously and overwhelm the origin."},{"heading":"Origin Cache-Control Configuration","text":"The origin sets TTL via Cache-Control headers. public: any cache can store. private: only browser cache (not CDN). max-age: seconds to cache. s-maxage: CDN-specific TTL (overrides max-age). stale-while-revalidate: serve stale while fetching fresh. must-revalidate: must check origin after expiry. Correct configuration is critical for CDN performance."}],"interviewAnswer":"The origin server is the authoritative source of content that the CDN pulls from. It must be properly configured with Cache-Control headers, health checks, and sufficient capacity to handle CDN fetch traffic. Origin shielding prevents cache stampedes and reduces origin load.","interviewQuestions":[{"question":"What is an origin server?","answer":"The authoritative source server where original content is hosted — the CDN pulls content from it on cache misses."},{"question":"What types of servers can be origins?","answer":"Web servers (Nginx, Apache), cloud storage (S3, GCS), application servers (Node.js), and load balancers."},{"question":"What is origin shielding?","answer":"A dedicated cache tier between edge servers and the origin that aggregates requests to prevent cache stampedes."},{"question":"What is a cache stampede (thundering herd)?","answer":"When many edge servers all miss cache simultaneously and overwhelm the origin with requests."},{"question":"What headers control CDN caching from origin?","answer":"Cache-Control: max-age, s-maxage, public, private, stale-while-revalidate, must-revalidate."},{"question":"What happens when the origin is unhealthy?","answer":"CDN serves stale cached content (stale-while-revalidate) or routes to a backup origin."},{"question":"What is the purpose of CDN health checks?","answer":"To continuously monitor origin availability and route traffic away from unhealthy origins."},{"question":"What is the difference between public and private Cache-Control?","answer":"public allows CDN caching; private restricts caching to the browser only."},{"question":"How does s-maxage differ from max-age?","answer":"s-maxage overrides max-age for shared caches (CDNs) while max-age applies to browser caches."},{"question":"Should an origin serve gzip-compressed content to CDNs?","answer":"Yes, it reduces transfer time between origin and edge servers, improving cache fill performance."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Origin Server</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">User Browser</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Requests content</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"225\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CDN Edge</text><text x=\"225\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cache check</text><line x1=\"290\" y1=\"48\" x2=\"320\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"170\" y1=\"65\" x2=\"170\" y2=\"85\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"300\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"355\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Origin Shield</text><text x=\"355\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Request aggregator</text><line x1=\"410\" y1=\"48\" x2=\"440\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"450\" y=\"35\" width=\"30\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"465\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Origin</text><text x=\"465\" y=\"43\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auth conte</text><text x=\"465\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">nt</text><rect x=\"160\" y=\"75\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"225\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cache HIT</text><text x=\"225\" y=\"94\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Serve from edge</text><rect x=\"160\" y=\"105\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"225\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cache MISS</text><text x=\"225\" y=\"124\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fetch from origin</text><text x=\"240\" y=\"195\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Origin Server: The authoritative source of content</text><text x=\"240\" y=\"207\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">. CDN fetches from origin on cache misses.</text></svg>","codeExamples":[{"title":"Nginx Origin CORS Configuration","useCase":"Setting up CORS headers for CDN origin.","code":"server {\n  listen 8080;\n  server_name origin.example.com;\n\n  # Cache-Control for different content types\n  location /static/ {\n    root /var/www;\n    add_header Cache-Control \"public, max-age=31536000, immutable\";\n    expires 1y;\n  }\n\n  location /api/ {\n    proxy_pass http://app-server:3000;\n    # Dynamic content: short cache or no cache\n    add_header Cache-Control \"no-cache, private\";\n  }\n\n  # CORS for CDN access\n  location / {\n    add_header Access-Control-Allow-Origin \"*\";\n    add_header Access-Control-Allow-Methods \"GET, HEAD, OPTIONS\";\n    add_header Access-Control-Max-Age 86400;\n  }\n}","description":"Nginx origin configuration with Cache-Control and CORS headers for CDN delivery."},{"title":"S3 Bucket as CDN Origin","useCase":"Configuring S3 as CloudFront origin.","code":"# Create S3 bucket with public read access policy\naws s3api create-bucket \\\n  --bucket my-cdn-origin-bucket \\\n  --region us-east-1\n\n# Block public access (if using OAI)\naws s3api put-public-access-block \\\n  --bucket my-cdn-origin-bucket \\\n  --public-access-block-configuration\n  \"BlockPublicAcls=true,IgnorePublicAcls=true,\n   BlockPublicPolicy=true,RestrictPublicBuckets=true\"\n\n# Create Origin Access Identity (OAI)\naws cloudfront get-cloud-front-origin-access-identity\n\n# Bucket policy to allow CloudFront only\necho '{\n  \"Version\": \"2012-10-17\",\n  \"Statement\": [{\n    \"Effect\": \"Allow\",\n    \"Principal\": {\n      \"AWS\": \"arn:aws:iam::cloudfront:user/CloudFront Origin Access Identity E12345\"\n    },\n    \"Action\": \"s3:GetObject\",\n    \"Resource\": \"arn:aws:s3:::my-cdn-origin-bucket/*\"\n  }]\n}' > policy.json\naws s3api put-bucket-policy --bucket my-cdn-origin-bucket --policy file://policy.json","description":"S3 bucket configured as a private origin for CloudFront using Origin Access Identity."},{"title":"Origin Health Check Configuration","useCase":"Setting up CDN health checks.","code":"# CloudFront origin health check configuration\n# Configured in origin settings:\n\n# Origin Domain: origin.example.com\n# Origin Path: /health\n# Connection Attempts: 3\n# Connection Timeout: 10 seconds\n# Response Timeout: 30 seconds\n# Keep Alive: 5 seconds\n\n# Health check response (origin side):\n# GET /health\n# Response: 200 OK\n# Body: {\"status\": \"healthy\"}\n\n# If health check fails N times:\n# CDN marks origin as unhealthy\n# Serves stale content from cache\n# Retries health check periodically\n\n# Example Nginx health endpoint:\nlocation /health {\n  access_log off;\n  return 200 \"healthy\\n\";\n  add_header Content-Type text/plain;\n}","description":"CDN origin health check configuration with Nginx health endpoint example."},{"title":"Origin Cache Stampede Prevention","useCase":"Using origin shielding to prevent overload.","code":"# Problem: Cache Stampede (Thundering Herd)\n# When cache expires, many edge locations\n# simultaneously request the same content from origin\n# This overwhelms the origin server\n\n# Solution 1: Origin Shielding (CloudFront)\n# Regional edge cache aggregates requests\n# Only one request goes to origin per region\n# Automatically enabled in CloudFront\n\n# Solution 2: stale-while-revalidate\n# Serve stale content while async refresh happens\n# Cache-Control: public, max-age=3600,\n#   stale-while-revalidate=86400\n\n# Solution 3: Request collapsing (Fastly)\n# Fastly automatically collapses simultaneous\n# requests for the same URL to a single origin request\n\n# Solution 4: Use a CDN with shield tier\n# CloudFront regional cache, Fastly shielding,\n# Varnish shield nodes","description":"Techniques to prevent cache stampedes from overwhelming the origin server."},{"title":"Multiple Origin Setup (CloudFront)","useCase":"Configuring multiple origins for failover.","code":"# CloudFront origin group with failover\naws cloudfront create-origin-group \\\n  --distribution-id E123456789ABCD \\\n  --origin-group-config \\\n    \"FailoverCriteria={StatusCodes=[500,502,503,504]},\n     Members={OriginItems=[\n       {OriginId=primaryOrigin},\n       {OriginId=secondaryOrigin}\n     ]}\"\n\n# Primary origin: app-server-primary.example.com\n# Secondary origin: app-server-secondary.example.com\n# If primary returns 5xx, CloudFront automatically\n# retries the request against the secondary origin\n\n# This provides high availability\n# even if one origin goes down","description":"CloudFront origin groups provide automatic failover between multiple origins."}],"mcqQuestions":[{"question":"What is the origin server in a CDN?","options":["The CDN cache server","The authoritative source of original content","The DNS resolver","The load balancer"],"answer":1,"explanation":"The origin server is the authoritative source of original content."},{"question":"What is origin shielding?","options":["Encrypting origin traffic","A cache tier that aggregates origin requests","Blocking certain origins","Origin server firewall"],"answer":1,"explanation":"Origin shielding aggregates edge requests to prevent cache stampedes."},{"question":"What does s-maxage do?","options":["Overrides max-age for CDN caches","Sets browser cache time","Defines compression level","Controls SSL settings"],"answer":0,"explanation":"s-maxage overrides max-age specifically for shared caches (CDNs)."},{"question":"What is a cache stampede?","options":["Fast cache hits","Many edges miss cache simultaneously and overload origin","Cache warming runs","Cache memory overflow"],"answer":1,"explanation":"A cache stampede occurs when many edge servers miss cache at the same time."},{"question":"What happens if the origin is unhealthy?","options":["Site goes down","CDN serves stale cached content","CDN stops working","Users see error page"],"answer":1,"explanation":"CDNs can serve stale content when the origin is unhealthy (stale-while-revalidate)."},{"question":"Which Cache-Control value restricts caching to the browser only?","options":["public","private","no-store","must-revalidate"],"answer":1,"explanation":"Cache-Control: private means only browser caches can store the content, not CDNs."}]};
TOPICS_DATA["cdn"]["cdn-cache-hit"] = {"id":"cdn-cache-hit","title":"Cache Hit","difficulty":"beginner","estimatedMinutes":10,"tldr":["A cache hit occurs when the CDN edge server has the requested content in its cache and can serve it directly without contacting the origin server.","Cache hits result in the fastest response times because content is served from the edge server's local memory or SSD storage.","The cache hit ratio (CHR) is a key CDN performance metric — the percentage of requests served from cache vs total requests.","Higher cache hit ratios mean better performance, lower origin load, and reduced bandwidth costs."],"laymanDefinition":"A cache hit is like finding the milk you need already in your neighborhood store's refrigerator. You grab it and pay immediately — no waiting. You don't need to call the central warehouse to order it. The store already knew people would want milk and kept it stocked.","deepDive":[{"heading":"Cache Hit Indicators","text":"Response headers indicate cache hits: x-cache: HIT (CloudFront/x-amz-cf-pop), CF-Cache-Status: HIT (Cloudflare), X-Cache: HIT (Fastly/Varnish), X-Cache-Status: HIT (Nginx). The Age header shows how many seconds ago the content was fetched from the origin."},{"heading":"Factors Affecting Cache Hits","text":"TTL settings (longer TTL = more hits). Cache capacity (more storage = more content cached). Content popularity (Pareto principle: 20% of content gets 80% of hits). Cache key design (including query strings reduces hit rate). Cache warming strategy (pre-fill cache during off-peak)."},{"heading":"Cache Hit Ratio Calculation","text":"CHR = (Cache Hits / Total Requests) * 100. A good CHR is 90-95% for static content and 50-80% for mixed content. CDNs report CHR in their dashboards. Improving CHR by 1% can save significant origin bandwidth and reduce latency."},{"heading":"Improving Cache Hit Ratio","text":"Increase TTL for stable content. Use cache warming (pre-fetch popular content). Optimize cache keys (avoid unnecessary query string variations). Implement tiered caching. Use stale-while-revalidate to serve stale content while refreshing in background. Version static assets with fingerprints."},{"heading":"Cache Hit Metrics Monitoring","text":"Key metrics: CHR (overall), CHR per URL pattern, CHR per geographic region, hit bytes vs miss bytes, origin offload percentage. Monitor via CDN provider dashboards, real-time logs, and third-party monitoring tools (Datadog, Grafana). Alert on sudden CHR drops which may indicate configuration issues."}],"interviewAnswer":"A cache hit means the CDN served content from its edge cache without contacting the origin. High cache hit ratios mean faster responses, lower origin load, and reduced costs. Monitor CHR and optimize TTLs, cache keys, and cache warming to maximize hits.","interviewQuestions":[{"question":"What is a cache hit?","answer":"When the CDN edge server has content cached and serves it directly without contacting the origin."},{"question":"How is a cache hit indicated in HTTP headers?","answer":"Headers like x-cache: HIT, CF-Cache-Status: HIT, or X-Cache: HIT in the response."},{"question":"What is cache hit ratio (CHR)?","answer":"The percentage of requests served from cache vs total requests. A key CDN performance metric."},{"question":"What is a good cache hit ratio for static content?","answer":"90-95% or higher. Mixed content may achieve 50-80%."},{"question":"What does the Age header indicate?","answer":"How many seconds ago the cached content was originally fetched from the origin server."},{"question":"How can you increase cache hit ratio?","answer":"Increase TTL, use cache warming, optimize cache keys, version assets, use tiered caching, and stale-while-revalidate."},{"question":"What is the Pareto principle in CDN caching?","answer":"About 20% of content generates 80% of cache hits. Focus caching efforts on popular content."},{"question":"How does query string affect cache hits?","answer":"Each unique query string creates a separate cache entry, reducing hit ratio. Normalize query strings in cache keys."},{"question":"What is cache warming?","answer":"Pre-fetching and caching content during off-peak hours to ensure it is available when users request it."},{"question":"What causes a sudden drop in cache hit ratio?","answer":"TTL changes, cache configuration updates, origin changes, cache purging, or traffic pattern shifts."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Cache Hit</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">User Request</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Resource URL</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"120\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"220\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Edge Cache</text><text x=\"220\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Check cache</text><line x1=\"280\" y1=\"48\" x2=\"310\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"320\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"390\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cache HIT?</text><text x=\"390\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Serve immediately</text><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cache MISS</text><text x=\"65\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fetch from origin</text><line x1=\"120\" y1=\"83\" x2=\"150\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"70\" width=\"120\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"220\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Origin Server</text><text x=\"220\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Generate response</text><line x1=\"280\" y1=\"83\" x2=\"310\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"105\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Serve to User</text><text x=\"65\" y=\"124\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Low latency (<10ms)</text><rect x=\"160\" y=\"105\" width=\"120\" height=\"25\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"220\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cache + Store</text><text x=\"220\" y=\"124\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Update cache</text><text x=\"240\" y=\"190\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Cache Hit: Content served from edge cache without </text><text x=\"240\" y=\"202\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">contacting origin — fastest possible response.</text></svg>","codeExamples":[{"title":"Check Cache Status with Curl","useCase":"Verifying cache hits.","code":"# Check if a URL is served from CDN cache\ncurl -I https://cdn.example.com/style.css\n\n# Example output showing cache hit:\n# HTTP/2 200\n# content-type: text/css\n# cache-control: public, max-age=31536000\n# x-cache: Hit from cloudfront\n# age: 72834\n# cf-cache-status: HIT\n\n# x-cache: Hit = CloudFront edge cache hit\n# age: 72834 = content has been cached\n#         for 72,834 seconds (~20 hours)\n# cf-cache-status: HIT = Cloudflare cache hit","description":"Using curl to verify CDN cache hits through response headers."},{"title":"CloudFront Cache Statistics","useCase":"Viewing CHR in CloudWatch.","code":"# CloudFront cache hit metrics via AWS CLI\naws cloudwatch get-metric-statistics \\\n  --namespace AWS/CloudFront \\\n  --metric-name HitRatio \\\n  --dimensions Name=DistributionId,Value=E123456789ABCD\n  --start-time 2024-01-01T00:00:00Z \\\n  --end-time 2024-01-02T00:00:00Z \\\n  --period 3600 \\\n  --statistics Average\n\n# View cache hit metrics by behavior\naws cloudfront get-distribution \\\n  --id E123456789ABCD \\\n  --query \"Distribution.DistributionConfig\"\n\n# Check total requests and hits\naws cloudfront get-distribution-statistics \\\n  --distribution-id E123456789ABCD","description":"AWS CLI commands to check CloudFront cache hit ratio metrics."},{"title":"Nginx Cache Hit Status with Upstream","useCase":"Nginx caching proxy status.","code":"server {\n  listen 80;\n  server_name cdn.example.com;\n\n  location / {\n    proxy_cache mycache;\n    proxy_pass http://origin;\n\n    # Show cache status in response header\n    add_header X-Cache-Status $upstream_cache_status;\n\n    # Values:\n    # HIT — served from cache\n    # MISS — not in cache, fetched from origin\n    # EXPIRED — cache expired, revalidated\n    # STALE — served stale, origin unavailable\n    # UPDATING — cache update in progress\n    # BYPASS — cache bypassed (proxy_cache_bypass)\n  }\n}\n\n# Test:\n# curl -I https://cdn.example.com/test.jpg\n# X-Cache-Status: HIT","description":"Nginx proxy cache configuration with $upstream_cache_status showing cache hit/miss."},{"title":"Cache Hit Ratio Calculation Script","useCase":"Calculating CHR from logs.","code":"# Parse CDN access logs to calculate CHR\n#!/bin/bash\n# Sample log format:\n# TIME | URL | CACHE_STATUS | BYTES\n\n# Count total requests\nTOTAL=$(wc -l < cdn-access.log)\n\n# Count cache hits\nHITS=$(grep -c \"HIT\" cdn-access.log)\n\n# Calculate ratio\nCHR=$(echo \"scale=2; $HITS * 100 / $TOTAL\" | bc)\necho \"Total requests: $TOTAL\"\necho \"Cache hits: $HITS\"\necho \"Cache Hit Ratio: $CHR%\"\n\n# Breakdown by URL pattern\necho \"\\nBy content type:\"\ngrep -oE \"\\.(css|js|png|jpg|html)\" cdn-access.log \\\n  | sort | uniq -c | sort -rn","description":"Bash script to calculate cache hit ratio from CDN access logs."},{"title":"Fastly Cache Hit Dashboard via API","useCase":"Programmatic CHR monitoring.","code":"# Fastly API to get cache hit ratio\ncurl -H \"Fastly-Key: $FASTLY_API_TOKEN\" \\\n  \"https://api.fastly.com/stats/service/$SERVICE_ID\" \\\n  \"?by=hour&from=2h ago&to=now\"\n\n# Response includes:\n# {\n#   \"status\": \"success\",\n#   \"data\": [{\n#     \"requests\": 1234567,\n#     \"hits\": 1111111,\n#     \"miss\": 123456,\n#     \"hit_ratio\": 0.90,\n#     \"bandwidth\": 45000000000,\n#     \"status_200\": 1100000\n#   }]\n# }\n\n# Python script for alerting on low CHR:\nimport requests, os\nresp = requests.get(\n  \"https://api.fastly.com/stats/service/$SID\",\n  headers={\"Fastly-Key\": os.environ[\"FASTLY_API_KEY\"]}\n)\nchr = resp.json()[\"data\"][0][\"hit_ratio\"]\nif chr < 0.80:\n  print(f\"ALERT: CHR dropped to {chr:.2%}\")","description":"Fastly API-based cache hit ratio monitoring with Python alerting."}],"mcqQuestions":[{"question":"What is a cache hit?","options":["Content fetched from origin","Content served from CDN cache","Cache miss retry","Cache invalidation"],"answer":1,"explanation":"A cache hit is when content is served directly from the CDN cache without contacting the origin."},{"question":"What does the Age header indicate?","options":["Content age in seconds since origin fetch","User age","Cache TTL remaining","Request duration"],"answer":0,"explanation":"The Age header shows how long the cached content has been stored on the edge server."},{"question":"What is a good cache hit ratio for static content?","options":["30-40%","50-60%","90-95%","100%"],"answer":2,"explanation":"A good CHR for static content is 90-95%."},{"question":"Which header indicates a cache hit?","options":["Content-Type","Cache-Control","x-cache: Hit","Accept-Encoding"],"answer":2,"explanation":"Headers like x-cache: Hit or CF-Cache-Status: HIT indicate a cache hit."},{"question":"What improves cache hit ratio?","options":["Lower TTL","Longer TTL and cache warming","Disabling cache","Adding unique query params"],"answer":1,"explanation":"Longer TTL and cache warming improve the cache hit ratio."},{"question":"How does versioned filenames affect caching?","options":["Reduces hits","Enables permanent caching, improving hits","No effect","Prevents caching"],"answer":1,"explanation":"Versioned filenames (fingerprints) enable immutable/permanent caching, improving hit ratio."}]};
TOPICS_DATA["cdn"]["cdn-cache-miss"] = {"id":"cdn-cache-miss","title":"Cache Miss","difficulty":"beginner","estimatedMinutes":10,"tldr":["A cache miss occurs when the requested content is not found in the CDN edge server's cache, requiring the server to fetch it from the origin.","Cache misses result in higher latency because the request must travel from the edge to the origin (or parent cache tier) before the content can be served.","Cache misses are expected on first requests, after cache expiration, or after cache invalidation. The response is then cached for subsequent requests.","Minimizing cache misses is key to CDN performance. Strategies include longer TTLs, cache warming, and optimizing cache key configuration."],"laymanDefinition":"A cache miss is like going to your neighborhood store for milk and finding the dairy section empty. The clerk has to call the central warehouse and have them deliver it. You wait a few minutes. The good news: next time you come for milk, it will be in stock because the store learned to keep it on hand.","deepDive":[{"heading":"Why Cache Misses Happen","text":"First request (cold cache): nobody has requested this content before. TTL expired: the cached content\\'s time-to-live has elapsed. Cache eviction: the edge server ran out of storage and removed less popular content. Cache invalidation: content was explicitly purged. Cache key mismatch: URL variations that don\\'t hit the same cache entry."},{"heading":"Cache Miss Penalty","text":"A cache miss adds significant latency: edge to origin round trip. For a US user hitting a European origin, this could add 100-300ms. The miss penalty includes DNS resolution of origin, TCP connection, SSL handshake, origin processing time, and response transfer. The cache fill response is then stored for future hits."},{"heading":"Cold Start / First Request","text":"The first user to request a piece of content after deployment experiences a cache miss (cold start). This user sees higher latency. Cache warming pre-fetches content to avoid cold starts for real users. For new deployments, consider pre-loading critical assets in the CDN cache."},{"heading":"Cache Miss vs Cache Hit Performance","text":"Cache hit: response in 1-10ms (from edge server memory/SSD). Cache miss: response in 50-500ms (requires origin round trip). The difference is dramatic — a cache miss can be 10-50x slower. This is why maximizing cache hit ratio is critical for CDN performance."},{"heading":"Monitoring Cache Misses","text":"Track miss rate, miss latency (time to fill from origin), top missed URLs, miss reasons (first byte, expired, evicted). High miss rate on popular content indicates configuration problems. CDN dashboards show miss breakdowns. Alert on spikes in cache miss rate that indicate issues."}],"interviewAnswer":"A cache miss means the CDN had to fetch content from the origin, adding latency. Misses happen on first requests, after TTL expiry, or after invalidation. Minimize misses with optimal TTLs, cache warming, and proper cache key configuration. Monitor miss rates to identify optimization opportunities.","interviewQuestions":[{"question":"What is a cache miss?","answer":"When requested content is not in the CDN edge cache and must be fetched from the origin server."},{"question":"Why do cache misses increase latency?","answer":"Because the request must travel from the edge server to the origin, adding round-trip time."},{"question":"What are common causes of cache misses?","answer":"First request (cold cache), TTL expiry, cache eviction, invalidation, and cache key mismatch."},{"question":"What is a cold start in CDN caching?","answer":"The first user request after content is deployed — the cache is empty, so it is always a miss."},{"question":"What is the typical latency difference between hit and miss?","answer":"Cache hit: 1-10ms. Cache miss: 50-500ms (10-50x slower)."},{"question":"How can you reduce cache misses?","answer":"Longer TTLs, cache warming, optimizing cache keys, larger cache allocations, and tiered caching."},{"question":"What is cache eviction?","answer":"When the edge server removes older or less popular content to make room for new content."},{"question":"What does the x-cache: Miss header mean?","answer":"The CDN edge server did not have the content cached and had to fetch it from the origin or parent cache."},{"question":"How does cache key configuration affect misses?","answer":"Including query string parameters in the cache key creates separate entries for each variation, potentially causing misses."},{"question":"What is cache fill?","answer":"The process of fetching content from the origin and storing it in the edge cache after a cache miss."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Cache Miss</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">User Request</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Resource URL</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"120\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"220\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Edge Cache</text><text x=\"220\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Check cache</text><line x1=\"280\" y1=\"48\" x2=\"310\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"320\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"390\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cache MISS!</text><text x=\"390\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fetch from origin</text><line x1=\"320\" y1=\"60\" x2=\"320\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"310\" y1=\"65\" x2=\"280\" y2=\"65\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"75\" width=\"120\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"220\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Fetch from Origin</text><text x=\"220\" y=\"94\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Requires round trip</text><line x1=\"280\" y1=\"88\" x2=\"310\" y2=\"88\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"320\" y=\"75\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"390\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Store in Cache</text><text x=\"390\" y=\"94\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cache fill</text><line x1=\"410\" y1=\"88\" x2=\"440\" y2=\"88\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"110\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"126\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Serve to User</text><text x=\"65\" y=\"118\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Higher latency (50-5</text><text x=\"65\" y=\"129\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">00ms)</text><text x=\"240\" y=\"190\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Cache Miss: Content not in edge cache. Must be fet</text><text x=\"240\" y=\"202\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ched from origin, increasing latency. Subsequent r</text><text x=\"240\" y=\"214\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">equests will hit.</text></svg>","codeExamples":[{"title":"Identifying Cache Misses with Curl","useCase":"Check cache miss headers.","code":"# Force a cache miss to see the full flow\ncurl -I https://cdn.example.com/image.jpg\n\n# Look for miss indicators:\n# x-cache: Miss from cloudfront\n# cf-cache-status: MISS\n# x-cache-status: MISS\n# age: 0 (just fetched, no age yet)\n\n# The first request will be a miss,\n# the second should be a hit:\ncurl -I https://cdn.example.com/image.jpg\n# x-cache: Hit from cloudfront\n# age: 5 (cached for 5 seconds)\n\n# Simulate a cold request with no-cache:\ncurl -s -o /dev/null -w \"Time: %{time_total}s \\n\" \\\n  -H \"Cache-Control: no-cache\" \\\n  https://cdn.example.com/image.jpg","description":"Using curl to observe cache miss headers and measure the difference between first and second request."},{"title":"Cache Miss Analysis from CDN Logs","useCase":"Parsing logs to understand misses.","code":"# CloudFront log format (tab-separated)\n# Fields: date time x-edge-location sc-bytes c-ip cs-method\n#         cs-host cs-uri-stem sc-status cs-referer\n#         cs-user-agent cs-uri-query cs-cookie\n#         x-edge-result-type x-edge-request-id\n#         x-host-header cs-protocol cs-bytes\n#         time-taken x-forwarded-for\n\n# x-edge-result-type = Hit, Miss, RefreshHit,\n#                      Redirect, ClientError, ServerError\n\n# Parse miss URLs from CloudFront logs\nGet-Content cloudfront.log |\n  Where-Object { $_ -match \"\\tMiss\\t\" } |\n  ForEach-Object { ($_ -split \"\\t\")[7] } |\n  Sort-Object | Get-Unique | Select-Object -First 10\n\n# Top 10 most frequently missed URLs\nGet-Content cloudfront.log |\n  Where-Object { $_ -match \"\\tMiss\\t\" } |\n  ForEach-Object { ($_ -split \"\\t\")[7] } |\n  Group-Object | Sort-Object Count -Descending |\n  Select-Object -First 10","description":"Parsing CloudFront log format to identify most frequently missed URLs."},{"title":"Cache Warming Script","useCase":"Pre-fetch content to avoid cold starts.","code":"#!/usr/bin/env node\n// Cache warming script\n// Run after deployment to pre-fill CDN cache\n\nconst https = require(\"https\");\n\nconst urlsToWarm = [\n  \"https://cdn.example.com/css/app.css\",\n  \"https://cdn.example.com/js/bundle.js\",\n  \"https://cdn.example.com/img/hero.webp\",\n  \"https://cdn.example.com/fonts/inter.woff2\"\n];\n\nasync function warmUrl(url) {\n  return new Promise((resolve, reject) => {\n    const start = Date.now();\n    https.get(url, (res) => {\n      let data = \"\";\n      res.on(\"data\", chunk => data += chunk);\n      res.on(\"end\", () => {\n        const ms = Date.now() - start;\n        const cache = res.headers[\"x-cache\"];\n        console.log(`${url} -> ${cache} (${ms}ms, ${data.length} bytes)`);\n        resolve({ url, cache, ms });\n      });\n    });\n  });\n}\n\n(async () => {\n  console.log(`Warming ${urlsToWarm.length} URLs...`);\n  const results = await Promise.all(urlsToWarm.map(warmUrl));\n  const misses = results.filter(r => r.cache?.includes(\"Miss\"));\n  console.log(`Done. ${misses.length} initial misses (now cached).`);\n})();","description":"Node.js cache warming script that pre-fetches assets to populate CDN cache after deployment."},{"title":"Understanding TTL-Based Cache Miss Flow","useCase":"How TTL expiration triggers misses.","code":"# Timeline of cache life:\n\n# T=0s: User A requests /data.json\n#        Cache MISS -> fetch from origin\n#        Cache-Control: max-age=3600\n#        Stored in edge for 1 hour\n\n# T=5s: User B requests /data.json\n#        Cache HIT -> served from edge\n#        Age: 5\n\n# T=3600s: Cache expires\n#         User C requests /data.json\n#         Cache MISS (stale) -> revalidate or refetch\n#         If origin returns 304 Not Modified,\n#           cache refreshes TTL (soft miss)\n#         If origin returns 200,\n#           cache replaces content (hard miss)\n\n# T=3601s: User D requests /data.json\n#        Cache HIT (fresh TTL)","description":"Timeline showing how TTL expiration causes cache misses and how the cache refreshes."},{"title":"Preventing Cache Misses with Service Workers","useCase":"Cache-first strategy in SW.","code":"// Service Worker with cache-first strategy\n// Prevents CDN cache misses from affecting UX\n\nself.addEventListener(\"fetch\", (event) => {\n  event.respondWith(cacheFirst(event.request));\n});\n\nasync function cacheFirst(request) {\n  const cache = await caches.open(\"cdn-cache-v1\");\n  const cached = await cache.match(request);\n\n  if (cached) {\n    // Cache hit at browser level too\n    return cached;\n  }\n\n  try {\n    const response = await fetch(request);\n    if (response.status === 200) {\n      cache.put(request, response.clone());\n    }\n    return response;\n  } catch (err) {\n    // Even if CDN misses and fails,\n    // we serve stale cache if available\n    return cached || new Response(\"Offline\", { status: 503 });\n  }\n}","description":"Service Worker cache-first strategy as an additional layer to handle CDN cache misses gracefully."}],"mcqQuestions":[{"question":"What is a cache miss?","options":["Content served from cache","Content not in cache, fetched from origin","Cache invalidation","Cache memory full"],"answer":1,"explanation":"A cache miss requires fetching content from the origin."},{"question":"What is a common cause of cache misses?","options":["Very long TTL","First request (cold cache)","High cache hit ratio","Small file size"],"answer":1,"explanation":"First requests always cause a cache miss (cold start)."},{"question":"What is the latency difference between hit and miss?","options":["Same latency","Hit is 10-50x faster","Miss is faster","Both vary equally"],"answer":1,"explanation":"Cache hits (1-10ms) are 10-50x faster than cache misses (50-500ms)."},{"question":"What is cache eviction?","options":["Adding content to cache","Removing old content to free space","Increasing TTL","Enabling compression"],"answer":1,"explanation":"Cache eviction removes less popular content when storage is full."},{"question":"How can cache warming help?","options":["Slows down the cache","Pre-fetches content to avoid cold starts","Reduces TTL","Encrypts cached content"],"answer":1,"explanation":"Cache warming pre-fetches content so real users never experience a cold cache miss."},{"question":"What header shows the content is a cache miss?","options":["x-cache: Hit","x-cache: Miss","Cache-Control: private","Content-Encoding: gzip"],"answer":1,"explanation":"Headers like x-cache: Miss or CF-Cache-Status: MISS indicate a cache miss."}]};
TOPICS_DATA["cdn"]["cdn-cache-invalidation"] = {"id":"cdn-cache-invalidation","title":"Cache Invalidation","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Cache invalidation is the process of removing or updating content stored in CDN edge caches before its TTL expires.","Invalidation is needed when content changes on the origin but the CDN still serves the old cached version to users.","Methods: path-based purge (specific URLs), wildcard purge (pattern matching), tag-based invalidation (groups of content), and versioned filenames (avoid invalidation entirely).","There is an old saying: \"There are only two hard things in computer science: cache invalidation and naming things.\" — Phil Karlton."],"laymanDefinition":"Cache invalidation is like recalling a batch of product packaging when you realize the ingredient list has an error. You have to go to every store (edge server) and remove all the old boxes. The tricky part: you need to know which boxes are in which stores, and you must replace them before customers see outdated information.","deepDive":[{"heading":"Invalidation Methods","text":"Exact path: /images/banner.jpg — invalidates one file. Wildcard: /images/* — invalidates all images. Directory: /css/ — invalidates all CSS files. Tag-based: invalidate by content tags like \"v2.0-release\". API-based: through CDN provider APIs. Some providers charge per invalidation path or have monthly limits."},{"heading":"Versioned Filename Strategy (Cache Busting)","text":"Instead of invalidating old cache, serve different filenames for updated content: style.abc123.css instead of style.css. The old content remains cached (no users request it). The new filename automatically gets its own cache entries. This is the most efficient approach — zero invalidation cost, zero cache miss penalty for updated content."},{"heading":"CDN Invalidation Policies","text":"CloudFront: free first 1000 paths/month, $0.005/path after. Fastly: instant purge, no charge (with limits). Cloudflare: unlimited purges via API, UI, or tag. Akamai: instant invalidation or CP code-based. Varnish: PURGE HTTP method (if configured). Most CDNs propagate invalidation within seconds globally."},{"heading":"Purge Propagation Time","text":"Invalidation must propagate to all edge servers worldwide. CloudFront: typically <60 seconds. Fastly: <150ms for instant purge. Cloudflare: <30 seconds. Akamai: <10 seconds. During propagation, some users may still receive the old content (eventual consistency). This is why versioned filenames are preferred."},{"heading":"Tag-Based Invalidation","text":"Assign content tags during cache (e.g., Cache-Tag: v2.0, product-123). Invalidate all content with a specific tag in one API call. Useful for: invalidating all pages related to a product update, all blog posts, or all content from a deployment. Supported by: Fastly (Surrogate-Key), Cloudflare (Cache-Tag), CloudFront (tags with Lambda@Edge)."}],"interviewAnswer":"Cache invalidation removes or updates cached content before TTL expires. Methods include path-based purge, wildcards, and tag-based invalidation. The best strategy is to avoid invalidation entirely by using versioned filenames, which make old cache entries unreferenced and naturally expire.","interviewQuestions":[{"question":"What is cache invalidation?","answer":"The process of removing or updating content in CDN caches before its TTL expires."},{"question":"Why is cache invalidation difficult?","answer":"Because cached content is distributed across hundreds of edge servers worldwide and must be coordinated."},{"question":"What is the best alternative to cache invalidation?","answer":"Versioned filenames (cache busting) — serve different filenames for updated content, avoiding the need to invalidate."},{"question":"How does tag-based invalidation work?","answer":"Assign tags to content during caching, then invalidate all content with a specific tag in one API call."},{"question":"How long does propagation take?","answer":"CloudFront: ~60s, Fastly: <150ms, Cloudflare: <30s, Akamai: <10s."},{"question":"What is the CloudFront invalidation cost?","answer":"First 1000 paths per month free, $0.005 per path after that."},{"question":"What is the PURGE HTTP method?","answer":"A non-standard HTTP method supported by some CDNs (like Varnish and Fastly) to trigger cache invalidation."},{"question":"What is eventual consistency in cache invalidation?","answer":"During propagation, some edge servers may still serve old content while others have already invalidated it."},{"question":"What are Surrogate-Keys?","answer":"Fastly\\'s tag-based invalidation mechanism — set Surrogate-Key response header, then purge by key."},{"question":"Can you invalidate content on Cloudflare?","answer":"Yes, via UI, API, or Cache-Tag headers. Options: purge everything, by URL, by hostname, or by tag."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Cache Invalidation</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Content Updates</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">New version deployed</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"225\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Option 1: Invalidate</text><text x=\"225\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Purge old cache paths</text><line x1=\"290\" y1=\"48\" x2=\"320\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"330\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"400\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Option 2: Versioned URLs</text><text x=\"400\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">style.abc123.css</text><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Wildcard Purge</text><text x=\"65\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">/images/*</text><rect x=\"10\" y=\"100\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Tag Purge</text><text x=\"65\" y=\"119\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cache-Tag: v2.0</text><rect x=\"10\" y=\"130\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Propagation</text><text x=\"65\" y=\"149\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Seconds globally</text><line x1=\"120\" y1=\"83\" x2=\"150\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"113\" x2=\"150\" y2=\"113\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"143\" x2=\"150\" y2=\"143\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"70\" width=\"150\" height=\"100\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"235\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cache Invalidation</text><text x=\"235\" y=\"131\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Removing stale cache before</text><text x=\"235\" y=\"142\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\"> TTL. Use versioned filenam</text><text x=\"235\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">es to avoid the need entire</text><text x=\"235\" y=\"164\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ly.</text><text x=\"240\" y=\"195\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Cache Invalidation: Removing cached content before</text><text x=\"240\" y=\"207\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\"> TTL expires. Best avoided via versioned filenames</text><text x=\"240\" y=\"219\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">.</text></svg>","codeExamples":[{"title":"CloudFront Cache Invalidation (CLI)","useCase":"Invalidating specific paths.","code":"# Invalidate specific file\naws cloudfront create-invalidation \\\n  --distribution-id E123456789ABCD \\\n  --paths \"/css/style.css\"\n\n# Invalidate wildcard pattern\naws cloudfront create-invalidation \\\n  --distribution-id E123456789ABCD \\\n  --paths \"/images/*\" \"/js/*\"\n\n# Invalidate entire distribution\naws cloudfront create-invalidation \\\n  --distribution-id E123456789ABCD \\\n  --paths \"/*\"\n\n# Check invalidation status\naws cloudfront get-invalidation \\\n  --distribution-id E123456789ABCD \\\n  --id I1234567890ABCDEF","description":"AWS CLI commands for CloudFront cache invalidation with wildcard support."},{"title":"Fastly Instant Purge via API","useCase":"Fastly\\'s near-instant invalidation.","code":"# Fastly purge by URL (instant)\ncurl -X PURGE https://cdn.example.com/style.css \\\n  -H \"Fastly-Key: $FASTLY_API_TOKEN\"\n\n# Fastly purge by surrogate key (tag)\ncurl -X POST \"https://api.fastly.com/service/$SID/purge/product-123\" \\\n  -H \"Fastly-Key: $FASTLY_API_TOKEN\"\n\n# Fastly purge all service content\ncurl -X POST \"https://api.fastly.com/service/$SID/purge_all\" \\\n  -H \"Fastly-Key: $FASTLY_API_TOKEN\"\n\n# Set surrogate key in origin response:\n# Surrogate-Key: product-123 product-category-456","description":"Fastly purge API calls including URL, tag-based (surrogate key), and full purge."},{"title":"Versioned Filenames with Webpack","useCase":"Automatic cache busting with build tools.","code":"// webpack.config.js\nmodule.exports = {\n  output: {\n    filename: \"[name].[contenthash:8].js\",\n    // Output: main.4a5b6c7d.js\n    // Content hash changes when file content changes\n    path: path.resolve(__dirname, \"dist\"),\n  },\n  plugins: [\n    // Generates HTML with versioned script references\n    new HtmlWebpackPlugin({\n      template: \"./src/index.html\",\n    }),\n  ],\n  // For images and fonts:\n  module: {\n    rules: [{\n      test: /\\.(png|jpg|webp|svg)$/,\n      type: \"asset/resource\",\n      generator: {\n        filename: \"img/[name].[contenthash:8][ext]\"\n      }\n    }]\n  }\n};\n\n# Result: myimg.abc123.jpg\n# Old: myimg.xyz789.jpg (still cached, but not used)\n# New content gets new URL = automatic cache busting","description":"Webpack configuration for automatic content-hash-based versioned filenames (cache busting)."},{"title":"Cloudflare Cache Purge API","useCase":"Programmatic cache purging.","code":"# Cloudflare purge by URLs (max 30/day free)\ncurl -X POST \"https://api.cloudflare.com/client/v4/zones/$ZONE_ID/purge_cache\" \\\n  -H \"Authorization: Bearer $TOKEN\" \\\n  -H \"Content-Type: application/json\" \\\n  -d '{\"files\":[\"https://example.com/style.css\",\n              \"https://example.com/script.js\"]}'\n\n# Cloudflare purge everything\ncurl -X POST \"https://api.cloudflare.com/client/v4/zones/$ZONE_ID/purge_cache\" \\\n  -H \"Authorization: Bearer $TOKEN\" \\\n  -H \"Content-Type: application/json\" \\\n  -d '{\"purge_everything\":true}'\n\n# Cloudflare purge by tags (requires Cache-Tag header)\ncurl -X POST \"https://api.cloudflare.com/client/v4/zones/$ZONE_ID/purge_cache\" \\\n  -H \"Authorization: Bearer $TOKEN\" \\\n  -H \"Content-Type: application/json\" \\\n  -d '{\"tags\":[\"tag-v2-release\"]}'","description":"Cloudflare API cache purging by URL, everything, or tags."},{"title":"Nginx Cache Purge Module","useCase":"Invalidating Nginx cache.","code":"# Nginx with ngx_cache_purge module\n\nlocation ~ /purge(/.*) {\n  allow 127.0.0.1;\n  allow 10.0.0.0/8;\n  deny all;\n\n  proxy_cache_purge mycache \"$1$is_args$args\";\n}\n\n# Usage: curl -X PURGE http://cdn.local/purge/style.css\n# This removes /style.css from the cache\n\n# Or use proxy_cache_key to match:\nproxy_cache_key \"$scheme$host$request_uri\";\nproxy_cache_purge mycache \"$scheme$host$1$is_args$args\";\n\n# Test:\n# curl -I http://cdn.local/style.css\n# X-Cache-Status: HIT\n# curl -X PURGE http://cdn.local/purge/style.css\n# curl -I http://cdn.local/style.css\n# X-Cache-Status: MISS","description":"Nginx cache purge module configuration for invalidating cached content."}],"mcqQuestions":[{"question":"What is the most efficient cache invalidation strategy?","options":["Path-based purge","Versioned filenames","Wildcard purge","Tag-based purge"],"answer":1,"explanation":"Versioned filenames avoid invalidation entirely — old content is never requested again."},{"question":"What is the CloudFront invalidation cost?","options":["Free unlimited","First 1000 free, then $0.005/path","$0.01 per path","Free up to 10000 paths"],"answer":1,"explanation":"CloudFront offers 1000 free invalidations per month, then charges $0.005 per path."},{"question":"Which CDN offers near-instant purge (<150ms)?","options":["CloudFront","Fastly","Cloudflare","Akamai"],"answer":1,"explanation":"Fastly offers near-instant purge, typically completing in under 150 milliseconds."},{"question":"What are Surrogate-Keys used for?","options":["Content compression","Tag-based cache invalidation","SSL termination","Load balancing"],"answer":1,"explanation":"Surrogate-Keys enable tag-based invalidation in Fastly."},{"question":"What is the saying about cache invalidation?","options":["\"Cache is king\"","\"There are only two hard things in computer science: cache invalidation and naming things\"","\"Invalidate early\"","\"Never invalidate cache\""],"answer":1,"explanation":"Phil Karlton famously said this about the difficulty of cache invalidation."},{"question":"What does a content hash-based filename prevent?","options":["Compression errors","Need for cache invalidation","SSL issues","DNS problems"],"answer":1,"explanation":"Content hash filenames change when content changes, so old cached versions are never requested again."}]};
TOPICS_DATA["cdn"]["cdn-cache-control-headers"] = {"id":"cdn-cache-control-headers","title":"Cache-Control Headers","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Cache-Control headers are HTTP response headers that tell browsers, CDNs, and proxies how to cache content.","Directives include: max-age (seconds to cache), s-maxage (CDN-specific TTL), public/private (who can cache), no-cache (revalidate before use), no-store (never cache).","Cache-Control is the primary mechanism for controlling CDN caching behavior. Incorrect configuration leads to either stale content or poor cache hit ratios.","Additional directives: stale-while-revalidate (serve stale while refreshing), immutable (content never changes), must-revalidate (must check origin after expiry)."],"laymanDefinition":"Cache-Control headers are like expiration dates and storage instructions on food products. \"Refrigerate after opening\" is like \"private\" (only browser cache). \"Best before 7 days\" is like \"max-age=604800\". \"Freeze for longer storage\" is like \"s-maxage=31536000\" for CDN. Labels tell different storage locations (pantry, fridge, freezer) how long to keep each item.","deepDive":[{"heading":"Core Cache-Control Directives","text":"public: any cache (browser, CDN, proxy) can store. private: only browser cache can store (not CDN). no-cache: must revalidate with origin before using cached copy. no-store: never cache at all. max-age=<seconds>: maximum time to cache. s-maxage=<seconds>: overrides max-age for shared caches (CDNs)."},{"heading":"s-maxage vs max-age","text":"max-age applies to all caches (browser + CDN). s-maxage overrides max-age specifically for shared caches (CDNs and proxies). Browser uses max-age. CDN uses s-maxage (if present) or falls back to max-age. Example: max-age=3600, s-maxage=86400 means browser caches 1 hour, CDN caches 1 day."},{"heading":"Stale Content Directives","text":"stale-while-revalidate=<seconds>: serve stale cached content while asynchronously fetching fresh version. Prevents cache misses from impacting users. stale-if-error=<seconds>: serve stale content if origin is unreachable. These directives dramatically improve perceived performance and reliability."},{"heading":"immutable Directive","text":"immutable tells the browser that the content will never change on that URL. The browser can skip revalidation entirely. Used with versioned filenames (e.g., style.abc123.css). Combined with max-age=31536000, the browser will never recheck the origin for 1 year. This is the highest-performance configuration."},{"heading":"Cache-Control Precedence","text":"More specific directives override general ones: s-maxage overrides max-age for CDN. no-cache overrides public/private. must-revalidate overrides stale-while-revalidate. The most restrictive directive wins. When in doubt, CDN providers document their specific Cache-Control handling behavior."}],"interviewAnswer":"Cache-Control headers are the primary mechanism for controlling CDN and browser caching. Use s-maxage to set CDN-specific TTLs, stale-while-revalidate for resilience, and immutable with versioned filenames for optimal performance. Test header configuration with curl before deploying.","interviewQuestions":[{"question":"What is the Cache-Control header?","answer":"An HTTP response header that controls how browsers, CDNs, and proxies cache content."},{"question":"What is the difference between public and private?","answer":"public allows any cache (CDN, browser) to store content. private restricts caching to the browser only."},{"question":"What does no-cache mean?","answer":"The content must revalidate with the origin before every use. It can be cached, but must be checked first."},{"question":"What does s-maxage do?","answer":"Overrides max-age specifically for shared caches (CDNs and proxies). Browser ignores s-maxage."},{"question":"What is stale-while-revalidate?","answer":"A directive that allows serving stale cached content while asynchronously fetching an updated version."},{"question":"What does the immutable directive do?","answer":"Tells the browser the content never changes on that URL — skip revalidation entirely."},{"question":"Can you use public and private together?","answer":"No, they are mutually exclusive. public is the default when max-age is set."},{"question":"What happens if no Cache-Control header is set?","answer":"Browsers and CDNs use heuristic caching — typically cache if response is 200 and method is GET. Behavior varies."},{"question":"What is the difference between no-cache and no-store?","answer":"no-cache: can cache but must revalidate. no-store: never cache at all."},{"question":"How do you test Cache-Control headers?","answer":"Use curl -I to view response headers. Check Cache-Control, Age, and x-cache headers."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Cache-Control Headers</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">public</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Any cache can store</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">private</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Browser only</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">max-age=3600</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cache for 1 hour</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">s-maxage=86400</text><text x=\"65\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">CDN caches 1 day</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">immutable</text><text x=\"65\" y=\"174\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Never revalidate</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"220\" height=\"155\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cache-Control Directives</text><text x=\"270\" y=\"173\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">HTTP headers that control caching behavi</text><text x=\"270\" y=\"184\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">or across browsers, CDNs, and proxies.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Cache-Control: max-age, s-maxage, public/private, </text><text x=\"240\" y=\"232\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">stale-while-revalidate, immutable — control cachin</text><text x=\"240\" y=\"244\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">g behavior.</text></svg>","codeExamples":[{"title":"Cache-Control for Different Content Types","useCase":"Optimal cache header configurations.","code":"# Static assets (versioned) — cache forever\n# Cache-Control: public, max-age=31536000, immutable\n# For: style.abc123.css, main.xyz789.js\n\n# Static assets (unversioned) — cache moderately\n# Cache-Control: public, max-age=86400\n# For: logo.png, favicon.ico\n\n# HTML pages — short cache with revalidation\n# Cache-Control: public, max-age=0, must-revalidate\n# For: index.html, /about\n\n# API responses — no browser cache, CDN cache short\n# Cache-Control: no-cache, s-maxage=60\n# Browser: always revalidate\n# CDN: cache for 60 seconds\n\n# Dynamic content — never cache\n# Cache-Control: no-store, private\n# For: /api/user/profile, /cart\n\n# User-specific content\n# Cache-Control: private, max-age=300\n# Only browser caches for 5 minutes","description":"Recommended Cache-Control configurations for different content types and use cases."},{"title":"Setting Cache-Control in Nginx","useCase":"Configuring headers on the origin.","code":"server {\n  listen 8080;\n  server_name origin.example.com;\n\n  # Versioned static assets (fingerprinted)\n  location ~* \\.(css|js)$ {\n    root /var/www/dist;\n    expires 1y;\n    add_header Cache-Control \"public, immutable\";\n    add_header Cache-Tag \"static-assets\";\n  }\n\n  # Images\n  location ~* \\.(png|jpg|jpeg|gif|webp|svg)$ {\n    root /var/www/images;\n    expires 30d;\n    add_header Cache-Control \"public, max-age=2592000\";\n  }\n\n  # HTML (no browser cache, CDN cache short)\n  location ~* \\.html$ {\n    root /var/www;\n    add_header Cache-Control \"no-cache, s-maxage=60\";\n  }\n\n  # API — never cache private data\n  location /api/ {\n    proxy_pass http://app:3000;\n    add_header Cache-Control \"private, no-store\";\n  }\n}","description":"Nginx configuration with Cache-Control headers for various content types."},{"title":"Verifying Cache-Control with Curl","useCase":"Testing header configuration.","code":"# Check all cache-related headers\ncurl -I https://cdn.example.com/style.abc123.css\n\n# Example output:\n# HTTP/2 200\n# content-type: text/css\n# cache-control: public, max-age=31536000, immutable\n# expires: Wed, 15 Jul 2026 12:00:00 GMT\n# last-modified: Tue, 14 Jul 2025 10:00:00 GMT\n# etag: \"abc123def456\"\n# age: 123456\n# x-cache: Hit from cloudfront\n# cf-cache-status: HIT\n\n# max-age=31536000 = 1 year cache\n# immutable = no revalidation needed\n# age: 123456 = cached on edge for 123456 seconds\n# x-cache: Hit = served from CloudFront edge","description":"Using curl to verify Cache-Control headers and CDN caching behavior."},{"title":"Cache-Control with Express (Node.js)","useCase":"Setting headers from application code.","code":"const express = require(\"express\");\nconst app = express();\n\n// Middleware to set cache headers based on path\napp.use((req, res, next) => {\n  // Versioned assets: cache forever\n  if (/.[a-f0-9]{8,}.(css|js)$/.test(req.path)) {\n    res.setHeader(\"Cache-Control\",\n      \"public, max-age=31536000, immutable\");\n  }\n  // Images: cache 30 days\n  else if (/.(png|jpg|webp)$/.test(req.path)) {\n    res.setHeader(\"Cache-Control\",\n      \"public, max-age=2592000\");\n  }\n  // API responses: no browser cache, CDN cache short\n  else if (req.path.startsWith(\"/api/\")) {\n    res.setHeader(\"Cache-Control\",\n      \"no-cache, s-maxage=60\");\n  }\n  // Default HTML\n  else {\n    res.setHeader(\"Cache-Control\",\n      \"public, max-age=0, must-revalidate\");\n  }\n  next();\n});","description":"Express.js middleware setting Cache-Control headers based on file type patterns."},{"title":"stale-while-revalidate Pattern","useCase":"Resilient caching with background refresh.","code":"# Cache-Control with stale-while-revalidate\n# max-age=60: cache for 1 minute\n# stale-while-revalidate=86400: for the next 24 hours,\n#   serve stale content while asynchronously refreshing\n\n# Header:\n# Cache-Control: public, max-age=60,\n#   stale-while-revalidate=86400\n\n# Timeline:\n# T=0: Fetch content, cache (max-age=60)\n# T=30: Request -> HIT (fresh)\n# T=61: TTL expired, content is stale\n# T=61: Request -> SERVE STALE + background refresh\n#        User gets instant response from cache\n#        Server asynchronously fetches new content\n#        Cache is updated with fresh content\n# T=90: Request -> HIT (fresh again)\n\n# Benefits:\n# - No cache miss penalty for users\n# - Origin load is smoothed (not bursty)\n# - Content is always eventually fresh","description":"Explanation of stale-while-revalidate pattern with timeline showing how it eliminates cache miss penalties."}],"mcqQuestions":[{"question":"What does s-maxage control?","options":["Browser cache time","CDN/Proxy cache time","Server processing time","DNS cache time"],"answer":1,"explanation":"s-maxage overrides max-age for shared caches (CDNs and proxies)."},{"question":"What is the difference between no-cache and no-store?","options":["Same thing","no-cache: revalidate before use; no-store: never cache","no-cache: never cache; no-store: revalidate","Both prevent all caching"],"answer":1,"explanation":"no-cache allows caching but requires revalidation. no-store prohibits caching entirely."},{"question":"What does the immutable directive do?","options":["Content can be modified","Content never changes on that URL","Cache cannot be changed","Content is encrypted"],"answer":1,"explanation":"immutable tells the browser the content will never change on that URL."},{"question":"Which caching issue does stale-while-revalidate solve?","options":["Cache corruption","Cache miss latency penalty","Cache size limits","Cache key conflicts"],"answer":1,"explanation":"stale-while-revalidate eliminates the user-facing latency penalty of cache misses."},{"question":"What Cache-Control value prevents CDN caching?","options":["public","private","max-age=3600","s-maxage=3600"],"answer":1,"explanation":"Cache-Control: private prevents CDNs and proxies from caching the content."},{"question":"What is the default behavior without Cache-Control?","options":["No caching","Heuristic caching (varies by browser/CDN)","Cache forever","Error"],"answer":1,"explanation":"Without Cache-Control, browsers and CDNs use heuristic caching based on status code and other headers."}]};
TOPICS_DATA["cdn"]["cdn-ttl"] = {"id":"cdn-ttl","title":"TTL (Time To Live)","difficulty":"beginner","estimatedMinutes":15,"tldr":["TTL (Time To Live) defines how long a CDN edge server should keep cached content before considering it stale and re-fetching from the origin.","TTL is set via the Cache-Control max-age directive (in seconds) from the origin server. Example: max-age=3600 means cache for 1 hour.","Longer TTLs improve cache hit ratios and reduce origin load but risk serving stale content. Shorter TTLs ensure freshness but reduce cache efficiency.","CDNs typically have configurable minimum, default, and maximum TTL settings that override or constrain the origin-provided TTL."],"laymanDefinition":"TTL is like the expiration date on a yogurt container. The manufacturer (origin) stamps a best-before date (TTL). The store (CDN edge) keeps the yogurt on the shelf until that date. After the date passes, the store throws it out and gets fresh stock from the warehouse. If the date is far in the future (long TTL), the store checks less often. If it is close (short TTL), the store checks frequently for fresher stock.","deepDive":[{"heading":"How TTL Works in CDNs","text":"When the origin responds with Cache-Control: max-age=3600, the CDN stores the content and sets a timer for 3600 seconds. For subsequent requests within that window, the content is served from cache (HIT). After 3600 seconds, the content is stale and the CDN re-fetches from origin on the next request. The CDN may also have MinTTL and MaxTTL boundaries."},{"heading":"Default vs Min vs Max TTL","text":"CDNs like CloudFront have three settings: Minimum TTL (MinTTL): shortest time to cache regardless of origin header. Default TTL: used when origin doesn\\'t set max-age. Maximum TTL (MaxTTL): longest time to cache regardless of origin header. These create boundaries: final TTL = clamp(origin_max_age, MinTTL, MaxTTL)."},{"heading":"Choosing TTL Values","text":"Static versioned assets (style.abc123.css): 1 year (31536000 seconds) with immutable. Static unversioned: 1-30 days. Blog posts: 1-7 days. News articles: minutes to hours. API responses: 0-60 seconds. HTML pages: 0-300 seconds. The Pareto principle applies — 80% of TTL benefit comes from setting long TTLs on the 20% of content that is most cacheable."},{"heading":"TTL and Content Freshness","text":"Trade-off: longer TTL = better performance, worse freshness. For a blog, 1-hour TTL means some readers may see a 1-hour-old page after an edit. For stock prices, a 1-second TTL is too stale. Solution: separate cacheable and non-cacheable content. Use s-maxage for different CDN vs browser TTLs. Use versioned filenames to effectively get \"infinite\" TTL."},{"heading":"TTL and Cache Invalidation","text":"Long TTLs mean content stays cached longer — when you need to update content, you must either wait for TTL expiry or use cache invalidation. Versioned filenames let you use infinite TTL (1 year) without invalidation issues — old filename becomes unreferenced, new filename gets its own cache. This is the ideal approach for static assets."}],"interviewAnswer":"TTL defines how long CDNs cache content. Longer TTLs = better performance but potentially stale content. Use versioned filenames for infinite TTL on static assets. Set shorter TTLs for dynamic content. CDNs clamp origin TTLs with Min/Max TTL settings. Balance freshness and performance based on content type.","interviewQuestions":[{"question":"What is TTL in CDN context?","answer":"Time To Live — how long a CDN caches content before considering it stale and re-fetching from origin."},{"question":"How is TTL set?","answer":"Via the Cache-Control: max-age=<seconds> response header from the origin server."},{"question":"What happens when TTL expires?","answer":"The cached content becomes stale. The next request triggers a re-fetch from the origin (cache miss)."},{"question":"What are MinTTL, DefaultTTL, and MaxTTL?","answer":"CDN-imposed boundaries that override or constrain the origin-provided TTL within these limits."},{"question":"What TTL should you use for versioned static assets?","answer":"1 year (31536000 seconds) with the immutable directive."},{"question":"What is the trade-off with long TTLs?","answer":"Better cache hit ratio and performance vs. serving potentially stale content."},{"question":"How do versioned filenames relate to TTL?","answer":"They allow effectively infinite TTL because the old filename is never requested again when content changes."},{"question":"What TTL is appropriate for HTML pages?","answer":"0-300 seconds (short) or no-cache with must-revalidate. HTML changes frequently and needs freshness."},{"question":"What TTL is appropriate for API responses?","answer":"Depends on the data. Stock prices: 0 seconds. Weather: 300 seconds. Blog posts: 3600 seconds."},{"question":"What is the default TTL if no max-age is set?","answer":"CDN provider-specific. CloudFront: 24 hours. Cloudflare: varies. Nginx proxy: none (no caching by default)."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">TTL (Time To Live)</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Origin Response</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">max-age=3600</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"225\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CDN Edge</text><text x=\"225\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">TTL Timer: 3600s</text><line x1=\"290\" y1=\"48\" x2=\"320\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"330\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"400\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cache HIT</text><text x=\"400\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">While TTL valid</text><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">TTL Expired</text><text x=\"65\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">3600s elapsed</text><line x1=\"120\" y1=\"83\" x2=\"150\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"70\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"225\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Stale Content</text><text x=\"225\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Re-fetch from origin</text><rect x=\"10\" y=\"100\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Versioned URLs</text><text x=\"65\" y=\"119\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Infinite TTL effect</text><rect x=\"160\" y=\"100\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"225\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">No Invalidation</text><text x=\"225\" y=\"119\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Old URL unused</text><text x=\"240\" y=\"185\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">TTL (Time To Live): How long content is cached bef</text><text x=\"240\" y=\"197\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ore re-fetching. Longer = better performance, but </text><text x=\"240\" y=\"209\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">potentially stale.</text></svg>","codeExamples":[{"title":"Setting TTL via Cache-Control on Origin","useCase":"Configuring TTL values.","code":"# Different TTL configurations for different needs\n\n# Cache for 1 hour:\n# Cache-Control: public, max-age=3600\n\n# Cache for 24 hours:\n# Cache-Control: public, max-age=86400\n\n# Cache for 1 year (static versioned assets):\n# Cache-Control: public, max-age=31536000, immutable\n\n# Short cache with revalidation:\n# Cache-Control: public, max-age=0, must-revalidate\n\n# CDN caches longer than browser:\n# Cache-Control: public, max-age=3600, s-maxage=86400\n# Browser: 1 hour, CDN: 1 day\n\n# Stale while revalidate pattern:\n# Cache-Control: public, max-age=60,\n#   stale-while-revalidate=86400","description":"Common TTL value configurations for different content types and caching strategies."},{"title":"CloudFront TTL Configuration","useCase":"Setting Min/Default/Max TTL in CloudFront.","code":"# CloudFront cache behavior TTL settings\n# These override origin Cache-Control headers:\n\n# Minimum TTL: 0 seconds\n# Respect origin max-age as-is, down to 0\n\n# Default TTL: 86400 seconds (24 hours)\n# Used when origin does NOT send max-age\n# If origin sends max-age, that takes precedence\n\n# Maximum TTL: 31536000 seconds (1 year)\n# Caps origin max-age to 1 year max\n# Even if origin sends max-age=99999999,\n# CloudFront will only cache for 1 year\n\n# CLI command to configure:\naws cloudfront update-distribution \\\n  --id E123456789ABCD \\\n  --default-cache-behavior \\\n    \"MinTTL=0,DefaultTTL=3600,MaxTTL=31536000\"","description":"CloudFront TTL configuration showing Min, Default, and Max TTL boundaries."},{"title":"TTL Debugging with Curl","useCase":"Inspecting TTL-related headers.","code":"# Check current TTL and cache age\ncurl -I https://cdn.example.com/image.jpg\n\n# Key headers for TTL analysis:\n#\n# cache-control: max-age=3600\n#   Total TTL set by origin = 3600 seconds\n#\n# age: 1234\n#   Content has been cached for 1234 seconds\n#   Remaining TTL = 3600 - 1234 = 2366 seconds\n#\n# x-cache: Hit from cloudfront\n#   It is a cache hit (within TTL window)\n#\n# Calculate when cache will expire:\n# Expires = Date when max-age was set + max-age\n# Or check \"expires\" header directly","description":"Using curl headers to analyze TTL status and remaining cache time."},{"title":"TTL Strategy by Content Type","useCase":"Recommended TTL values for different types.","code":"// Recommended TTL strategy by content type\nconst ttlConfig = {\n  \"versioned-assets\": {\n    // style.abc123.css, main.xyz789.js\n    ttl: 31536000, // 1 year\n    immutable: true,\n    reason: \"Content never changes on same URL\"\n  },\n  \"unversioned-assets\": {\n    // logo.png, favicon.ico\n    ttl: 2592000, // 30 days\n    immutable: false,\n    reason: \"Rarely changes, long cache OK\"\n  },\n  \"blog-posts\": {\n    // /blog/hello-world\n    ttl: 3600, // 1 hour\n    immutable: false,\n    reason: \"May be edited, balance freshness\"\n  },\n  \"api-public-data\": {\n    // /api/products, /api/posts\n    ttl: 60, // 1 minute\n    immutable: false,\n    reason: \"Frequently updated, CDN cache only\"\n  },\n  \"api-user-data\": {\n    // /api/user/profile\n    ttl: 0, // never\n    private: true,\n    reason: \"User-specific, never cache on CDN\"\n  }\n};","description":"JavaScript object showing recommended TTL strategy for different content categories."},{"title":"Nginx Proxy Cache TTL Configuration","useCase":"Server-side TTL settings.","code":"proxy_cache_path /var/cache/nginx levels=1:2\n  keys_zone=mycache:10m max_size=10g\n  inactive=60m use_temp_path=off;\n\nserver {\n  location / {\n    proxy_cache mycache;\n\n    # Override origin TTL with proxy_cache_valid\n    proxy_cache_valid 200 302 60m;  # 1 hour\n    proxy_cache_valid 404 1m;        # 1 minute\n    proxy_cache_valid any 10m;       # default 10 min\n\n    # Ignore origin Cache-Control\n    proxy_ignore_headers Cache-Control Expires;\n\n    # Use custom cache key with TTL consideration\n    proxy_cache_key \"$scheme$host$uri\";\n\n    proxy_pass http://origin:8080;\n  }\n}","description":"Nginx proxy cache TTL configuration with proxy_cache_valid overriding origin headers."}],"mcqQuestions":[{"question":"What does TTL stand for?","options":["Transfer Time Limit","Time To Live","Total Transfer Length","Time To Load"],"answer":1,"explanation":"TTL = Time To Live — how long content is cached."},{"question":"How is TTL typically set?","options":["DNS configuration","Cache-Control: max-age header","Server port setting","SSL certificate"],"answer":1,"explanation":"TTL is set via the Cache-Control max-age header in seconds."},{"question":"What happens when TTL expires?","options":["Content is deleted from disk","Content becomes stale, next request re-fetches","Server restarts","Cache size doubles"],"answer":1,"explanation":"After TTL expiry, the next request triggers a cache miss and re-fetch from origin."},{"question":"What TTL should versioned assets use?","options":["1 hour","1 day","1 year with immutable","0 seconds"],"answer":2,"explanation":"Versioned assets should use 1 year TTL with immutable for optimal caching."},{"question":"What does MinTTL do in CloudFront?","options":["Sets minimum cache duration regardless of origin headers","Sets maximum cache duration","Default TTL when origin has none","Disables caching"],"answer":0,"explanation":"MinTTL is the minimum time CloudFront caches content, overriding shorter origin TTLs."},{"question":"What is the trade-off with longer TTL?","options":["Better performance vs. potential stale content","More origin load vs. fresh content","Lower CHR vs. faster updates","More cost vs. better performance"],"answer":0,"explanation":"Longer TTL improves performance but risks serving stale content to users."}]};
TOPICS_DATA["cdn"]["cdn-dynamic-content"] = {"id":"cdn-dynamic-content","title":"Dynamic Content","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Dynamic content is content that changes per user, session, or context — personalized pages, API responses, shopping carts, real-time data.","Dynamic content is harder to cache because it varies by user, authentication state, location, or time. Incorrect caching can leak user data between sessions.","CDNs accelerate dynamic content through: edge computing (workers), dynamic TTL (short), surrogate keys, connection optimization (TLS, keep-alive), and route optimization.","Techniques: edge-side includes (ESI), personalized edge caching (vary by cookie/header), streaming responses via chunked transfer encoding, and smart routing to nearest origin."],"laymanDefinition":"Dynamic content is like a custom-made sandwich. Unlike pre-made sandwiches (static content) that you grab from the cooler, a custom sandwich is made fresh based on your specific order. The CDN can't pre-make your sandwich because it doesn't know what you'll order. However, the CDN can speed up the ordering process and the route from kitchen to you.","deepDive":[{"heading":"Why Dynamic Content is Hard to Cache","text":"Dynamic content is user-specific (personalized dashboards), session-specific (shopping cart contents), time-sensitive (stock prices), or dependent on authentication state. Each variation would need a separate cache entry, making caching inefficient. Cache keys must include cookies, headers, or authentication tokens to isolate user data."},{"heading":"Dynamic Content Acceleration Techniques","text":"TLS connection reuse: CDN maintains persistent connections to origin, reducing connection overhead. TCP optimization: optimized congestion control algorithms reduce latency. Route optimization: CDN uses real-time internet health data to find the best path to origin. Preconnect: CDN establishes early connections to speed up dynamic requests."},{"heading":"Edge Computing for Dynamic Content","text":"Cloudflare Workers, Fastly Compute@Edge, and CloudFront Functions can generate dynamic responses at the edge without hitting the origin. Use cases: A/B testing (serve variant based on cookie), personalization (modify HTML based on geolocation), API aggregation (combine multiple API responses), authentication (validate JWT at edge)."},{"heading":"Caching Dynamic Content (Selectively)","text":"Cache personalized content with Vary header (Vary: Cookie, Authorization). Use short TTLs (30-60 seconds) for semi-dynamic content. Cache fragments via Edge Side Includes (ESI). Use surrogate keys to invalidate groups. Cache API responses with user-specific cache keys. Only cache if the benefit outweighs the complexity."},{"heading":"Dynamic vs Static Content Separation","text":"Best practice: separate dynamic and static content on different URL patterns. Static: /static/, /assets/, /images/. Dynamic: /api/, /app/, /dashboard/. This allows different CDN configurations (TTL, cache policies, origin groups) for each. Many CDNs support path-based behavior configuration."}],"interviewAnswer":"Dynamic content is personalized or time-sensitive and harder to cache than static content. CDNs accelerate it through edge computing, connection optimization, and smart routing. Use selective caching with Vary headers and short TTLs for semi-dynamic content. Separate dynamic and static URL patterns for optimal CDN configuration.","interviewQuestions":[{"question":"What is dynamic content in CDN context?","answer":"Content that changes per user, session, or context — personalized pages, API responses, real-time data."},{"question":"Why is dynamic content hard to cache?","answer":"Because it varies by user, auth state, time, or location — each variation needs a separate cache entry."},{"question":"How does edge computing help with dynamic content?","answer":"By running code (workers) at the edge to generate or modify dynamic responses without hitting the origin."},{"question":"What is the Vary header used for?","answer":"To tell CDNs to cache different versions based on request headers like Cookie, Authorization, or Accept-Language."},{"question":"What is dynamic TTL?","answer":"A TTL that varies based on content type, URL pattern, or response headers — short TTL for dynamic content."},{"question":"What is ESI (Edge Side Includes)?","answer":"A technology that allows composing dynamic content from cached fragments at the edge."},{"question":"How do CDNs accelerate uncacheable dynamic content?","answer":"Through TLS reuse, TCP optimization, route optimization, and preconnect to reduce latency."},{"question":"Should dynamic and static content use the same CDN configuration?","answer":"No — separate URL patterns allow different caching rules, TTLs, and origin behaviors."},{"question":"What is a common pattern for caching API responses?","answer":"Short TTL (30-60 seconds), Vary on Authentication header, cache key includes user/device ID."},{"question":"How does Surrogate-Key help with dynamic content?","answer":"It allows selective invalidation of related dynamic content without purging everything."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Dynamic Content</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Static Content</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cache long TTL</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Dynamic Content</text><text x=\"65\" y=\"73\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Per-user, uncacheabl</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">e</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"230\" height=\"70\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"275\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CDN Edge Acceleration</text><text x=\"275\" y=\"88\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Edge workers, TLS reuse, route optimizati</text><text x=\"275\" y=\"99\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">on, selective caching with Vary header.</text><rect x=\"10\" y=\"100\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Edge Workers</text><text x=\"65\" y=\"119\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Generate at edge</text><rect x=\"10\" y=\"130\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Selective Cache</text><text x=\"65\" y=\"138\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Vary: Cookie, TTL=60</text><text x=\"65\" y=\"149\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">s</text><rect x=\"10\" y=\"160\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"176\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Route Optimization</text><text x=\"65\" y=\"179\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Smart path to origin</text><line x1=\"120\" y1=\"113\" x2=\"150\" y2=\"113\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"143\" x2=\"150\" y2=\"143\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"173\" x2=\"150\" y2=\"173\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><text x=\"240\" y=\"195\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Dynamic Content: Personalized, hard-to-cache conte</text><text x=\"240\" y=\"207\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">nt accelerated via edge compute, connection optimi</text><text x=\"240\" y=\"219\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">zation, and selective caching.</text></svg>","codeExamples":[{"title":"Selective Caching with Vary Header","useCase":"Caching dynamic content safely.","code":"# Cache different versions based on Cookie\n# Origin response header:\nVary: Cookie\n\n# Or more specifically:\nVary: X-User-ID, X-Region\n\n# Effect on CDN:\n# Separate cache entries per cookie value\n# Each unique cookie = separate cached response\n# Use carefully — too many variations reduce CHR\n\n# Better approach: extract only relevant cookie\n# From origin (Python/Flask example):\nfrom flask import request\nregion = request.cookies.get('region', 'default')\nresponse.headers['Vary'] = 'Cookie'\n\n# Warning: Vary: * means never cache\n# Avoid using Vary with high-cardinality values","description":"Using the Vary header to cache different versions of dynamic content based on cookies or headers."},{"title":"CloudFront Function for A/B Testing","useCase":"Edge-based dynamic modification.","code":"// CloudFront Function — runs at edge\n// Modifies response based on experiment cookie\n\nfunction handler(event) {\n  var request = event.request;\n  var headers = request.headers;\n  var cookie = headers.cookie;\n\n  // Default origin path\n  request.uri = \"/v1/index.html\";\n\n  // Check experiment cookie\n  if (cookie && cookie.value.includes(\"variant=B\")) {\n    request.uri = \"/v2/index.html\";\n  }\n\n  return request;\n}\n\n# This runs at every edge location\n# Zero latency added — no origin call needed\n# Dynamic routing based on user cookie","description":"CloudFront Function at the edge for A/B testing — dynamically routes users without origin round trip."},{"title":"Fastly VCL for Dynamic Request Routing","useCase":"Edge logic for dynamic content.","code":"# Fastly VCL: Route dynamic requests to nearest origin\n\n# Define multiple backends (origins)\nbackend us_east { .host = \"us-origin.example.com\"; }\nbackend eu_west { .host = \"eu-origin.example.com\"; }\nbackend asia { .host = \"asia-origin.example.com\"; }\n\n# Geo-based routing at edge\nsub vcl_recv {\n  # Dynamic API requests — route geographically\n  if (req.url.path ~ \"^/api/\") {\n    if (req.http.Fastly-Geo-Country ~ \"(US|CA)\") {\n      set req.backend = us_east;\n    } else if (req.http.Fastly-Geo-Country\n               ~ \"(GB|DE|FR|NL)\") {\n      set req.backend = eu_west;\n    } else {\n      set req.backend = asia;\n    }\n\n    # Don't cache API responses\n    return (pass);\n  }\n\n  # Static content — cache at edge\n  if (req.url.path ~ \"^/static/\") {\n    return (lookup);\n  }\n}","description":"Fastly VCL geo-routing dynamic requests to the nearest origin server while caching static content."},{"title":"Edge Worker for API Aggregation","useCase":"Combining multiple API calls at edge.","code":"// Cloudflare Worker — aggregate APIs at edge\n// Reduces multiple client requests to one edge call\n\nexport default {\n  async fetch(request) {\n    const url = new URL(request.url);\n\n    if (url.pathname === \"/api/dashboard\") {\n      // Fetch multiple APIs in parallel from edge\n      const [user, orders, recommendations] =\n        await Promise.all([\n          fetch(\"https://api.example.com/user\"),\n          fetch(\"https://api.example.com/orders\"),\n          fetch(\"https://api.example.com/recommend\")\n        ]);\n\n      // Combine at edge — single client response\n      const dashboard = {\n        user: await user.json(),\n        orders: await orders.json(),\n        recommendations: await recommendations.json()\n      };\n\n      return new Response(JSON.stringify(dashboard), {\n        headers: {\"Content-Type\": \"application/json\"}\n      });\n    }\n\n    return fetch(request); // pass through\n  },\n}","description":"Edge worker aggregating multiple API calls into a single response, reducing client-side latency."},{"title":"Private Cache for Dynamic Content","useCase":"Ensuring dynamic content is not cached by CDN.","code":"# Option 1: Set Cache-Control to private/no-store\n# Cache-Control: private, no-store\n# CDN will never cache this response\n# Browser will not cache either\n\n# Option 2: Set Cache-Control to no-cache\n# Cache-Control: no-cache\n# Browser may cache but must revalidate\n# CDN should not cache (varies by provider)\n\n# Option 3: Set s-maxage=0\n# Cache-Control: public, max-age=3600, s-maxage=0\n# Browser caches 1 hour,\n# CDN does not cache at all (s-maxage=0)\n\n# Option 4: Custom header to bypass CDN cache\n# X-Accel-Expires: 0  (for Nginx-based CDNs)","description":"Methods to ensure dynamic content is never cached by the CDN while allowing selective browser caching."}],"mcqQuestions":[{"question":"What is dynamic content in CDN context?","options":["Content that never changes","Content that varies by user/session/context","Only video content","Only HTML content"],"answer":1,"explanation":"Dynamic content varies by user, session, time, or context."},{"question":"Why is caching dynamic content challenging?","options":["It is too large","It varies by user/context creating many cache entries","It is encrypted","It expires too fast"],"answer":1,"explanation":"Each variation of dynamic content needs a separate cache entry, making caching inefficient."},{"question":"What does the Vary header do?","options":["Changes the content encoding","Tells CDN to cache different versions based on request headers","Varies the TTL dynamically","Changes the origin server"],"answer":1,"explanation":"Vary tells CDNs to cache different versions based on request headers like Cookie or Authorization."},{"question":"What is an Edge Worker used for?","options":["Cleaning edge cache","Running code at edge for dynamic responses","Managing DNS records","Compressing images"],"answer":1,"explanation":"Edge Workers run custom code at CDN edge locations for dynamic content generation."},{"question":"What is ESI?","options":["Edge Side Includes — dynamic content assembly from cached fragments","Extra Server Infrastructure","Elastic Server Integration","Edge Security Interface"],"answer":0,"explanation":"ESI allows composing dynamic content from cached fragments at the edge."},{"question":"What CDN feature helps with selective dynamic content caching?","options":["Cache-Control: private","s-maxage with Vary header","Increasing TTL","Disabling cache entirely"],"answer":1,"explanation":"Using s-maxage with Vary header allows selective caching of dynamic content with user-specific variations."}]};
TOPICS_DATA["cdn"]["cdn-static-content"] = {"id":"cdn-static-content","title":"Static Content","difficulty":"beginner","estimatedMinutes":10,"tldr":["Static content refers to files that do not change frequently and can be cached for long periods — images, CSS, JavaScript, fonts, PDFs, and videos.","Static content is the easiest to optimize with CDNs because it is identical for every user and rarely changes between requests.","Best practices: use versioned filenames (style.abc123.css) with immutable caching, long TTLs (1 year), and aggressive CDN caching with public Cache-Control.","Static assets typically account for 70-90% of a website's total page weight, making their optimization critical for overall performance."],"laymanDefinition":"Static content is like pre-packaged snack bags in a vending machine. Everyone gets the same chips in the same packaging. The vending machine (CDN) can be stocked with thousands of bags, and they don't spoil for a long time. Once stocked, the machine serves them instantly without needing to call the factory. No customization, no expiration worries.","deepDive":[{"heading":"Types of Static Content","text":"Images: JPEG, PNG, WebP, AVIF, SVG. Stylesheets: CSS (often versioned). Scripts: JavaScript (bundled, minified, versioned). Fonts: WOFF2, WOFF, TTF. Media: MP4, WebM, PDF documents. Archives: ZIP files, installers. API responses that are public and rarely changing (JSON/XML)."},{"heading":"Optimal Caching for Static Content","text":"Set Cache-Control: public, max-age=31536000, immutable for versioned assets. For unversioned but rarely changed: public, max-age=2592000 (30 days). Use content hashes in filenames (Webpack, Vite, esbuild output). Serve from CDN with origin shield. Enable compression (Brotli > Gzip). Use HTTP/2 or HTTP/3 for multiplexing."},{"heading":"Static Content Optimization Techniques","text":"Minification: remove whitespace, comments. Bundling: combine multiple files into fewer requests. Tree-shaking: remove unused code. Image optimization: WebP/AVIF, responsive images (srcset), lazy loading. Font subsetting: include only needed characters. Critical CSS inlining for above-the-fold content."},{"heading":"Fingerprinting / Versioning","text":"Content hash in filename: style.4a5b6c7d.css. When content changes, the hash changes, creating a new URL. Old file remains cached but is never requested. No invalidation needed. Build tools: Webpack [contenthash], Vite [hash], esbuild [hash]."},{"heading":"CDN Impact on Static Content","text":"Static content benefits most from CDN: 90%+ cache hit ratio achievable. Origin offload for static content can exceed 95%. Bandwidth savings are significant. Page load time improvements of 40-60% for first visits, 80%+ for repeat visits. Global users see consistent fast load times regardless of location."}],"interviewAnswer":"Static content (images, CSS, JS, fonts) is ideal for CDN caching. Use versioned filenames with immutable, long TTL caching. Optimize with compression, minification, and responsive images. Static assets typically account for 70-90% of page weight, and CDN optimization can improve load times by 60% or more.","interviewQuestions":[{"question":"What is static content?","answer":"Files that do not change frequently and are identical for every user — images, CSS, JS, fonts, PDFs."},{"question":"What percentage of page weight is typically static content?","answer":"70-90% of total page weight."},{"question":"What is the optimal Cache-Control for versioned static assets?","answer":"Cache-Control: public, max-age=31536000, immutable (1 year, never revalidate)."},{"question":"What is content fingerprinting?","answer":"Adding a content hash to the filename (style.abc123.css) so the URL changes when content changes."},{"question":"What is the benefit of versioned filenames?","answer":"Old cache is never requested again after update — eliminates need for cache invalidation."},{"question":"What is the typical cache hit ratio for static content on a CDN?","answer":"90-95% or higher."},{"question":"What compression should be used for static content?","answer":"Brotli (preferred) or Gzip. Enable at CDN level and serve pre-compressed files when possible."},{"question":"How much can a CDN improve static content load times?","answer":"40-60% for first visits, 80%+ for repeat visits compared to direct origin access."},{"question":"What is tree-shaking?","answer":"Removing unused code from JavaScript bundles to reduce file size."},{"question":"What image formats are best for static content delivery?","answer":"WebP and AVIF offer superior compression compared to JPEG and PNG."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Static Content</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CSS files</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">style.abc123.css</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">JS files</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">bundle.xyz789.js</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Images</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">WebP/AVIF/JPEG</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Fonts</text><text x=\"65\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">WOFF2, variable</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Media</text><text x=\"65\" y=\"174\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">MP4, WebM</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"220\" height=\"155\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Static Content CDN</text><text x=\"270\" y=\"173\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Versioned filenames, immutable cache, lo</text><text x=\"270\" y=\"184\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ng TTL (1 year), compression, 95%+ CHR.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Static Content: Images, CSS, JS, fonts — ideal for</text><text x=\"240\" y=\"232\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\"> CDN with versioned filenames, long TTL, and aggre</text><text x=\"240\" y=\"244\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ssive caching.</text></svg>","codeExamples":[{"title":"HTML Template with Versioned Static Assets","useCase":"Loading versioned assets via CDN.","code":"<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>My App</title>\n\n  <!-- Versioned CSS with long-term CDN caching -->\n  <link rel=\"stylesheet\"\n    href=\"https://cdn.example.com/css/app.4a5b6c7d.css\">\n  <link rel=\"stylesheet\"\n    href=\"https://cdn.example.com/css/vendor.1a2b3c4d.css\">\n\n  <!-- Preconnect to CDN for faster asset loading -->\n  <link rel=\"preconnect\" href=\"https://cdn.example.com\">\n  <link rel=\"dns-prefetch\" href=\"https://cdn.example.com\">\n\n  <!-- Preload critical assets -->\n  <link rel=\"preload\"\n    href=\"https://cdn.example.com/fonts/inter.woff2\"\n    as=\"font\" type=\"font/woff2\" crossorigin>\n</head>\n<body>\n  <!-- Responsive image with srcset -->\n  <img\n    src=\"https://cdn.example.com/img/hero-640.webp\"\n    srcset=\"\n      https://cdn.example.com/img/hero-640.webp 640w,\n      https://cdn.example.com/img/hero-1280.webp 1280w,\n      https://cdn.example.com/img/hero-1920.webp 1920w\"\n    sizes=\"(max-width: 640px) 100vw, 50vw\"\n    loading=\"lazy\"\n    alt=\"Hero image\">\n\n  <!-- Versioned JavaScript -->\n  <script\n    src=\"https://cdn.example.com/js/bundle.xyz789.js\"\n    defer></script>\n</body>\n</html>","description":"HTML template with versioned static assets loaded from CDN, preconnect hints, and responsive images."},{"title":"Webpack Config for Content Hash Filenames","useCase":"Automatic versioned filenames.","code":"// webpack.config.js\nconst path = require(\"path\");\nconst HtmlWebpackPlugin = require(\"html-webpack-plugin\");\n\nmodule.exports = {\n  entry: \"./src/index.js\",\n  output: {\n    path: path.resolve(__dirname, \"dist\"),\n    filename: \"js/[name].[contenthash:8].js\",\n    chunkFilename: \"js/[id].[contenthash:8].chunk.js\",\n    assetModuleFilename: \"assets/[hash:8][ext]\",\n    publicPath: \"https://cdn.example.com/\",\n    clean: true,\n  },\n  plugins: [\n    new HtmlWebpackPlugin({\n      template: \"./src/index.html\",\n      inject: true,\n    }),\n  ],\n  optimization: {\n    splitChunks: {\n      chunks: \"all\",\n      cacheGroups: {\n        vendor: {\n          test: /[\\\\/]node_modules[\\\\/]/,\n          name: \"vendor\",\n          chunks: \"all\",\n        },\n      },\n    },\n  },\n  module: {\n    rules: [{\n      test: /\\.(png|jpg|webp|svg)$/,\n      type: \"asset\",\n      parser: {\n        dataUrlCondition: {\n          maxSize: 8 * 1024,\n        },\n      },\n    },],\n  },\n};","description":"Webpack configuration generating content-hash-based filenames for automatic CDN cache busting."},{"title":"Serving Pre-compressed Static Assets from CDN","useCase":"Brotli and Gzip compression.","code":"# CloudFront: Enable Brotli compression\n# In CloudFront distribution settings:\n#   Supported HTTP Versions: HTTP/2, HTTP/3\n#   Compression: Automatically compress objects\n\n# Nginx origin with pre-compressed files:\nserver {\n  location /static/ {\n    root /var/www;\n    gzip_static on;\n    gunzip on;\n    add_header Content-Encoding br;\n  }\n}\n\n# Pre-compress at build time:\n#!/bin/bash\nfind dist -type f \\( -name \"*.css\" -o -name \"*.js\"\n  -o -name \"*.html\" -o -name \"*.svg\" \\) | while read f; do\n  gzip -k -f -9 \"$f\"\n  brotli -k -f -q 11 \"$f\"\ndone","description":"Pre-compressing static assets with Brotli and Gzip for efficient CDN delivery."},{"title":"CDN Cache Configuration for Static Content (Nginx)","useCase":"Optimizing static content caching.","code":"server {\n  listen 80;\n  server_name cdn.example.com;\n\n  location ~* \\.(css|js)$ {\n    root /var/www/static;\n    expires 1y;\n    add_header Cache-Control \"public, max-age=31536000, immutable\";\n    gzip_static on;\n    brotli_static on;\n  }\n\n  location ~* \\.(png|jpg|jpeg|gif|webp|avif|svg)$ {\n    root /var/www/images;\n    expires 30d;\n    add_header Cache-Control \"public, max-age=2592000\";\n  }\n\n  location ~* \\.(woff2?|ttf|eot)$ {\n    root /var/www/fonts;\n    expires 1y;\n    add_header Cache-Control \"public, max-age=31536000\";\n    add_header Access-Control-Allow-Origin \"*\";\n  }\n}","description":"Nginx CDN configuration optimized for static content with long TTLs and compression."},{"title":"Lighthouse Performance Budget for Static Content","useCase":"Setting targets for static content optimization.","code":"module.exports = {\n  ci: {\n    collect: {\n      url: [\"https://example.com\"],\n      numberOfRuns: 3,\n    },\n    assert: {\n      assertions: {\n        \"total-byte-weight\": [\"error\", {\n          maxNumericValue: 500 * 1024,\n        }],\n        \"uses-optimized-images\": \"error\",\n        \"uses-webp-images\": \"error\",\n        \"offscreen-images\": \"error\",\n        \"render-blocking-resources\": [\"error\", {\n          maxNumericValue: 0,\n        }],\n        \"unminified-css\": \"error\",\n        \"unminified-javascript\": \"error\",\n        \"uses-responsive-images\": \"error\",\n      },\n    },\n  },\n};","description":"Lighthouse CI configuration enforcing performance budgets for static content optimization."}],"mcqQuestions":[{"question":"What types of content are considered static?","options":["API responses, user profiles","Images, CSS, JS, fonts (unchanging per user)","Live chat messages","Stock ticker data"],"answer":1,"explanation":"Static content includes images, CSS, JavaScript, fonts."},{"question":"What percentage of page weight is static content?","options":["10-20%","30-40%","70-90%","100%"],"answer":2,"explanation":"Static content typically makes up 70-90% of a page\\'s total weight."},{"question":"What is the optimal TTL for versioned static assets?","options":["1 hour","1 week","1 year with immutable","Never cache"],"answer":2,"explanation":"Versioned assets should use 1 year TTL with the immutable directive."},{"question":"What is content fingerprinting?","options":["Adding user fingerprints","Adding content hash to filenames","Fingerprint authentication","Image optimization"],"answer":1,"explanation":"Content fingerprinting adds a hash of the file content to the filename for automatic cache busting."},{"question":"What is the typical cache hit ratio for static content on CDN?","options":["50%","70%","90-95%","99%"],"answer":2,"explanation":"Static content typically achieves 90-95%+ cache hit ratios on CDNs."},{"question":"What is the best compression for static text assets?","options":["Brotli","Gzip","Deflate","Zstandard"],"answer":0,"explanation":"Brotli offers better compression ratios than Gzip for text-based static assets."}]};
TOPICS_DATA["cdn"]["cdn-image-optimization"] = {"id":"cdn-image-optimization","title":"Image Optimization","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Image optimization reduces file sizes while maintaining visual quality, improving page load times and reducing bandwidth costs.","Modern formats (WebP, AVIF) offer 25-50% better compression than JPEG/PNG with similar quality. Serve the best format based on browser support.","CDN image optimization features: on-the-fly resizing, format conversion, quality adjustment, cropping, compression, and responsive image generation.","Images account for ~50% of a typical webpage's total weight. Optimization is the single highest-impact performance improvement you can make."],"laymanDefinition":"Image optimization is like packing a suitcase. A JPEG is a bulky suitcase that fits everything but weighs a ton. WebP is a modern vacuum-compression bag that fits the same clothes in half the space. AVIF is like using a vacuum sealer — even smaller. The CDN image optimizer is your packing assistant that chooses the right bag and squishes everything perfectly.","deepDive":[{"heading":"Image Formats Compared","text":"JPEG: lossy, 8-bit, good for photos, no transparency. PNG: lossless, up to 48-bit, transparency, good for graphics. GIF: 256 colors, animation. WebP: lossy/lossless, 24-bit, transparency, animation, 25-35% smaller than JPEG. AVIF: lossy/lossless, HDR, 12-bit, transparency, 50% smaller than JPEG. SVG: vector, resolution-independent, code-based."},{"heading":"CDN Image Processing Features","text":"Resize: generate exact dimensions needed. Format conversion: auto-serve WebP/AVIF based on Accept header. Quality: adjust compression level (q=50-85). Crop: smart cropping with focal point detection. Compress: remove metadata. Strip EXIF: remove camera data. Blur: for placeholders. Watermark: overlay branding. All at the edge cache."},{"heading":"Responsive Images with srcset","text":"Use HTML srcset and sizes attributes to serve different image sizes based on viewport. CDN generates 3-5 variants at different widths. Browser selects the best size. Combined with CDN: single upload, multiple cached variants. Example sizes: 480w, 768w, 1024w, 1920w."},{"heading":"Image CDNs vs General CDNs","text":"Specialized image CDNs (Imgix, Cloudinary, ImageKit): extensive transformation APIs, real-time processing, AI-based compression. General CDNs (CloudFront, Cloudflare, Fastly): basic resizing/format conversion via Workers or Lambda@Edge. Choose based on needs."},{"heading":"Lazy Loading and Preloading","text":"Native lazy loading: loading=lazy attribute defers off-screen images. Intersection Observer: custom lazy loading with fade-in effects. Critical images: preload above-the-fold images with <link rel=preload>. Blur-up placeholders: tiny blurred version shown while full image loads."}],"interviewAnswer":"Image optimization reduces file size 25-80% through modern formats (WebP, AVIF), CDN-based resizing, quality adjustment, and responsive image techniques. Images are ~50% of page weight, making this the highest-impact optimization.","interviewQuestions":[{"question":"What percentage of page weight do images account for?","answer":"Approximately 50% of a typical webpage\\'s total weight."},{"question":"What are the best modern image formats?","answer":"WebP (25-35% smaller than JPEG) and AVIF (50% smaller than JPEG)."},{"question":"How does a CDN optimize images?","answer":"Through on-the-fly resizing, format conversion (WebP/AVIF), quality adjustment, compression, and cropping at the edge."},{"question":"What is the srcset attribute used for?","answer":"To serve different image sizes based on viewport width, combined with CDN-generated variants."},{"question":"What is the difference between WebP and AVIF?","answer":"AVIF offers ~50% better compression than JPEG; WebP offers 25-35%. AVIF supports HDR and 12-bit color."},{"question":"What is lazy loading?","answer":"Deferring off-screen image loading until the user scrolls near them. Native with loading=lazy."},{"question":"What EXIF data should be stripped from images?","answer":"Camera model, GPS location, date/time, and device information to improve privacy and reduce file size."},{"question":"How does format conversion work at the CDN?","answer":"CDN checks the Accept header for image/webp or image/avif support and converts accordingly."},{"question":"What is an image CDN?","answer":"A specialized CDN focused on image transformation — Imgix, Cloudinary, ImageKit."},{"question":"What is blur-up image loading?","answer":"Showing a tiny blurred placeholder image while the full-resolution image loads from CDN."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Image Optimization</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Original Image</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">PNG 500KB</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"225\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CDN Optimizer</text><text x=\"225\" y=\"43\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Resize, convert, compre</text><text x=\"225\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ss</text><line x1=\"290\" y1=\"48\" x2=\"320\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"170\" y1=\"65\" x2=\"170\" y2=\"85\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"330\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"400\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">WebP</text><text x=\"400\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">200KB (60% smaller)</text><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">AVIF</text><text x=\"65\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">125KB (75% smaller)</text><rect x=\"10\" y=\"100\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Responsive</text><text x=\"65\" y=\"119\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">srcset variants</text><rect x=\"10\" y=\"130\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Lazy Loading</text><text x=\"65\" y=\"149\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">loading=lazy</text><rect x=\"160\" y=\"70\" width=\"310\" height=\"130\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"315\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Image Optimization at CDN</text><text x=\"315\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Format conversion (WebP/AVIF), resizing, compression, re</text><text x=\"315\" y=\"194\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">sponsive images — all at the edge.</text><text x=\"240\" y=\"225\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Image Optimization: Modern formats (WebP, AVIF), C</text><text x=\"240\" y=\"237\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">DN processing, responsive images, and lazy loading</text><text x=\"240\" y=\"249\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">.</text></svg>","codeExamples":[{"title":"CloudFront Image Optimization with Lambda@Edge","useCase":"On-the-fly image transformation.","code":"const sharp = require(\"sharp\");\n\nexports.handler = async (event) => {\n  const request = event.Records[0].cf.request;\n  const headers = request.headers;\n  if (!request.uri.match(/\\.(jpg|jpeg|png)$/)) {\n    return request;\n  }\n  const accept = headers[\"accept\"];\n  if (accept && accept[0].value.includes(\"webp\")) {\n    request.uri = request.uri.replace(/\\.(jpg|jpeg|png)$/, \".webp\");\n  }\n  return request;\n};","description":"Lambda@Edge function that converts images to WebP format at the CDN edge based on browser support."},{"title":"Cloudflare Image Resizing via Workers","useCase":"CDN image transformations.","code":"export default {\n  async fetch(request) {\n    const url = new URL(request.url);\n    if (url.pathname.match(/\\.(jpg|png)$/)) {\n      const width = url.searchParams.get(\"w\") || 800;\n      const quality = url.searchParams.get(\"q\") || 80;\n      const format = url.searchParams.get(\"fmt\") || \"webp\";\n      const resizingUrl =\n        `/cdn-cgi/image/width=${width},quality=${quality},format=${format}`\n        + url.pathname;\n      return fetch(new URL(resizingUrl, request.url));\n    }\n    return fetch(request);\n  },\n}","description":"Cloudflare Worker leveraging Image Resizing for on-the-fly format conversion."},{"title":"Nginx Image Filter Module","useCase":"Server-side image optimization.","code":"server {\n  listen 80;\n  server_name images.example.com;\n  location /uploads/ {\n    root /var/www;\n    image_filter resize 800 600;\n    image_filter_jpeg_quality 85;\n    image_filter_webp_quality 80;\n    image_filter_buffer 20M;\n    proxy_cache mycache;\n    proxy_cache_valid 200 24h;\n  }\n}","description":"Nginx image_filter module for server-side image resizing and quality adjustment."},{"title":"Responsive Images with Srcset (HTML)","useCase":"Serving multiple image sizes via CDN.","code":"<img\n  src=\"https://cdn.example.com/img/photo-800.webp\"\n  srcset=\"\n    https://cdn.example.com/img/photo-400.webp 400w,\n    https://cdn.example.com/img/photo-800.webp 800w,\n    https://cdn.example.com/img/photo-1200.webp 1200w,\n    https://cdn.example.com/img/photo-1920.webp 1920w\"\n  sizes=\"(max-width: 400px) 100vw, (max-width: 800px) 80vw, 50vw\"\n  loading=\"lazy\" decoding=\"async\"\n  alt=\"Optimized photo\">\n<picture>\n  <source srcset=\"https://cdn.example.com/img/photo.avif 1x\" type=\"image/avif\">\n  <source srcset=\"https://cdn.example.com/img/photo.webp 1x\" type=\"image/webp\">\n  <img src=\"https://cdn.example.com/img/photo.jpg\" alt=\"Fallback\" loading=\"lazy\">\n</picture>","description":"Responsive images with srcset and picture element for optimal CDN-served formats."},{"title":"Image Compression Benchmark Script","useCase":"Comparing format effectiveness.","code":"#!/usr/bin/env node\nconst sharp = require(\"sharp\");\nconst fs = require(\"fs\");\nasync function benchmark(inputPath) {\n  const formats = [\n    { name: \"JPEG (q80)\", ext: \"jpg\", opts: { quality: 80 } },\n    { name: \"WebP (q80)\", ext: \"webp\", opts: { quality: 80 } },\n    { name: \"AVIF (q50)\", ext: \"avif\", opts: { quality: 50 } },\n    { name: \"PNG\", ext: \"png\", opts: {} },\n  ];\n  const original = fs.statSync(inputPath).size;\n  console.log(`Original: ${(original / 1024).toFixed(1)}KB\\n`);\n  for (const fmt of formats) {\n    const output = inputPath.replace(/\\.\\w+$/, `.${fmt.ext}`);\n    await sharp(inputPath).toFormat(fmt.ext.replace(\"jpg\", \"jpeg\"), fmt.opts).toFile(output);\n    const size = fs.statSync(output).size;\n    const savings = ((original - size) / original * 100).toFixed(1);\n    console.log(`${fmt.name}: ${(size / 1024).toFixed(1)}KB (${savings}% smaller)`);\n  }\n}\nbenchmark(process.argv[2]);","description":"Node.js script to benchmark image format sizes and compression effectiveness."}],"mcqQuestions":[{"question":"What percentage of page weight is images?","options":["10%","25%","50%","75%"],"answer":2,"explanation":"Images account for approximately 50% of a typical webpage\\'s total weight."},{"question":"Which modern format offers the best compression?","options":["JPEG","PNG","WebP","AVIF"],"answer":3,"explanation":"AVIF offers approximately 50% better compression than JPEG."},{"question":"What does the srcset attribute do?","options":["Sets multiple sources for script loading","Serves different image sizes based on viewport","Sets image source fallback order","Configures CDN image optimization"],"answer":1,"explanation":"srcset tells the browser which image sizes are available for different viewport widths."},{"question":"What CDN feature converts images to WebP?","options":["DDoS protection","Format conversion based on Accept header","Cache invalidation","Load balancing"],"answer":1,"explanation":"CDNs convert images based on the Accept header from the browser indicating WebP/AVIF support."},{"question":"What is an image CDN example?","options":["CloudFront","Imgix","Fastly","Akamai"],"answer":1,"explanation":"Imgix is a specialized image CDN focused on real-time image transformation."},{"question":"What does loading=lazy do?","options":["Loads image immediately","Defers off-screen image loading","Applies image filter","Converts image format"],"answer":1,"explanation":"loading=lazy defers loading of off-screen images until the user scrolls near them."}]};
TOPICS_DATA["cdn"]["cdn-compression"] = {"id":"cdn-compression","title":"Compression","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Compression reduces the size of content transferred over the network, improving load times and reducing bandwidth costs for CDN delivery.","Text-based content (HTML, CSS, JS, JSON, XML, SVG) compresses extremely well — typically 70-90% size reduction.","Two main compression algorithms: Gzip (widely supported, older) and Brotli (better ratios, modern, preferred). Both are supported by all major CDNs.","CDNs can compress content on-the-fly or serve pre-compressed files. Pre-compression at build time is most efficient for static assets."],"laymanDefinition":"Compression is like vacuum-sealing your clothes for a trip. A fluffy winter jacket (uncompressed HTML file) takes up half your suitcase. Vacuum-seal it (compress with Gzip or Brotli) and it's a flat pancake taking 10% of the space. At your destination, you unseal it (browser decompresses) and it's back to normal.","deepDive":[{"heading":"How Compression Works","text":"Client sends Accept-Encoding header listing supported algorithms (br, gzip, deflate). Server/CDN selects best supported algorithm, compresses the response, adds Content-Encoding header (br for Brotli, gzip for Gzip). Client decompresses automatically."},{"heading":"Gzip Compression","text":"Based on DEFLATE algorithm. Compression levels 1-9 (level 6 default). Good balance of speed and compression. Typical reduction: 70-80% for text. Widely supported since HTTP/1.1."},{"heading":"Brotli Compression","text":"Developed by Google. Compression levels 0-11. Levels 1-4 fast, levels 5-11 higher compression. Level 11 typically 20-30% better than Gzip level 9. Supported by all modern browsers (95%+)."},{"heading":"Pre-compression Strategy","text":"Pre-compress static files at build time: generate .gz and .br versions. Nginx gzip_static/brotli_static serves pre-compressed files directly — zero CPU overhead. CDN caches compressed versions."},{"heading":"Compression Configuration at CDN","text":"CloudFront: automatic compression (Brotli preferred). Cloudflare: Auto Minify + Brotli compression. Fastly: Vary based on Accept-Encoding. Nginx CDN: gzip on, brotli on. Avoid double compression on already compressed data."}],"interviewAnswer":"Compression reduces transferred content size by 70-90% for text-based assets. Brotli is preferred over Gzip for 20-30% better ratios. Pre-compress static assets at build time. Let CDN handle compression for dynamic content.","interviewQuestions":[{"question":"What is HTTP compression?","answer":"Reducing the size of content transferred using algorithms like Gzip and Brotli."},{"question":"What is the difference between Gzip and Brotli?","answer":"Brotli offers 20-30% better compression than Gzip, especially for text."},{"question":"How does compression work in HTTP?","answer":"Client sends Accept-Encoding header. Server compresses and adds Content-Encoding header."},{"question":"What content benefits most from compression?","answer":"Text-based content: HTML, CSS, JS, JSON, XML, SVG — up to 70-90% reduction."},{"question":"What content should NOT be compressed?","answer":"Already compressed formats: JPEG, PNG, WebP, MP4, WebM, ZIP, PDF."},{"question":"What is pre-compression?","answer":"Generating compressed (.gz, .br) files at build time and serving them directly."},{"question":"What is the Accept-Encoding header?","answer":"An HTTP request header listing compression algorithms the client supports."},{"question":"What is the Content-Encoding header?","answer":"An HTTP response header indicating which compression algorithm was applied."},{"question":"Does CloudFront support Brotli?","answer":"Yes, CloudFront supports Brotli compression automatically when enabled."},{"question":"What is the most common Nginx compression config?","answer":"gzip on; gzip_types text/css application/javascript; gzip_comp_level 6;"}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Compression</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Browser Request</text><text x=\"65\" y=\"43\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Accept-Encoding: br,</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\"> gzip</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"225\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CDN Edge</text><text x=\"225\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Select best algorithm</text><line x1=\"290\" y1=\"48\" x2=\"320\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"170\" y1=\"65\" x2=\"170\" y2=\"85\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"330\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"400\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Compressed</text><text x=\"400\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Content-Encoding: br</text><rect x=\"10\" y=\"75\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pre-compressed</text><text x=\"65\" y=\"94\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">.br, .gz at build</text><rect x=\"10\" y=\"105\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">On-the-fly</text><text x=\"65\" y=\"124\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Dynamic at edge</text><rect x=\"10\" y=\"135\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"151\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">No Compression</text><text x=\"65\" y=\"154\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">JPEG, MP4, WebP</text><line x1=\"120\" y1=\"88\" x2=\"150\" y2=\"88\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"118\" x2=\"150\" y2=\"118\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"148\" x2=\"150\" y2=\"148\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"75\" width=\"150\" height=\"100\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"235\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Compression at CDN</text><text x=\"235\" y=\"147\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Brotli preferred. Pre-compr</text><text x=\"235\" y=\"158\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ess static. 70-90% size red</text><text x=\"235\" y=\"169\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">uction.</text><text x=\"240\" y=\"210\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Compression: Brotli and Gzip reduce text content 7</text><text x=\"240\" y=\"222\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">0-90%. Pre-compress static assets.</text></svg>","codeExamples":[{"title":"Nginx Gzip and Brotli Configuration","useCase":"Enabling compression on origin/CDN.","code":"http {\n  gzip on;\n  gzip_comp_level 6;\n  gzip_min_length 256;\n  gzip_types text/plain text/css application/javascript application/json text/xml image/svg+xml;\n  gzip_proxied any;\n  gzip_vary on;\n  gzip_static on;\n\n  brotli on;\n  brotli_comp_level 6;\n  brotli_static on;\n  brotli_types text/plain text/css application/javascript application/json text/xml image/svg+xml;\n}","description":"Nginx configuration for both Gzip and Brotli compression with pre-compressed file support."},{"title":"Pre-compression Build Script","useCase":"Generating compressed files at build time.","code":"#!/bin/bash\nBUILD_DIR=\"./dist\"\nfind \"$BUILD_DIR\" -type f \\( -name \"*.html\" -o -name \"*.css\" -o -name \"*.js\"\n  -o -name \"*.json\" -o -name \"*.svg\" \\) | while read -r file; do\n  if [ ! -f \"${file}.br\" ] || [ \"$file\" -nt \"${file}.br\" ]; then\n    brotli -k -f -q 11 \"$file\"\n  fi\n  if [ ! -f \"${file}.gz\" ] || [ \"$file\" -nt \"${file}.gz\" ]; then\n    gzip -k -f -9 \"$file\"\n  fi\ndone\necho \"Pre-compression complete.\"","description":"Build-time pre-compression script generating .br and .gz files for all static text assets."},{"title":"CloudFront Compression Settings","useCase":"Enabling compression in CDN.","code":"# In CloudFront distribution settings:\n# Under \"Compress objects automatically\" select Yes.\n# CloudFront will use Brotli if supported, fallback to Gzip.\n# Files must be > 1000 bytes. Already compressed formats skipped.\n\naws cloudfront update-distribution \\\n  --id E123456789ABCD \\\n  --default-cache-behavior \"Compress=true\"","description":"CloudFront automatic compression configuration."},{"title":"Curl Test for Compression","useCase":"Verifying compression is working.","code":"curl -H \"Accept-Encoding: br\" -I https://cdn.example.com/style.css\n# Response: Content-Encoding: br\ncurl -H \"Accept-Encoding: gzip\" -I https://cdn.example.com/style.css\n# Response: Content-Encoding: gzip\ncurl -s -o /dev/null -w \"Size: %{size_download} bytes\\n\" -H \"Accept-Encoding: identity\" https://cdn.example.com/style.css\ncurl -s -o /dev/null -w \"Size: %{size_download} bytes\\n\" -H \"Accept-Encoding: br\" https://cdn.example.com/style.css","description":"Curl commands to verify compression headers and compare compressed vs uncompressed sizes."},{"title":"Cloudflare Auto Minify and Compression","useCase":"Cloudflare compression features.","code":"# Cloudflare Auto Minify:\n# Speed -> Optimization -> Auto Minify\n# Toggle: HTML, CSS, JavaScript\n\n# Cloudflare Brotli compression is automatic\n# Falls back to Gzip for non-Brotli clients\n\n# Cloudflare Polish (image compression):\n# Speed -> Optimization -> Polish\n# Options: Lossless or Lossy","description":"Cloudflare compression and minification features for optimal content delivery."}],"mcqQuestions":[{"question":"What algorithm offers the best compression for text?","options":["Gzip","Brotli","Deflate","Zstandard"],"answer":1,"explanation":"Brotli offers 20-30% better compression than Gzip for text."},{"question":"What header indicates the client supports compression?","options":["Content-Encoding","Accept-Encoding","Transfer-Encoding","Cache-Control"],"answer":1,"explanation":"Accept-Encoding lists supported compression algorithms."},{"question":"What should NOT be compressed?","options":["HTML","CSS","JSON","JPEG"],"answer":3,"explanation":"Already compressed formats like JPEG should not be re-compressed."},{"question":"What is pre-compression?","options":["Compressing on every request","Generating compressed files at build time","Compressing images only","Edge-level compression"],"answer":1,"explanation":"Pre-compression generates .gz and .br files at build time."},{"question":"What does Content-Encoding indicate?","options":["Which compression algorithm was applied","What client supports","Content type","Cache policy"],"answer":0,"explanation":"Content-Encoding indicates the compression algorithm applied to the response."},{"question":"What is gzip_static in Nginx?","options":["Forces dynamic compression","Serves pre-compressed .gz files","Enables Gzip at OS level","Disables Gzip"],"answer":1,"explanation":"gzip_static serves pre-compressed .gz files without re-compressing."}]};
TOPICS_DATA["cdn"]["cdn-brotli"] = {"id":"cdn-brotli","title":"Brotli","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Brotli is a compression algorithm developed by Google that offers 20-30% better compression ratios than Gzip for web content.","Brotli uses a pre-defined dictionary of common HTML/CSS/JS strings, making it especially effective for small web files.","Compression levels: 0 (fastest) to 11 (slowest, best compression). Level 4-6 recommended for on-the-fly, level 11 for pre-compressed.","Brotli is supported by all modern browsers (95%+ global coverage). All major CDNs support Brotli."],"laymanDefinition":"Brotli is like a multilingual translator who also knows common phrases. Gzip compresses your sentence word-by-word. Brotli recognizes common phrases like \"margin: 0; padding: 0;\" and replaces them with shorthand codes. The more common phrases it knows, the shorter the message becomes.","deepDive":[{"heading":"How Brotli Achieves Better Compression","text":"Brotli uses a 120KB static dictionary of common substrings found in HTML, CSS, and JavaScript. It also employs context modeling and large sliding windows (up to 16MB). These make Brotli particularly effective for small web files where Gzip struggles with overhead."},{"heading":"Brotli Compression Levels","text":"Levels 0-4: fast compression, suitable for on-the-fly. Levels 5-9: moderate speed. Levels 10-11: highest compression, CPU-intensive, best for pre-compressed static files. Level 11 achieves 5-15% better compression than level 6 but takes 10x longer to compress. Decompression is fast at all levels."},{"heading":"Brotli vs Gzip Comparison","text":"Compression ratio: Brotli level 4 ~ Gzip level 6. Brotli level 11: 20-30% better than Gzip level 9. Compress speed: Gzip is faster. Decompress speed: Brotli is comparable or faster. File size example: 100KB JS — Gzip: ~30KB, Brotli: ~22KB."},{"heading":"Brotli at the CDN Edge","text":"CDNs can compress on-the-fly with Brotli or serve pre-compressed .br files. CloudFront: automatic Brotli. Cloudflare: Brotli enabled by default. Fastly: Brotli via VCL. Set Content-Encoding: br and Vary: Accept-Encoding for cache separation."},{"heading":"Brotli for APIs","text":"Brotli is excellent for JSON API responses. A 500KB JSON response compresses to ~50KB with Brotli (vs ~70KB with Gzip). Faster mobile API calls, reduced bandwidth costs. Always check Accept-Encoding and fallback to Gzip for older clients."}],"interviewAnswer":"Brotli is Google's compression algorithm offering 20-30% better ratios than Gzip. It excels at compressing web content due to its built-in dictionary. Use level 11 for pre-compressed static assets, level 4-6 for on-the-fly. Supported by all modern browsers and major CDNs.","interviewQuestions":[{"question":"What is Brotli?","answer":"A compression algorithm developed by Google offering 20-30% better compression than Gzip for web content."},{"question":"What makes Brotli more effective than Gzip?","answer":"A built-in dictionary of common HTML/CSS/JS strings and context modeling."},{"question":"What are Brotli compression levels?","answer":"0 (fastest) to 11 (best compression). Level 4-6 for on-the-fly, level 11 for pre-compressed."},{"question":"What improvement does Brotli offer over Gzip?","answer":"20-30% better compression ratios at equivalent quality levels."},{"question":"Is Brotli supported by all browsers?","answer":"Yes, by all modern browsers — approximately 95%+ global coverage."},{"question":"What Content-Encoding value does Brotli use?","answer":"Content-Encoding: br"},{"question":"What is the best Brotli level for pre-compressed static files?","answer":"Level 11 — highest compression, done at build time."},{"question":"Does CloudFront support Brotli?","answer":"Yes, CloudFront supports automatic Brotli compression when enabled."},{"question":"What header must be set for pre-compressed Brotli?","answer":"Content-Encoding: br and Vary: Accept-Encoding"},{"question":"Can Brotli be used for API responses?","answer":"Yes, it is excellent for JSON — typically 25-35% better than Gzip for API payloads."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Brotli</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Original</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">HTML 20KB</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Gzip</text><text x=\"215\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Level 9: 5KB</text><line x1=\"270\" y1=\"48\" x2=\"300\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"310\" y=\"35\" width=\"170\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"395\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Brotli</text><text x=\"395\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Level 11: 3.5KB</text><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Dictionary</text><text x=\"65\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">120KB common strings</text><rect x=\"10\" y=\"100\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Context Model</text><text x=\"65\" y=\"108\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Predictive compressi</text><text x=\"65\" y=\"119\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">on</text><rect x=\"10\" y=\"130\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">16MB Window</text><text x=\"65\" y=\"138\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Larger sliding windo</text><text x=\"65\" y=\"149\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">w</text><line x1=\"120\" y1=\"83\" x2=\"150\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"113\" x2=\"150\" y2=\"113\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"143\" x2=\"150\" y2=\"143\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"70\" width=\"320\" height=\"100\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"320\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Brotli Compression</text><text x=\"320\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">20-30% better than Gzip. Built-in dictionary. Level 11 for</text><text x=\"320\" y=\"164\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\"> pre-compress. CDN edge support.</text><text x=\"240\" y=\"200\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Brotli: Google's compression algorithm with 20-30%</text><text x=\"240\" y=\"212\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\"> better ratios than Gzip.</text></svg>","codeExamples":[{"title":"Build Script: Brotli Pre-compression","useCase":"Pre-compress all static assets with Brotli 11.","code":"#!/bin/bash\nDIST=\"./dist\"\nfind \"$DIST\" -type f \\( -name \"*.html\" -o -name \"*.css\" -o -name \"*.js\"\n  -o -name \"*.json\" -o -name \"*.svg\" \\) -exec sh -c '\n  brotli -k -f -q 11 \"$1\"\n' _ {} \\;\necho \"Brotli pre-compression complete.\"","description":"Build script pre-compressing all static text assets with Brotli level 11."},{"title":"Nginx Brotli Module Configuration","useCase":"Serving Brotli pre-compressed files.","code":"http {\n  server {\n    listen 80;\n    server_name cdn.example.com;\n    location /static/ {\n      root /var/www;\n      brotli_static on;\n      brotli on;\n      brotli_comp_level 6;\n      brotli_types text/css application/javascript application/json;\n    }\n    gzip on;\n    gzip_static on;\n    gzip_vary on;\n  }\n}","description":"Nginx configuration serving pre-compressed Brotli files with Gzip fallback."},{"title":"Brotli vs Gzip Size Comparison Script","useCase":"Compare compression ratios.","code":"#!/usr/bin/env node\nconst zlib = require(\"zlib\");\nconst fs = require(\"fs\");\nconst file = process.argv[2];\nconst content = fs.readFileSync(file);\nconst gzipped = zlib.gzipSync(content, { level: 9 });\nconst brotlied = zlib.brotliCompressSync(content, {\n  params: { [zlib.constants.BROTLI_PARAM_QUALITY]: 11 }\n});\nconst gzipRatio = ((1 - gzipped.length / content.length) * 100).toFixed(1);\nconst brRatio = ((1 - brotlied.length / content.length) * 100).toFixed(1);\nconst improvement = ((gzipped.length - brotlied.length) / gzipped.length * 100).toFixed(1);\nconsole.log(`Gzip: ${gzipRatio}%, Brotli: ${brRatio}%, Improvement: ${improvement}%`);","description":"Node.js script comparing Brotli vs Gzip compression ratios."},{"title":"CDN Brotli Verification with Curl","useCase":"Check if CDN is serving Brotli.","code":"curl -s -I -H \"Accept-Encoding: br\" https://cdn.example.com/style.css\n# Expect: content-encoding: br\ncurl -s -I -H \"Accept-Encoding: gzip\" https://cdn.example.com/style.css\n# Expect: content-encoding: gzip\ncurl -s -o /dev/null -w \"Time: %{time_total}s, Size: %{size_download}B\\n\" -H \"Accept-Encoding: br\" https://cdn.example.com/bundle.js\ncurl -s -o /dev/null -w \"Time: %{time_total}s, Size: %{size_download}B\\n\" -H \"Accept-Encoding: identity\" https://cdn.example.com/bundle.js","description":"Curl commands to verify Brotli compression headers from the CDN edge."},{"title":"CloudFront Brotli Configuration (AWS CLI)","useCase":"Enabling Brotli on CloudFront.","code":"aws cloudfront get-distribution-config --id E123456789ABCD --query \"DistributionConfig\" > config.json\n# Edit config.json: set \"Compress\": true in DefaultCacheBehavior\naws cloudfront update-distribution --id E123456789ABCD --if-match \"ETAG_VALUE\" --distribution-config file://config.json\n# CloudFront will now compress with Brotli when client sends Accept-Encoding: br","description":"AWS CLI steps to enable Brotli compression on CloudFront."}],"mcqQuestions":[{"question":"What is Brotli?","options":["A caching algorithm","A compression algorithm by Google","A CDN provider","A JS framework"],"answer":1,"explanation":"Brotli is a compression algorithm developed by Google."},{"question":"How much better is Brotli than Gzip?","options":["5-10%","20-30%","50%","Same"],"answer":1,"explanation":"Brotli offers 20-30% better compression ratios than Gzip."},{"question":"What is the highest Brotli compression level?","options":["5","9","10","11"],"answer":3,"explanation":"Brotli level 11 provides the highest compression ratio."},{"question":"What Content-Encoding does Brotli use?","options":["gzip","deflate","br","brotli"],"answer":2,"explanation":"Brotli uses Content-Encoding: br."},{"question":"What makes Brotli effective for web content?","options":["Larger windows only","Built-in dictionary of common web strings","Faster decompression only","Hardware acceleration"],"answer":1,"explanation":"Brotli\\'s built-in dictionary of common web strings makes it effective."},{"question":"Is Brotli supported by major CDNs?","options":["No","Only Cloudflare","Yes, all major CDNs","Only Fastly"],"answer":2,"explanation":"All major CDNs support Brotli compression."}]};
TOPICS_DATA["cdn"]["cdn-gzip"] = {"id":"cdn-gzip","title":"Gzip","difficulty":"beginner","estimatedMinutes":10,"tldr":["Gzip is a file compression algorithm widely used for HTTP content compression, reducing file sizes by 70-80% for text-based content.","Based on the DEFLATE algorithm, Gzip has been the standard HTTP compression method since HTTP/1.1.","Gzip compression levels: 1 (fastest, least compression) to 9 (slowest, best compression). Level 6 is the default and recommended balance.","While Brotli is superior, Gzip has universal support — every browser, server, and HTTP client supports Gzip."],"laymanDefinition":"Gzip is like the original vacuum-seal bag. It's been around forever, works everywhere, and everyone knows how to use it. It reduces your files to about 25% of their original size. A newer bag (Brotli) might be slightly better, but Gzip works in every suitcase (browser) ever made.","deepDive":[{"heading":"How Gzip Compression Works","text":"Gzip uses DEFLATE combining LZ77 (finds repeated sequences) and Huffman coding (shorter codes for frequent bytes). Decompression reconstructs original data exactly (lossless). Content is compressed before sending and decompressed by the browser automatically."},{"heading":"Gzip Compression Levels","text":"Level 1: fastest, ~50% reduction. Level 6: default, ~70-75% reduction (good balance). Level 9: slowest, ~75-80% reduction. Beyond level 6, diminishing returns — level 9 is only ~2% better but takes 3-4x longer to compress."},{"heading":"Gzip in CDN Context","text":"CDNs compress on-the-fly or serve pre-compressed .gz files. Static pre-compression at build time is more efficient. CDNs cache compressed versions separately (Vary: Accept-Encoding). Most CDNs prioritize Brotli when supported, falling back to Gzip."},{"heading":"Gzip Limitations","text":"Less efficient than Brotli for small files. Not effective on already-compressed data. Single-threaded compression. 32KB sliding window limits long-range duplicate detection."},{"heading":"Gzip vs Brotli Trade-offs","text":"Gzip: universal support, faster compression, good enough (70-80% reduction). Brotli: 20-30% better ratio, slower compression, 95%+ browser support. Serve Brotli to modern browsers, Gzip as fallback."}],"interviewAnswer":"Gzip is the universal standard for HTTP compression, supported by every browser and server. While Brotli offers better ratios, Gzip remains essential as a fallback. Compression levels 6-9 provide 70-80% size reduction. Pre-compress .gz files at build time for optimal CDN performance.","interviewQuestions":[{"question":"What is Gzip?","answer":"A compression algorithm for HTTP content, reducing text file sizes by 70-80%."},{"question":"What algorithm does Gzip use?","answer":"DEFLATE — combining LZ77 and Huffman coding."},{"question":"What are Gzip compression levels?","answer":"1 (fastest) to 9 (best compression). Level 6 is the default."},{"question":"What is the typical compression ratio for text?","answer":"70-80% reduction for HTML, CSS, JS, JSON."},{"question":"Does every browser support Gzip?","answer":"Yes, universal support across every browser and HTTP client."},{"question":"What Content-Encoding does Gzip use?","answer":"Content-Encoding: gzip"},{"question":"What is gzip_static in Nginx?","answer":"A module that serves pre-compressed .gz files without re-compressing."},{"question":"What should NOT be Gzip compressed?","answer":"Already compressed formats: JPEG, PNG, MP4, ZIP, PDF."},{"question":"What header ensures proper cache separation for compressed content?","answer":"Vary: Accept-Encoding"},{"question":"What is the default Gzip level in most servers?","answer":"Level 6 — good balance of speed and compression."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Gzip</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Browser</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Accept-Encoding</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"225\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CDN Edge</text><text x=\"225\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Check header</text><line x1=\"290\" y1=\"48\" x2=\"320\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"330\" y=\"35\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"400\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Gzip</text><text x=\"400\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Content-Encoding: gzip</text><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pre-compressed</text><text x=\"65\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">.gz at build</text><rect x=\"10\" y=\"100\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">On-the-fly</text><text x=\"65\" y=\"119\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Dynamic content</text><rect x=\"10\" y=\"130\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"65\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Fallback</text><text x=\"65\" y=\"149\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Brotli unsupported</text><line x1=\"120\" y1=\"83\" x2=\"150\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"113\" x2=\"150\" y2=\"113\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"143\" x2=\"150\" y2=\"143\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"70\" width=\"150\" height=\"100\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"235\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Gzip Compression</text><text x=\"235\" y=\"142\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Universal support. 70-80% r</text><text x=\"235\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">eduction. Level 6 default. </text><text x=\"235\" y=\"164\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Pre-compress or CDN edge.</text><text x=\"240\" y=\"200\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Gzip: Universal HTTP compression standard. Support</text><text x=\"240\" y=\"212\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ed by every browser and CDN.</text></svg>","codeExamples":[{"title":"Enabling Gzip in Nginx","useCase":"Server-side Gzip configuration.","code":"http {\n  gzip on;\n  gzip_comp_level 6;\n  gzip_min_length 256;\n  gzip_proxied any;\n  gzip_vary on;\n  gzip_static on;\n  gzip_types text/plain text/css text/xml text/javascript application/javascript application/json image/svg+xml;\n  gzip_disable \"msie6\";\n}","description":"Nginx Gzip configuration with pre-compressed file support."},{"title":"Pre-compressing with Gzip","useCase":"Build-time pre-compression.","code":"gzip -k -9 style.css\n# Creates style.css.gz alongside style.css\n\nfind ./dist -type f \\( -name \"*.html\" -o -name \"*.css\" -o -name \"*.js\" -o -name \"*.json\" -o -name \"*.svg\" \\) -exec gzip -k -9 {} \\;\n\n# Check savings:\nfor f in $(find ./dist -name \"*.html\" | head -5); do\n  orig=$(stat -c%s \"$f\")\n  gz=$(stat -c%s \"${f}.gz\" 2>/dev/null)\n  echo \"$(basename $f): $(( (orig-gz)*100/orig ))% reduction\"\ndone","description":"Pre-compressing static files with Gzip level 9 at build time."},{"title":"Express.js Gzip Middleware","useCase":"Server-side compression for dynamic responses.","code":"const express = require(\"express\");\nconst compression = require(\"compression\");\nconst app = express();\napp.use(compression({\n  level: 6,\n  threshold: 256,\n  filter: (req, res) => {\n    const type = res.getHeader(\"Content-Type\");\n    if (type && !type.match(/text|json|javascript|xml/)) return false;\n    return compression.filter(req, res);\n  },\n}));\napp.get(\"/api/data\", (req, res) => {\n  res.json({ message: \"This will be Gzip compressed\", data: \"x\".repeat(10000) });\n});\napp.listen(3000);","description":"Express.js compression middleware for Gzip compression of dynamic responses."},{"title":"Apache Gzip Configuration (mod_deflate)","useCase":"Apache compression setup.","code":"<IfModule mod_deflate.c>\n  SetOutputFilter DEFLATE\n  AddOutputFilterByType DEFLATE text/html text/plain text/xml text/css text/javascript application/javascript application/json image/svg+xml\n  SetEnvIfNoCase Request_URI \\.(?:gif|jpe?g|png|webp|mp4|zip|gz)$ no-gzip dont-vary\n  Header append Vary Accept-Encoding env=!dont-vary\n</IfModule>","description":"Apache mod_deflate configuration for Gzip compression."},{"title":"Curl Test for Gzip","useCase":"Verify Gzip compression.","code":"# Check if Gzip is enabled\ncurl -I -H \"Accept-Encoding: gzip\" https://cdn.example.com/style.css\n# Look for: Content-Encoding: gzip\n\n# Compare sizes\ncurl -s -o /dev/null -w \"Uncompressed: %{size_download} bytes\\n\" -H \"Accept-Encoding: identity\" https://cdn.example.com/page.html\ncurl -s -o /dev/null -w \"Gzip: %{size_download} bytes\\n\" -H \"Accept-Encoding: gzip\" https://cdn.example.com/page.html","description":"Curl commands to test Gzip compression and compare sizes."}],"mcqQuestions":[{"question":"What is Gzip?","options":["Image format","Compression algorithm based on DEFLATE","CDN provider","JavaScript library"],"answer":1,"explanation":"Gzip is a compression algorithm based on DEFLATE."},{"question":"What is the default Gzip level?","options":["1","6","9","11"],"answer":1,"explanation":"Gzip default is level 6 — good balance of speed and ratio."},{"question":"What Content-Encoding does Gzip use?","options":["br","deflate","gzip","compress"],"answer":2,"explanation":"Gzip uses Content-Encoding: gzip."},{"question":"What is gzip_static?","options":["Dynamic compression","Serves pre-compressed .gz files","Enables Brotli","Caches compressed files"],"answer":1,"explanation":"gzip_static serves pre-compressed .gz files directly."},{"question":"Does every browser support Gzip?","options":["Yes, universal","Only modern","Only Chrome","Only mobile"],"answer":0,"explanation":"Gzip has universal support across all browsers."},{"question":"What should you NOT Gzip?","options":["HTML","CSS","JPEG","JSON"],"answer":2,"explanation":"Already-compressed formats like JPEG should not be Gzipped."}]};
TOPICS_DATA["cdn"]["cdn-http-2"] = {"id":"cdn-http-2","title":"HTTP/2","difficulty":"intermediate","estimatedMinutes":20,"tldr":["HTTP/2 is a major revision of the HTTP protocol that improves performance through multiplexing, header compression, server push, and binary framing.","Key features: multiplexed streams (multiple requests over single TCP connection), HPACK header compression, server push, stream prioritization, and binary protocol.","HTTP/2 eliminates head-of-line blocking (where one slow request blocks others) and reduces connection overhead (from 6+ TCP connections to 1).","CDNs benefit significantly from HTTP/2: multiplexing improves cache fill performance and header compression reduces overhead."],"laymanDefinition":"HTTP/2 is like upgrading from a single-lane road to a multi-lane highway with a carpool lane. HTTP/1.1 forced you to open 6 separate roads to send 6 cars (requests). HTTP/2 is one wide road where all cars travel simultaneously. It compresses the license plates (headers) so each car is smaller.","deepDive":[{"heading":"Binary Framing Layer","text":"HTTP/2 is binary (not text). All communication is broken into frames (HEADERS, DATA, SETTINGS, PRIORITY). Frames from different streams are multiplexed over a single TCP connection. Binary format is more efficient to parse and less error-prone."},{"heading":"Multiplexing and HOL Blocking","text":"HTTP/1.1: one request per connection, 6-8 parallel connections. If one connection is slow, it blocks the queue. HTTP/2: all requests share one TCP connection. If one stream is slow, other streams continue unaffected."},{"heading":"HPACK Header Compression","text":"HTTP/1.1 sends headers as plaintext (800 bytes+ per request). HTTP/2 uses HPACK: static table, dynamic table, and Huffman encoding. Typical reduction: 85-90% header size."},{"heading":"Server Push","text":"Server can proactively send resources before the client requests them. Being deprecated in Chrome. Preload links (<link rel=\"preload\">) are recommended instead."},{"heading":"HTTP/2 and CDNs","text":"All major CDNs support HTTP/2. CDNs terminate HTTP/2 with clients and may use HTTP/1.1 or HTTP/2 to origin. Benefits: improved cache fill, reduced connection overhead, better mobile performance."}],"interviewAnswer":"HTTP/2 improves performance through multiplexing, HPACK header compression, and binary framing. It eliminates HTTP/1.1's head-of-line blocking and reduces connection overhead. All major CDNs support HTTP/2.","interviewQuestions":[{"question":"What is HTTP/2?","answer":"A major HTTP protocol revision with multiplexing, HPACK compression, and binary framing."},{"question":"What is multiplexing?","answer":"Multiple request/response streams over a single TCP connection."},{"question":"What is head-of-line blocking?","answer":"In HTTP/1.1, one slow request on a connection blocks subsequent requests on that connection."},{"question":"What is HPACK?","answer":"HTTP/2 header compression — reduces header size by 85-90%."},{"question":"What is server push?","answer":"Server proactively sends resources before the client requests them. Being deprecated."},{"question":"How does HTTP/2 improve CDN performance?","answer":"Multiplexing speeds up cache fill, reduces connection overhead."},{"question":"Is HTTP/2 binary or text?","answer":"Binary — all frames are binary, more efficient to parse."},{"question":"How many TCP connections does HTTP/2 use?","answer":"One connection per origin (vs 6-8 in HTTP/1.1)."},{"question":"Did HTTP/2 change HTTP semantics?","answer":"No — methods, status codes, headers, and URLs remain the same."},{"question":"What is ALPN?","answer":"TLS extension that negotiates HTTP/2 during the TLS handshake."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">HTTP/2</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">HTTP/1.1</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">6 connections</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">HTTP/2</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">1 connection</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"320\" height=\"55\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"320\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">HTTP/2 Benefits</text><text x=\"320\" y=\"73\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Multiplexing: single TCP connection. HPACK: 85-90% header </text><text x=\"320\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">compression. Binary framing.</text><rect x=\"160\" y=\"100\" width=\"120\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"220\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Multiplexing</text><text x=\"220\" y=\"119\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">No HOL blocking</text><rect x=\"160\" y=\"130\" width=\"120\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"220\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">HPACK</text><text x=\"220\" y=\"149\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Header compression</text><rect x=\"160\" y=\"160\" width=\"120\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"220\" y=\"176\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Server Push</text><text x=\"220\" y=\"179\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Proactive push</text><text x=\"240\" y=\"210\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">HTTP/2: Multiplexing, HPACK, binary framing. Singl</text><text x=\"240\" y=\"222\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">e TCP connection per origin.</text></svg>","codeExamples":[{"title":"HTTP/2 Server Configuration (Nginx)","useCase":"Enabling HTTP/2 on Nginx.","code":"server {\n  listen 443 ssl http2;\n  server_name cdn.example.com;\n  ssl_certificate /etc/ssl/certs/example.pem;\n  ssl_certificate_key /etc/ssl/private/example.key;\n  ssl_protocols TLSv1.2 TLSv1.3;\n  ssl_ciphers ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256;\n  ssl_prefer_server_ciphers on;\n  add_header Strict-Transport-Security \"max-age=63072000\" always;\n  location / { root /var/www; }\n}","description":"Nginx HTTP/2 configuration with SSL/TLS requirements."},{"title":"Verifying HTTP/2 with Curl","useCase":"Check HTTP version.","code":"curl -s -I --http2 https://cdn.example.com/\n# HTTP/2 200\n\ncurl -s -I --http1.1 https://cdn.example.com/\n# HTTP/1.1 200 OK\n\necho \"=== HTTP/2 ===\"\ncurl -w \"Connect: %{time_connect}s TTFB: %{time_starttransfer}s Total: %{time_total}s\\n\" -o /dev/null -s --http2 https://cdn.example.com/\necho \"=== HTTP/1.1 ===\"\ncurl -w \"Connect: %{time_connect}s TTFB: %{time_starttransfer}s Total: %{time_total}s\\n\" -o /dev/null -s --http1.1 https://cdn.example.com/","description":"Curl commands to verify HTTP/2 support and compare performance."},{"title":"CloudFront HTTP/2 Configuration","useCase":"Enabling HTTP/2 on CloudFront.","code":"aws cloudfront get-distribution --id E123456789ABCD --query \"Distribution.DistributionConfig.HttpVersion\"\n# Should be \"http2\" or \"http2and3\"\n\naws cloudfront update-distribution --id E123456789ABCD --http-version http2\n# CloudFront HTTP/2 is enabled by default for new distributions","description":"AWS CLI commands to check and configure HTTP/2 support on CloudFront."},{"title":"HTTP/2 Multiplexing Visualization","useCase":"Performance comparison.","code":"# HTTP/1.1: 100 requests across 6 connections\n# Connection 1: req1 -> req2 -> req3 ... (blocking)\n# Connection 2: req1 -> req2 -> req3 ... (blocking)\n# ... up to 6 connections total\n\n# HTTP/2: 100 requests over 1 connection\n# |--- req1 ---|\n# |--- req2 ---|  (all in parallel)\n# |--- req3 ---|\n# Single TCP connection, multiplexed streams","description":"Visual comparison of HTTP/1.1 vs HTTP/2 request handling."},{"title":"HTTP/2 Connection Coalescing","useCase":"Multiple domains sharing one connection.","code":"# When cdn.example.com and static.example.com\n# resolve to the same CDN edge IP, the browser\n# can reuse the same HTTP/2 connection for both.\n\n# SSL certificate must cover both hostnames:\n# Subject: *.example.com\n\n# Reduces connection overhead by 50-80%","description":"HTTP/2 connection coalescing allows multiple domains to share one CDN connection."}],"mcqQuestions":[{"question":"What is the key advantage of HTTP/2?","options":["Encryption by default","Multiplexing over single connection","New status codes","Larger bodies"],"answer":1,"explanation":"HTTP/2 multiplexes multiple streams over a single TCP connection."},{"question":"What is HPACK?","options":["HTTP/2 header compression","Hardware packet accelerator","HTTP toolkit","Protocol for API calls"],"answer":0,"explanation":"HPACK compresses HTTP/2 headers by 85-90%."},{"question":"How many TCP connections does HTTP/2 use?","options":["6","8","1","2"],"answer":2,"explanation":"HTTP/2 uses one TCP connection per origin."},{"question":"What problem does multiplexing solve?","options":["Slow server response","Head-of-line blocking","DNS delay","SSL overhead"],"answer":1,"explanation":"Multiplexing eliminates head-of-line blocking."},{"question":"Is HTTP/2 binary or text?","options":["Text","Binary","Both","XML"],"answer":1,"explanation":"HTTP/2 uses a binary framing layer."},{"question":"What is ALPN?","options":["TLS extension for HTTP/2 negotiation","Compression algorithm","Cache invalidation","Load balancing"],"answer":0,"explanation":"ALPN negotiates HTTP/2 during the TLS handshake."}]};
TOPICS_DATA["cdn"]["cdn-http-3"] = {"id":"cdn-http-3","title":"HTTP/3","difficulty":"advanced","estimatedMinutes":20,"tldr":["HTTP/3 is the latest HTTP protocol version, built on QUIC (Quick UDP Internet Connections) instead of TCP, offering significant performance improvements.","Key improvements: zero-RTT connection establishment, no head-of-line blocking at transport layer, built-in encryption, connection migration, and improved loss recovery.","Unlike HTTP/2 (TCP-based), HTTP/3 runs over QUIC (UDP-based), eliminating TCP head-of-line blocking where a lost packet blocks ALL streams.","HTTP/3 is particularly beneficial for mobile users (connection migration) and high-latency or lossy connections."],"laymanDefinition":"HTTP/3 is like upgrading from a train (TCP) to independent drones (QUIC/UDP). With the train, if one track is blocked (lost packet), the entire train stops. With drones, each package flies independently. If one drone is delayed, the others keep going. Drones already know your address (0-RTT) and can switch bases if you move (connection migration).","deepDive":[{"heading":"QUIC Protocol (Foundation)","text":"QUIC is a transport protocol on UDP. It integrates TLS 1.3 directly, provides stream multiplexing without HOL blocking, includes forward error correction, and has built-in connection migration. Standardized as RFC 9000."},{"heading":"0-RTT Connection Establishment","text":"HTTP/3 can send data on the first packet (0-RTT) for returning clients. Client remembers previous connection parameters. Reconnects without a handshake. HTTP/1.1: 3 round trips. HTTP/3: 0 for returning visitors."},{"heading":"No Transport-Level HOL Blocking","text":"HTTP/2 solved HTTP-level HOL blocking but has TCP-level HOL blocking. A lost TCP packet blocks ALL HTTP/2 streams. QUIC isolates streams — a lost packet only affects its stream. For 2-5% packet loss, HTTP/3 can be 15-30% faster."},{"heading":"Connection Migration","text":"When a mobile user switches from WiFi to cellular, TCP connections must be re-established. QUIC uses a Connection ID — when IP changes, the connection survives. Transformative for mobile users."},{"heading":"HTTP/3 Adoption and CDN Support","text":"All major CDNs support HTTP/3: CloudFront, Cloudflare (enabled by default), Fastly, Akamai. All modern browsers support HTTP/3. ~30-40% of web traffic uses HTTP/3 as of 2025."}],"interviewAnswer":"HTTP/3 (QUIC over UDP) eliminates transport-layer HOL blocking, enables 0-RTT connection reuse, and supports connection migration. It is a significant evolution over HTTP/2, especially for lossy networks and mobile connections.","interviewQuestions":[{"question":"What is HTTP/3?","answer":"The latest HTTP protocol built on QUIC (UDP) instead of TCP, with 0-RTT, no HOL blocking, and connection migration."},{"question":"What is QUIC?","answer":"Quick UDP Internet Connections — a transport protocol standardized as RFC 9000."},{"question":"What is 0-RTT?","answer":"Zero Round Trip Time — returning clients send data immediately without a handshake."},{"question":"How does HTTP/3 eliminate HOL blocking?","answer":"QUIC isolates streams so a lost packet only affects one stream, not all."},{"question":"What is connection migration?","answer":"QUIC connections survive IP changes (WiFi to cellular) using a Connection ID."},{"question":"What protocol does QUIC use instead of TCP?","answer":"UDP (User Datagram Protocol)."},{"question":"Is encryption mandatory in HTTP/3?","answer":"Yes, TLS 1.3 is integrated into QUIC, making encryption mandatory."},{"question":"What makes HTTP/3 better for mobile?","answer":"Connection migration allows seamless WiFi to cellular switching."},{"question":"Which major CDNs support HTTP/3?","answer":"CloudFront, Cloudflare, Fastly, Akamai all support HTTP/3."},{"question":"What header advertises HTTP/3 support?","answer":"Alt-Svc: h3=\":443\"; ma=86400"}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">HTTP/3</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">HTTP/1.1</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">TCP, 3 RTT</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">HTTP/2</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">TCP, 2 RTT</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">HTTP/3</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">QUIC/UDP, 0-1 RTT</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"320\" height=\"95\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"320\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">HTTP/3 Evolution</text><text x=\"320\" y=\"113\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">TCP -> QUIC/UDP. 0-RTT, no HOL blocking, connection migrat</text><text x=\"320\" y=\"124\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ion, built-in TLS 1.3.</text><rect x=\"160\" y=\"140\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"230\" y=\"156\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Mobile</text><text x=\"230\" y=\"159\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Seamless network switch</text><rect x=\"160\" y=\"165\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"230\" y=\"181\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Lossy Networks</text><text x=\"230\" y=\"184\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">30% faster with loss</text><text x=\"240\" y=\"210\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">HTTP/3: QUIC/UDP. 0-RTT, no HOL blocking, connecti</text><text x=\"240\" y=\"222\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">on migration, mandatory encryption.</text></svg>","codeExamples":[{"title":"Enabling HTTP/3 on CloudFront","useCase":"CloudFront HTTP/3 configuration.","code":"# Via AWS Management Console:\n# Distribution -> Edit -> Supported HTTP Versions\n# Select \"HTTP/2 and HTTP/3\"\n\n# Via AWS CLI:\naws cloudfront update-distribution \\\n  --id E123456789ABCD \\\n  --http-version http2and3 \\\n  --if-match \"ETAG_VALUE\"\n\n# Requirements:\n# - HTTPS only (viewer protocol)\n# - TLSv1.2 or TLSv1.3\n\n# Verify with curl:\ncurl -s -I --http3 https://d123.cloudfront.net/","description":"AWS CLI and console configuration for enabling HTTP/3 on CloudFront."},{"title":"Cloudflare HTTP/3 Enablement","useCase":"HTTP/3 is enabled by default.","code":"# Cloudflare HTTP/3 is enabled by default for all plans\n\n# Verify via Dashboard:\n# Network tab -> HTTP/3 (with QUIC) -> On\n\n# Verify via API:\ncurl -X GET \"https://api.cloudflare.com/client/v4/zones/$ZONE_ID/settings/http3\" \\\n  -H \"Authorization: Bearer $TOKEN\"\n\n# Response should show \"value\": \"on\"","description":"Cloudflare HTTP/3 configuration — enabled by default."},{"title":"Nginx HTTP/3 Configuration","useCase":"Enabling HTTP/3 on Nginx.","code":"server {\n  listen 443 quic reuseport;\n  listen 443 ssl http2;\n  server_name cdn.example.com;\n  ssl_certificate /etc/ssl/certs/example.pem;\n  ssl_certificate_key /etc/ssl/private/example.key;\n  ssl_protocols TLSv1.2 TLSv1.3;\n  ssl_early_data on;\n  add_header Alt-Svc 'h3=\":443\"; ma=86400';\n  quic_retry on;\n  location / { root /var/www/static; }\n}","description":"Nginx HTTP/3 (QUIC) configuration with HTTP/2 fallback."},{"title":"Verify HTTP/3 with Curl","useCase":"Testing HTTP/3 support.","code":"# Requires curl built with quiche/HTTP/3 support\ncurl -s -I --http3 https://cdn.example.com/\n# Response: HTTP/3 200\n\necho \"=== HTTP/3 ===\"\ncurl -w \"\\nConnect: %{time_connect}s\\nTTFB: %{time_starttransfer}s\\nTotal: %{time_total}s\\n\" -o /dev/null -s --http3 https://cdn.example.com/\necho \"=== HTTP/2 ===\"\ncurl -w \"\\nConnect: %{time_connect}s\\nTTFB: %{time_starttransfer}s\\nTotal: %{time_total}s\\n\" -o /dev/null -s --http2 https://cdn.example.com/","description":"Curl commands with HTTP/3 to compare connection times."},{"title":"HTTP/3 Alt-Svc Header","useCase":"How servers advertise HTTP/3.","code":"# Server sends Alt-Svc header to advertise HTTP/3:\nAlt-Svc: h3=\":443\"; ma=86400\n\n# h3 = HTTP/3 over QUIC\n# :443 = UDP port 443\n# ma=86400 = cache for 24 hours\n\n# Browser then attempts QUIC connection\n# Falls back to TCP if QUIC fails\n# Future requests use HTTP/3 directly","description":"The Alt-Svc header mechanism for HTTP/3 discovery and upgrade."}],"mcqQuestions":[{"question":"What transport does HTTP/3 use?","options":["TCP","UDP (via QUIC)","SCTP","WebSocket"],"answer":1,"explanation":"HTTP/3 uses QUIC over UDP."},{"question":"What is 0-RTT?","options":["Zero data","Faster setup","Zero round trips for returning clients","No encryption"],"answer":2,"explanation":"0-RTT allows returning clients to send data immediately."},{"question":"What does HTTP/3 fix that HTTP/2 still has?","options":["Slow responses","TCP HOL blocking","Large headers","No encryption"],"answer":1,"explanation":"HTTP/2 has TCP-level HOL blocking; HTTP/3 eliminates it."},{"question":"What is connection migration?","options":["Server migration","Connection survives IP changes","Content migration","User migration"],"answer":1,"explanation":"QUIC connections survive IP changes via Connection ID."},{"question":"Is encryption mandatory in HTTP/3?","options":["No","Yes, TLS 1.3 built-in","Only for POST","Optional"],"answer":1,"explanation":"TLS 1.3 is integrated into QUIC."},{"question":"What header advertises HTTP/3?","options":["Cache-Control","Alt-Svc","Content-Type","Accept-Encoding"],"answer":1,"explanation":"Alt-Svc: h3=\":443\"; ma=86400 advertises HTTP/3."}]};
TOPICS_DATA["cdn"]["cdn-security"] = {"id":"cdn-security","title":"CDN Security","difficulty":"intermediate","estimatedMinutes":20,"tldr":["CDN security encompasses DDoS mitigation, WAF, SSL/TLS, bot management, and access control features provided at the edge.","CDNs act as a security shield by sitting between users and the origin, absorbing attacks and filtering malicious traffic.","Key features: DDoS protection, Web Application Firewall (SQLi, XSS), SSL/TLS termination, geo-blocking, rate limiting, and bot detection.","CDN security is defense in depth — multiple layers protect against different attack vectors simultaneously."],"laymanDefinition":"CDN security is like having a private security team at your building entrance instead of just a lock on your apartment door. The team checks everyone coming in, stops known troublemakers (DDoS), checks for weapons (WAF), and only lets appropriate people through to your door.","deepDive":[{"heading":"DDoS Protection","text":"CDNs absorb volumetric DDoS attacks across thousands of servers. Layer 3/4 attacks: absorbed by network infrastructure. Layer 7 attacks: detected via rate limiting, behavioral analysis, and challenges. Cloudflare can absorb 2+ Tbps attacks."},{"heading":"Web Application Firewall (WAF)","text":"CDN WAF inspects HTTP requests for SQL injection, XSS, path traversal, command injection. Managed rule sets (OWASP Top 10). Custom rules for application-specific threats. Logging and alerting for blocked requests."},{"heading":"SSL/TLS Termination at Edge","text":"CDN terminates TLS from users, decrypts, re-encrypts to origin. Offloads CPU from origin. Supports modern TLS versions (1.3). Manages certificates centrally. Full end-to-end encryption available."},{"heading":"Bot Management","text":"CDNs distinguish legitimate users from bots via JS challenges, CAPTCHA, behavioral analysis, IP reputation, and browser fingerprinting. Googlebot allowed through. Suspicious traffic challenged or blocked."},{"heading":"Access Control Features","text":"Geo-blocking: block traffic by country. IP whitelisting/blacklisting. Signed URLs/cookies for time-limited access. Token authentication. HTTP basic auth at edge. All enforced before origin."}],"interviewAnswer":"CDN security provides defense in depth: DDoS absorption, WAF, SSL/TLS termination, bot management, and access control. The CDN shields the origin by filtering malicious traffic at the edge.","interviewQuestions":[{"question":"What security features do CDNs provide?","answer":"DDoS mitigation, WAF, SSL/TLS, bot management, geo-blocking, rate limiting, signed URLs."},{"question":"How does a CDN protect against DDoS?","answer":"By absorbing attack traffic across its globally distributed infrastructure."},{"question":"What is a CDN WAF?","answer":"A Web Application Firewall that inspects HTTP requests for malicious patterns."},{"question":"How does SSL termination work at CDN?","answer":"CDN terminates TLS from users, decrypts, re-encrypts when forwarding to origin."},{"question":"What is geo-blocking?","answer":"Blocking or allowing traffic from specific geographic regions at the CDN edge."},{"question":"What are signed URLs?","answer":"Time-limited URLs with cryptographic signatures for temporary content access."},{"question":"How do CDNs handle bot management?","answer":"JS challenges, CAPTCHA, behavioral analysis, IP reputation, rate limiting."},{"question":"What is rate limiting?","answer":"Restricting requests from an IP/path/region within a time window."},{"question":"Can a CDN prevent SQL injection?","answer":"Yes, through WAF rules inspecting request bodies and parameters."},{"question":"What is origin cloaking?","answer":"Hiding the origin server IP so attackers cannot directly target it."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">CDN Security</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Layer 3/4</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">DDoS</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Layer 7</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">WAF, rate limit</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SSL/TLS</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Edge termination</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Bot Mgmt</text><text x=\"65\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Challenges</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Access Ctrl</text><text x=\"65\" y=\"163\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Geo-block, signed UR</text><text x=\"65\" y=\"174\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Ls</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"220\" height=\"155\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"270\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CDN Security Shield</text><text x=\"270\" y=\"173\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Defense in depth at the edge: DDoS, WAF,</text><text x=\"270\" y=\"184\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\"> SSL, bot management, access control.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">CDN Security: DDoS, WAF, SSL/TLS, bot management, </text><text x=\"240\" y=\"232\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">geo-blocking, signed URLs.</text></svg>","codeExamples":[{"title":"CloudFront Security Headers via Lambda@Edge","useCase":"Adding security headers.","code":"exports.handler = async (event) => {\n  const response = event.Records[0].cf.response;\n  const headers = response.headers;\n  headers[\"strict-transport-security\"] = [{ key: \"Strict-Transport-Security\", value: \"max-age=63072000; includeSubdomains; preload\" }];\n  headers[\"x-content-type-options\"] = [{ key: \"X-Content-Type-Options\", value: \"nosniff\" }];\n  headers[\"x-frame-options\"] = [{ key: \"X-Frame-Options\", value: \"DENY\" }];\n  headers[\"x-xss-protection\"] = [{ key: \"X-XSS-Protection\", value: \"1; mode=block\" }];\n  headers[\"referrer-policy\"] = [{ key: \"Referrer-Policy\", value: \"strict-origin-when-cross-origin\" }];\n  return response;\n};","description":"Lambda@Edge adding security headers to all CDN responses."},{"title":"Cloudflare WAF Custom Rule","useCase":"Creating WAF rules.","code":"# Block SQL injection via API:\ncurl -X POST \"https://api.cloudflare.com/client/v4/zones/$ZONE_ID/rulesets/$RULESET_ID/rules\" \\\n  -H \"Authorization: Bearer $TOKEN\" \\\n  -H \"Content-Type: application/json\" \\\n  -d '{\"action\": \"block\", \"expression\": \"(lower(http.request.uri.path) contains \\\"select\\\")\", \"description\": \"Block SQLi\", \"enabled\": true}'\n\n# Rate limiting login:\ncurl -X POST \"https://api.cloudflare.com/client/v4/zones/$ZONE_ID/rate_limits\" \\\n  -H \"Authorization: Bearer $TOKEN\" \\\n  -H \"Content-Type: application/json\" \\\n  -d '{\"threshold\": 5, \"period\": 60, \"action\": \"block\", \"match\": {\"request\": {\"url\": \"https://example.com/login\"}}}'","description":"Cloudflare WAF and rate limiting rules via API."},{"title":"Fastly VCL Security (Rate Limiting)","useCase":"Edge security with VCL.","code":"sub vcl_recv {\n  if (ratecounter.rate_limit_count(req.url.path, \"1 minute\", 30) > 30) {\n    error 429 \"Rate limit exceeded\";\n  }\n  if (req.http.Fastly-Geo-Country == \"XX\") {\n    error 403 \"Region blocked\";\n  }\n}\nsub vcl_error {\n  if (obj.status == 429) {\n    set obj.status = 429;\n    set obj.response = \"Too Many Requests\";\n    set obj.http.Retry-After = \"60\";\n    return (deliver);\n  }\n}","description":"Fastly VCL for rate limiting and geo-blocking at the edge."},{"title":"SSL/TLS Configuration (CloudFront)","useCase":"End-to-end encryption.","code":"# Viewer protocol: redirect HTTP to HTTPS\naws cloudfront update-distribution --id E123456789ABCD --default-cache-behavior \"ViewerProtocolPolicy=redirect-to-https\"\n\n# Origin protocol: HTTPS only\naws cloudfront update-distribution --id E123456789ABCD --origins \"DomainName=origin.example.com,Id=myOrigin,OriginProtocolPolicy=https-only\"\n\n# Minimum TLS version: TLSv1.2_2021\n# Custom SSL via ACM\naws acm import-certificate --certificate file://cert.pem --private-key file://key.pem","description":"CloudFront SSL/TLS configuration for end-to-end encryption."},{"title":"Signed URL with CloudFront","useCase":"Protecting content with signed URLs.","code":"const crypto = require(\"crypto\");\nconst expiration = Math.floor(Date.now() / 1000) + 3600;\nconst policy = JSON.stringify({\n  Statement: [{\n    Resource: \"https://d123.cloudfront.net/private/*\",\n    Condition: { DateLessThan: { \"AWS:EpochTime\": expiration } }\n  }]\n});\nconst signature = crypto.createSign(\"RSA-SHA1\").update(policy).sign(privateKey, \"base64\");\nconst signedUrl = `https://d123.cloudfront.net/private/file.pdf?Expires=${expiration}&Signature=${encodeURIComponent(signature)}&Key-Pair-Id=${keyPairId}`;","description":"CloudFront signed URL generation for private content access."}],"mcqQuestions":[{"question":"What is the primary DDoS protection mechanism of CDNs?","options":["Blocking all traffic","Absorbing attacks across distributed infrastructure","Rate limiting only","Server shutdown"],"answer":1,"explanation":"CDNs absorb DDoS attacks across their globally distributed network."},{"question":"What does a CDN WAF protect against?","options":["DDoS only","SQL injection, XSS, and other web attacks","DNS attacks","Physical attacks"],"answer":1,"explanation":"WAF protects against web application attacks like SQLi and XSS."},{"question":"What is origin cloaking?","options":["Hiding origin IP","Encrypting origin data","Backing up origin","Load balancing"],"answer":0,"explanation":"Origin cloaking hides the origin server IP from attackers."},{"question":"What are signed URLs used for?","options":["Public content","Time-limited access to protected content","DDoS mitigation","SSL termination"],"answer":1,"explanation":"Signed URLs provide time-limited access to protected content."},{"question":"What is geo-blocking?","options":["Blocking all traffic","Blocking traffic by geographic region","Geographic routing","Location analytics"],"answer":1,"explanation":"Geo-blocking restricts traffic based on geographic region."},{"question":"What is defense in depth?","options":["Single security layer","Multiple security layers","Deep encryption","Physical security"],"answer":1,"explanation":"CDN security uses multiple layers (DDoS, WAF, SSL, bot mgmt) for defense in depth."}]};
TOPICS_DATA["cdn"]["cdn-geo-routing"] = {"id":"cdn-geo-routing","title":"Geo Routing","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Geo routing directs user requests to the nearest CDN edge server based on geographic location, minimizing latency.","Methods: DNS-based routing (geo DNS returns IP of nearest PoP) and Anycast routing (multiple PoPs share IP, BGP routes to nearest).","Geo routing considers: geographic distance, server load, network conditions, cache availability, and origin health.","Advanced geo routing uses real-time internet weather data to dynamically route around congestion and outages."],"laymanDefinition":"Geo routing is like a GPS navigation system that directs you to the nearest gas station instead of one across town. When you need directions, the system checks where you are, finds all nearby stations, considers traffic (server load), and sends you to the best one. If one station is crowded, it routes you to the next closest.","deepDive":[{"heading":"DNS-Based Geo Routing","text":"DNS server returns different IP addresses based on the client\\'s resolver location. Uses GeoIP databases to map IPs to regions. Simple to implement. Updates can be slow (DNS TTL). Less precise than Anycast. Used by: Akamai, Azure CDN, legacy CDNs."},{"heading":"Anycast Routing","text":"Multiple edge servers share the same IP address. BGP (Border Gateway Protocol) automatically routes traffic to the nearest server announcing that IP. Fast failover (if one PoP goes down, BGP converges to next nearest). More precise and resilient. Used by: Cloudflare, Fastly, CloudFront."},{"heading":"Geo Routing Factors","text":"Latency: primary metric (measured via RTT). Server load: avoid overloaded edge servers. Cache availability: prefer edge with cached content. Origin health: route around unhealthy origins. Network conditions: avoid congested paths. Cost: some routes may be cheaper. Custom rules: route specific content to specific regions."},{"heading":"Real-Time Traffic Steering","text":"Advanced CDNs use real-time monitoring to detect network congestion, packet loss, and latency spikes. Traffic is dynamically rerouted to avoid problem areas. Fastly uses real-time data to steer traffic around internet weather events. Cloudflare Argo Smart Routing optimizes paths in real-time."},{"heading":"Geo Routing for Origin Traffic","text":"CDNs can also route requests to the nearest origin server (multi-region origins). User in Europe -> nearest European edge -> nearest European origin. Requires origin servers in multiple regions. Benefits: lower latency for dynamic cache misses, compliance (data sovereignty)."}],"interviewAnswer":"Geo routing directs users to the nearest CDN edge server using DNS-based or Anycast routing. Anycast is preferred for its precision and fast failover. Advanced routing considers server load, cache state, and real-time network conditions. Multi-region origin routing further reduces latency for dynamic content.","interviewQuestions":[{"question":"What is geo routing?","answer":"Directing user requests to the nearest CDN edge server based on geographic location."},{"question":"What are the two main geo routing methods?","answer":"DNS-based routing (geo DNS) and Anycast routing (shared IP with BGP)."},{"question":"How does DNS-based geo routing work?","answer":"DNS returns different IP addresses based on the client resolver\\'s geographic location."},{"question":"How does Anycast routing work?","answer":"Multiple PoPs share the same IP address; BGP routes traffic to the nearest one."},{"question":"What is the advantage of Anycast over DNS routing?","answer":"Faster failover, more precise routing, and automatic load distribution."},{"question":"What factors does geo routing consider?","answer":"Latency, server load, cache availability, origin health, and network conditions."},{"question":"What is traffic steering?","answer":"Dynamically routing traffic based on real-time network conditions and performance data."},{"question":"What is multi-region origin routing?","answer":"Routing requests to the nearest origin server for lower latency on cache misses."},{"question":"Which CDNs use Anycast routing?","answer":"Cloudflare, Fastly, and CloudFront use Anycast for edge routing."},{"question":"What is Argo Smart Routing?","answer":"Cloudflare\\'s real-time traffic optimization that finds faster paths across the internet."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Geo Routing</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">User in EU</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Requests content</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">User in US</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Requests content</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">User in Asia</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Requests content</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"310\" height=\"100\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"315\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Geo Routing (Anycast + DNS)</text><text x=\"315\" y=\"118\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Routes each user to nearest edge PoP based on location, </text><text x=\"315\" y=\"129\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">load, cache, and network health.</text><rect x=\"10\" y=\"140\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"156\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Factors</text><text x=\"65\" y=\"159\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Latency, load, cache</text><rect x=\"160\" y=\"140\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"230\" y=\"156\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Anycast</text><text x=\"230\" y=\"159\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Shared IP, BGP routed</text><rect x=\"160\" y=\"170\" width=\"140\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"230\" y=\"186\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DNS Geo</text><text x=\"230\" y=\"189\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Region-based IP</text><text x=\"240\" y=\"210\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Geo Routing: Directing users to nearest CDN edge v</text><text x=\"240\" y=\"222\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ia Anycast or DNS-based geo routing for lowest lat</text><text x=\"240\" y=\"234\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ency.</text></svg>","codeExamples":[{"title":"Anycast Routing with BGP","useCase":"How Anycast distributes traffic.","code":"# Multiple edge PoPs announce the same IP block\n# via BGP to the internet routing table.\n\n# PoP1 (New York):\n#   router bgp 65001\n#   network 203.0.113.0/24\n\n# PoP2 (London):\n#   router bgp 65002\n#   network 203.0.113.0/24\n\n# When a user in NY resolves cdn.example.com,\n# traffic goes to PoP1 (closest BGP announcement).\n# If PoP1 goes down, BGP converges to PoP2.\n# Converge time: typically <30 seconds.","description":"BGP configuration for Anycast routing across multiple edge PoPs."},{"title":"CloudFront Geo Restriction","useCase":"Geographic access control.","code":"# CloudFront geo restriction (whitelist/blacklist)\n\n# Whitelist: only allow these countries\naws cloudfront update-distribution \\\n  --id E123456789ABCD \\\n  --geo-restriction \\\n    \"RestrictionType=whitelist,Locations=[US,CA,GB]\"\n\n# Blacklist: block these countries\naws cloudfront update-distribution \\\n  --id E123456789ABCD \\\n  --geo-restriction \\\n    \"RestrictionType=blacklist,Locations=[XX]\"\n\n# Geo restriction uses MaxMind GeoIP database\n# Applied at edge locations before content is served","description":"CloudFront geo restriction for allowing or blocking countries."},{"title":"Fastly Geo-Based VCL Routing","useCase":"Geo routing with Fastly VCL.","code":"backend us_origin { .host = \"us-origin.example.com\"; }\nbackend eu_origin { .host = \"eu-origin.example.com\"; }\nbackend asia_origin { .host = \"asia-origin.example.com\"; }\n\nsub vcl_recv {\n  if (req.http.Fastly-Geo-Country ~ \"(US|CA|MX)\") {\n    set req.backend = us_origin;\n  } else if (req.http.Fastly-Geo-Country ~ \"(GB|DE|FR|NL|IT|ES)\") {\n    set req.backend = eu_origin;\n  } else if (req.http.Fastly-Geo-Country ~ \"(JP|KR|SG|AU|NZ)\") {\n    set req.backend = asia_origin;\n  } else {\n    set req.backend = us_origin;\n  }\n}","description":"Fastly VCL geo-routing requests to the nearest origin backend."},{"title":"Cloudflare Argo Smart Routing","useCase":"Real-time traffic optimization.","code":"# Cloudflare Argo Smart Routing:\n# - Learns optimal paths across the internet\n# - Avoids congested routes in real-time\n# - Typically 30% faster on average\n# - Enabled via Dashboard: Speed -> Optimization -> Argo\n\n# How it works:\n# 1. Cloudflare edge nodes share latency data\n# 2. Argo builds a real-time internet map\n# 3. Traffic is routed through optimal intermediary nodes\n# 4. Paths adapt to changing network conditions\n\n# Benefits:\n# - Lower latency for uncached content\n# - Better performance for dynamic requests\n# - Automatic failover around outages","description":"Cloudflare Argo Smart Routing for real-time traffic optimization."},{"title":"Multi-Region Origin with Route53","useCase":"DNS-based origin geo routing.","code":"# AWS Route 53 geo routing policy for origins\n\n# Create latency-based routing to multiple origins:\n# Record: origin.example.com\n# Type: A - Latency routing\n\n# Region: us-east-1\n#   Value: 203.0.113.10 (us-origin)\n#   Region: us-east-1\n\n# Region: eu-west-1\n#   Value: 203.0.113.20 (eu-origin)\n#   Region: eu-west-1\n\n# Region: ap-southeast-1\n#   Value: 203.0.113.30 (asia-origin)\n#   Region: ap-southeast-1\n\n# CloudFront origins: point to Route53 alias\n# Users resolve to nearest origin via latency routing","description":"Route 53 latency-based routing for multi-region origin deployment."}],"mcqQuestions":[{"question":"What are the two main geo routing methods?","options":["DNS-based and Anycast","HTTP and HTTPS","TCP and UDP","IPv4 and IPv6"],"answer":0,"explanation":"The two main methods are DNS-based geo routing and Anycast routing."},{"question":"How does Anycast routing work?","options":["Different IP per PoP","Multiple PoPs share one IP, BGP routes to nearest","DNS returns different IPs","HTTP redirects"],"answer":1,"explanation":"Anycast shares one IP across multiple PoPs; BGP routes to the nearest."},{"question":"What is the advantage of Anycast over DNS routing?","options":["Slower updates","Faster failover and more precise","More complex","Less reliable"],"answer":1,"explanation":"Anycast provides faster failover and more precise routing than DNS-based."},{"question":"What is Argo Smart Routing?","options":["Cloudflare DNS service","Real-time traffic path optimization","CDN caching product","Compression algorithm"],"answer":1,"explanation":"Argo Smart Routing optimizes traffic paths in real-time."},{"question":"What factors affect geo routing decisions?","options":["Only distance","Latency, load, cache, network health","Only server load","Only cache availability"],"answer":1,"explanation":"Geo routing considers latency, server load, cache state, and network health."},{"question":"What is multi-region origin routing?","options":["Multiple CDN providers","Routing to nearest origin server","Multiple DNS providers","Multiple SSL certificates"],"answer":1,"explanation":"Multi-region origin routes to the nearest origin server for lower latency."}]};
TOPICS_DATA["cdn"]["cdn-geo-blocking"] = {"id":"cdn-geo-blocking","title":"Geo Blocking","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Geo blocking restricts content access based on the user's geographic location. Used for licensing compliance, regional content restrictions, and security.","CDNs implement geo blocking at the edge, rejecting requests from blocked regions before they reach the origin, reducing origin load and attack surface.","Implementation: GeoIP database lookup at the edge, comparison against allow/deny lists, and appropriate HTTP response (403, redirect, or custom block page).","Accuracy and limitations: GeoIP databases are ~99% accurate at country level but less precise for cities. VPNs/proxies can bypass geo blocking."],"laymanDefinition":"Geo blocking is like a bouncer at a club that checks your ID to see if you're from a allowed region. If your ID shows a blocked country, you're turned away at the door before you even enter. The bouncer (CDN edge) doesn't even bother telling the DJ (origin) about you.","deepDive":[{"heading":"GeoIP Database and Accuracy","text":"CDNs use GeoIP databases (MaxMind, IP2Location) to map IP addresses to countries. Country-level accuracy: ~99%. City-level: ~80-90%. Databases updated monthly. Some CDNs (Cloudflare) have their own proprietary GeoIP data. VPN/Proxy detection can identify evaders."},{"heading":"Whitelist vs Blacklist Approach","text":"Whitelist: only allow traffic from specific countries (strictest, best for security). Blacklist: block specific countries while allowing all others (common for licensing). Global allow with country exceptions: most flexible but requires careful rule ordering."},{"heading":"Edge Implementation","text":"Geo blocking happens at CDN edge before origin. No origin load from blocked requests. Low latency (checked locally at edge). HTTP response customization: 403 Forbidden, redirect to different page, custom block page, or captcha challenge."},{"heading":"Use Cases","text":"Licensing compliance: media/streaming rights by region. Regulatory compliance: GDPR (EU data stay in EU), data sovereignty laws. Security: block high-threat regions. Content localization: serve different content per region. Pricing: region-specific pricing for digital goods."},{"heading":"Bypass Techniques and Mitigations","text":"VPNs, proxies, and Tor can bypass geo blocking. CDNs detect known VPN/proxy IPs. Threat intelligence feeds flag suspicious proxies. Challenge unsupported IPs with captcha. Combine geo blocking with other security measures (rate limiting, WAF)."}],"interviewAnswer":"Geo blocking restricts content access by geographic region at the CDN edge. It uses GeoIP databases, supports whitelist/blacklist, and can be bypassed by VPNs. CDNs can detect and block many proxies to improve effectiveness.","interviewQuestions":[{"question":"What is geo blocking?","answer":"Restricting content access based on the user\\'s geographic location."},{"question":"How does a CDN implement geo blocking?","answer":"GeoIP database lookup at edge, comparing against allow/deny lists."},{"question":"What HTTP status does geo blocking typically return?","answer":"403 Forbidden (can be customized to redirect or block page)."},{"question":"What is the difference between whitelist and blacklist?","answer":"Whitelist allows only listed countries; blacklist blocks listed countries."},{"question":"How accurate is country-level GeoIP?","answer":"~99% accurate at country level."},{"question":"What are common use cases for geo blocking?","answer":"Licensing, compliance, security, content localization, pricing."},{"question":"Can VPNs bypass geo blocking?","answer":"Yes, but CDNs detect and can block known VPN/proxy IPs."},{"question":"Where does geo blocking happen in the request flow?","answer":"At the CDN edge, before reaching the origin."},{"question":"What is GDPR-related geo blocking?","answer":"Keeping EU user data within EU regions for compliance."},{"question":"What databases do CDNs use for geo blocking?","answer":"MaxMind GeoIP, IP2Location, or proprietary (Cloudflare)."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Geo Blocking</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">User</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Attempts access</text><rect x=\"160\" y=\"35\" width=\"160\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"240\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GeoIP Database</text><text x=\"240\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Maps IP to country</text><rect x=\"160\" y=\"65\" width=\"160\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"240\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Decision</text><text x=\"240\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Allowed or blocked?</text><rect x=\"10\" y=\"135\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"151\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Allowed</text><text x=\"65\" y=\"143\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Pass through to orig</text><text x=\"65\" y=\"154\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">in</text><rect x=\"10\" y=\"165\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"181\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Blocked</text><text x=\"65\" y=\"173\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">403 / redirect / cap</text><text x=\"65\" y=\"184\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">tcha</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"320\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"320\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"148\" x2=\"150\" y2=\"148\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"178\" x2=\"150\" y2=\"178\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"100\" width=\"160\" height=\"50\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"240\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Geo Blocking Logic</text><text x=\"240\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Whitelist? Blacklist? VPN det</text><text x=\"240\" y=\"144\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ected? Custom rules?</text><text x=\"240\" y=\"215\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Geo Blocking: Restrict content by geography at edg</text><text x=\"240\" y=\"227\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">e. GeoIP + whitelist/blacklist + VPN detection.</text></svg>","codeExamples":[{"title":"CloudFront Geo Restriction via Console","useCase":"Setting up geo blocking.","code":"# AWS Console:\n# CloudFront -> Distribution -> Restrictions -> Geo Restriction\n\n# Option 1: Whitelist (Allow List)\n# Select countries to ALLOW traffic from\n# All other countries get 403 Forbidden\n\n# Option 2: Blacklist (Block List)\n# Select countries to BLOCK traffic from\n# All other countries are allowed\n\n# Geo restriction is applied per distribution\n# Uses MaxMind GeoIP database\n# Cannot customize block response page natively","description":"CloudFront console geo restriction setup with whitelist/blacklist options."},{"title":"Cloudflare Geo Blocking via WAF","useCase":"Geo blocking with Cloudflare WAF.","code":"# Block traffic from specific countries:\n\n# Dashboard: Security -> WAF -> Custom Rules\n# Expression: (ip.geoip.country in {\"XX\" \"YY\" \"ZZ\"})\n# Action: Block\n\n# Or via API:\ncurl -X POST \"https://api.cloudflare.com/client/v4/zones/$ZONE_ID/rulesets/$RULESET_ID/rules\" \\\n  -H \"Authorization: Bearer $TOKEN\" \\\n  -H \"Content-Type: application/json\" \\\n  -d '{\"action\": \"block\", \"expression\": \"(ip.geoip.country in {\\\"XX\\\" \\\"YY\\\"})\", \"description\": \"Geo Block\"}'\n\n# Cloudflare uses its own GeoIP (more accurate)\n# Can combine with IP reputation scoring","description":"Cloudflare WAF geo blocking with country-specific rules."},{"title":"Fastly Geo Blocking in VCL","useCase":"Geo blocking with Fastly VCL.","code":"sub vcl_recv {\n  # Block high-threat regions\n  if (req.http.Fastly-Geo-Country ~ \"(XX|YY|ZZ)\") {\n    error 403 \"Access denied from your region\";\n  }\n\n  # Only allow US traffic for licensed content\n  if (req.url ~ \"^/licensed/\" && req.http.Fastly-Geo-Country != \"US\") {\n    error 403 \"Content not available in your region\";\n  }\n\n  # Custom block page (serve from Fastly)\n  if (req.http.Fastly-Geo-Country == \"XX\") {\n    set req.url = \"/blocked.html\";\n    error 900 \"Blocked\";\n  }\n}\nsub vcl_error {\n  if (obj.status == 900) {\n    set obj.status = 403;\n    return (deliver);\n  }\n}","description":"Fastly VCL geo blocking with custom block pages and selective blocking."},{"title":"Akamai Geo Blocking via Property Manager","useCase":"Geo blocking with Akamai.","code":"# Akamai Property Manager:\n# Add behavior -> Access Control ->\n# \"Deny Access Based on Country\"\n\n# Configuration:\n# - Select Deny or Allow behavior\n# - Country list (multi-select)\n# - Response: 403 Forbidden or custom\n\n# Match criteria:\n# - Country code from GeoIP\n# - Can combine with other criteria\n#   (path, device, cookie)\n\n# Also available via Akamai API (PAPI)\n# Can use EdgeWorkers for complex logic","description":"Akamai Property Manager geo blocking configuration."},{"title":"VPN/Proxy Detection with Geo Blocking","useCase":"Detecting geo-block bypass attempts.","code":"# Cloudflare VPN/Proxy detection:\n# Field: cf.edge.server_ip_type\n# Values: \"vpn\", \"proxy\", \"tor\", \"hosting\"\n# Available in WAF expressions\n\n# WAF rule: Block VPN + blocked country\nexpression: \n  (ip.geoip.country eq \"XX\") or \n  (cf.edge.server_ip_type eq \"vpn\")\n\n# Rate limiting proxy users:\n# If IP type is proxy, apply stricter limits\n# e.g., 5 req/min instead of 100 req/min\n\n# Drawback: false positives for legitimate users\n# traveling or using corporate VPNs","description":"VPN and proxy detection to strengthen geo blocking effectiveness."}],"mcqQuestions":[{"question":"What is geo blocking?","options":["Blocking all traffic","Restricting content by geographic location","Blocking IP addresses","Blocking content types"],"answer":1,"explanation":"Geo blocking restricts content by the user\\'s geographic location."},{"question":"Where does geo blocking happen?","options":["At the origin server","At the CDN edge","At the DNS server","At the client browser"],"answer":1,"explanation":"Geo blocking happens at the CDN edge before reaching the origin."},{"question":"What is the accuracy of country-level GeoIP?","options":["~50%","~80%","~99%","~60%"],"answer":2,"explanation":"Country-level GeoIP is approximately 99% accurate."},{"question":"What does a whitelist geo block do?","options":["Allows all countries","Allows only listed countries","Blocks only listed countries","Allows all traffic"],"answer":1,"explanation":"A whitelist only allows traffic from specified countries."},{"question":"How can users bypass geo blocking?","options":["Using a different browser","Using VPNs/proxies","Clearing cookies","Disabling JavaScript"],"answer":1,"explanation":"Users commonly use VPNs or proxies to bypass geo blocking."},{"question":"What is GDPR-related geo blocking?","options":["Blocking EU users","Keeping EU data within EU regions","Blocking all traffic","Allowing EU users"],"answer":1,"explanation":"GDPR-related geo blocking keeps EU user data within EU regions."}]};
TOPICS_DATA["cdn"]["cdn-ddos-protection"] = {"id":"cdn-ddos-protection","title":"DDoS Protection","difficulty":"advanced","estimatedMinutes":25,"tldr":["CDNs protect against Distributed Denial of Service (DDoS) attacks by absorbing and filtering malicious traffic across their globally distributed infrastructure.","DDoS attack types: volumetric (bandwidth exhaustion), protocol (SYN flood, DNS amplification), and application layer (HTTP flood, slow loris).","CDN DDoS mitigation layers: network edge (packet filtering), load balancers (traffic distribution), application-aware inspection (WAF, rate limiting).","CDNs can absorb attacks up to multiple Tbps by distributing traffic across thousands of edge servers, each handling a fraction of the attack."],"laymanDefinition":"DDoS protection by a CDN is like having a thousand fire stations across the country instead of just one. When arsonists start fires everywhere (DDoS attack), instead of one station getting overwhelmed, each station handles the fires in its neighborhood. A few extra sprinklers (rate limiting) and fire inspectors (WAF) at each station also help.","deepDive":[{"heading":"Volumetric (Layer 3/4) Attacks","text":"Goal: saturate bandwidth. Types: UDP floods, ICMP floods, amplification (DNS, NTP, SSDP). CDN mitigation: absorbs at network edge, null-routes attacking IPs, uses Anycast to distribute traffic. Cloudflare absorbed 2.5 Tbps+ attacks."},{"heading":"Protocol (Layer 3/4) Attacks","text":"Goal: exhaust server/network resources. Types: SYN floods, ACK floods, fragmented packet attacks. CDN mitigation: SYN cookies, connection tracking, TCP stack hardening. Fastly and Cloudflare handle millions of SYNs per second."},{"heading":"Application Layer (Layer 7) Attacks","text":"Goal: crash application server. Types: HTTP floods, slow loris, slow POST, cache-busting attacks. CDN mitigation: rate limiting, WAF inspection, challenge pages (JS challenge, captcha), behavioral analysis. Most dangerous because hardest to distinguish from legitimate traffic."},{"heading":"Always-On vs On-Demand Protection","text":"Always-on: CDN continuously scrubs all traffic. On-demand: traffic is redirected to scrubbing center only during attacks (may have 1-5 minute switchover). CDNs typically offer always-on for basic protection; premium plans add on-demand for large attacks."},{"heading":"CDN DDoS Response Flow","text":"1) Traffic arrives at closest edge. 2) Layer 3/4 filters drop obvious attacks. 3) Connection tracking ensures valid TCP. 4) Rate limiting per IP/region/ASN. 5) WAF inspects HTTP requests. 6) Behavioral analysis identifies attack patterns. 7) Challenge pages verify humans."}],"interviewAnswer":"CDN DDoS protection uses layered defense: network edge absorbs volumetric, protocol filtering handles SYN/UDP floods, WAF and rate limiting mitigate application attacks. Always-on scrubbing and Anycast distribution enable multi-Tbps attack absorption.","interviewQuestions":[{"question":"What is a DDoS attack?","answer":"Distributed Denial of Service — multiple systems flood a target with traffic to overwhelm it."},{"question":"How do CDNs protect against DDoS?","answer":"Distribute traffic across global edge network, filter at multiple layers."},{"question":"What are the three DDoS attack types?","answer":"Volumetric (Layer 3/4), Protocol, Application (Layer 7)."},{"question":"What is a SYN flood?","answer":"Attack sends many TCP SYN requests without completing the handshake, exhausting server resources."},{"question":"What is an HTTP flood?","answer":"Sending many legitimate-looking HTTP requests to overwhelm the application server."},{"question":"What is always-on DDoS protection?","answer":"Traffic is continuously scrubbed by the CDN for all traffic all the time."},{"question":"What is on-demand DDoS protection?","answer":"Traffic routed to scrubbing centers only during an active attack."},{"question":"What is a challenge page?","answer":"A JS challenge or captcha that verifies the visitor is human, not a bot."},{"question":"What was the largest DDoS attack absorbed by a CDN?","answer":"Cloudflare absorbed a 2.5+ Tbps attack in 2023."},{"question":"What is the downside of always-on DDoS protection?","answer":"Potential latency added from inspection, even when no attack is happening."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">DDoS Protection</text><rect x=\"10\" y=\"35\" width=\"80\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"50\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Attacker</text><text x=\"50\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Botnet</text><rect x=\"10\" y=\"65\" width=\"80\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"50\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Attacker</text><text x=\"50\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">SYN flood</text><rect x=\"10\" y=\"95\" width=\"80\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"50\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Attacker</text><text x=\"50\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">HTTP flood</text><line x1=\"90\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"90\" y1=\"78\" x2=\"140\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"90\" y1=\"108\" x2=\"140\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"160\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"230\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Layer 3/4</text><text x=\"230\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Packet filter</text><rect x=\"150\" y=\"65\" width=\"160\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"230\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Layer 7</text><text x=\"230\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">WAF + rate limit</text><rect x=\"150\" y=\"95\" width=\"160\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"230\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Behavioral</text><text x=\"230\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Challenge page</text><line x1=\"310\" y1=\"48\" x2=\"340\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"310\" y1=\"78\" x2=\"340\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"310\" y1=\"108\" x2=\"340\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"350\" y=\"35\" width=\"120\" height=\"90\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"410\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CDN Edge</text><text x=\"410\" y=\"97\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Distributed absorptio</text><text x=\"410\" y=\"108\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">n across thousands of</text><text x=\"410\" y=\"119\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\"> servers</text><line x1=\"470\" y1=\"80\" x2=\"490\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"500\" y=\"35\" width=\"100\" height=\"90\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"550\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Origin</text><text x=\"550\" y=\"119\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Protected</text><text x=\"280\" y=\"205\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">DDoS Protection: Layered filtering at CDN edge abs</text><text x=\"280\" y=\"217\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">orbs multi-Tbps attacks and shields origin.</text></svg>","codeExamples":[{"title":"Cloudflare DDoS Overview & Settings","useCase":"Cloudflare DDoS protection configuration.","code":"# Cloudflare DDoS protection is automatic\n# and included on all plans\n\n# Dashboard: Security -> DDoS\n# Settings:\n# - DDoS Attack Alerts (Webhooks/Email)\n# - DDoS Override (mitigation sensitivity)\n# - Advanced DDoS Rules\n\n# Custom DDoS rule via API:\ncurl -X POST \"https://api.cloudflare.com/client/v4/zones/$ZONE_ID/ddos_rules\" \\\n  -H \"Authorization: Bearer $TOKEN\" \\\n  -H \"Content-Type: application/json\" \\\n  -d '{\"action\": \"block\", \"expression\": \"(http.request.method eq \\\"GET\\\")\", \"sensitivity\": \"high\"}'\n\n# DDoS alerts:\n# - HTTP DDoS Attack Alert\n# - Layer 3/4 DDoS Attack Alert\n# - Advanced DDoS Attack Alert","description":"Cloudflare DDoS protection settings and custom rules configuration."},{"title":"AWS Shield + CloudFront DDoS Protection","useCase":"AWS DDoS protection for CloudFront.","code":"# AWS Shield Standard (Free)\n# - Automatic with CloudFront and Route53\n# - Protects against L3/L4 attacks\n# - Up to 5 Gbps protection\n\n# AWS Shield Advanced ($3,000/month)\n# - Enhanced DDoS protection\n# - 24/7 DRT access\n# - Financial protection (cost reimbursement)\n# - Real-time metrics and visibility\n# - Up to 500 Gbps+ protection\n\n# Enabling Shield Advanced for CloudFront:\naws shield create-protection --name \"cdn-distribution\" \\\n  --resource-arn \"arn:aws:cloudfront::123456789:distribution/E123456789ABCD\"\n\n# Shield Advanced also provides:\n# - Application Layer (L7) DDoS mitigation\n# - Health-based detection\n# - Custom mitigation rules","description":"AWS Shield Standard and Advanced DDoS protection for CloudFront distributions."},{"title":"Rate Limiting for HTTP Floods","useCase":"Rate limiting to mitigate Layer 7 attacks.","code":"# Cloudflare Rate Limiting:\n# Dashboard: Security -> WAF -> Rate Limiting Rules\n# Rule: Block if > 100 requests from same IP in 1 minute\n\n# Via API:\ncurl -X POST \"https://api.cloudflare.com/client/v4/zones/$ZONE_ID/rate_limits\" \\\n  -H \"Authorization: Bearer $TOKEN\" \\\n  -d '{\"threshold\": 100, \"period\": 60, \"action\": \"block\", \"match\": {\"request\": {\"url\": \"https://example.com/login\"}}}'\n\n# Fastly:\nif (ratecounter.rate_limit_count(req.url.path, \"10 seconds\") > 50) {\n  error 429 \"Too many requests\";\n}\n\n# NGINX:\nlimit_req_zone $binary_remote_addr zone=mylimit:10m rate=10r/s;","description":"Rate limiting rules for mitigating HTTP flood DDoS attacks."},{"title":"Challenge Page (JS Challenge)","useCase":"Bot verification via challenge.","code":"# Cloudflare JS Challenge:\n# Security -> Settings -> Challenge Passage\n\n# JS Challenge works:\n# 1. CDN returns interstitial HTML page\n# 2. Browser executes JavaScript challenge\n# 3. If solved, visitor gets cf_clearance cookie\n# 4. Cookie valid for challenge passage period\n# 5. Permanent access (no more challenges)\n\n# Non-JS environments (API clients):\n# Cannot solve JS challenge -> blocked\n# API clients should use rate limiting instead\n\n# Alternative: CAPTCHA challenge\n# - Manual verification for sensitive endpoints\n# - Higher security but worse user experience\n# - Turnstile: Cloudflare's privacy-first captcha","description":"JS Challenge page mechanism for verifying human visitors during DDoS events."},{"title":"DDoS Incident Response with CDN","useCase":"Responding to a DDoS attack.","code":"# 1. Detect: Monitor CDN analytics for traffic spikes\ncurl -s \"https://api.cloudflare.com/client/v4/zones/$ZONE_ID/analytics/dashboard\" | jq \".result.totals.http_requests\"\n\n# 2. Activate DDoS override (if needed)\ncurl -X PATCH \"https://api.cloudflare.com/client/v4/zones/$ZONE_ID/ddos_override\" -d '{\"action\": \"block\"}'\n\n# 3. Enable \"I'm Under Attack\" mode (Cloudflare)\ncurl -X PATCH \"https://api.cloudflare.com/client/v4/zones/$ZONE_ID/settings/security_level\" -d '{\"value\": \"under_attack\"}'\n\n# 4. Rate limit aggressively\n# 5. Block attacking IPs/ASNs/regions\n# 6. Contact CDN support for escalation\n# 7. Monitor:\ncurl -s \"https://api.cloudflare.com/client/v4/zones/$ZONE_ID/security/events\" | jq \".result\" | head -20","description":"DDoS incident response commands using CDN APIs to mitigate active attacks."}],"mcqQuestions":[{"question":"What are the three types of DDoS attacks?","options":["SQL injection, XSS, CSRF","Volumetric, Protocol, Application","GET, POST, PUT","Internal, external, lateral"],"answer":1,"explanation":"DDoS attacks are categorized as volumetric, protocol, and application layer."},{"question":"How does a CDN absorb volumetric DDoS attacks?","options":["By blocking all traffic","By distributing traffic across global edge servers","By rate limiting only","By disabling the site"],"answer":1,"explanation":"CDN distributes attack traffic across thousands of edge servers."},{"question":"What is an HTTP flood?","options":["Many DNS queries","Many legitimate-looking HTTP requests","Many SYN packets","Many UDP packets"],"answer":1,"explanation":"An HTTP flood sends many HTTP requests to overwhelm the application."},{"question":"What is a challenge page?","options":["Login page","JS/CAPTCHA verification page","Error page","Homepage"],"answer":1,"explanation":"A challenge page verifies the visitor is human, not a bot."},{"question":"What is always-on DDoS protection?","options":["Protection only during attacks","Continuous traffic scrubbing","Manual mitigation","No protection"],"answer":1,"explanation":"Always-on scrubs all traffic continuously."},{"question":"What is AWS Shield Advanced?","options":["Free DDoS protection","Premium DDoS protection for AWS","WAF service","CDN service"],"answer":1,"explanation":"AWS Shield Advanced is a premium DDoS protection service."}]};
TOPICS_DATA["cdn"]["cdn-waf-integration"] = {"id":"cdn-waf-integration","title":"WAF Integration","difficulty":"intermediate","estimatedMinutes":20,"tldr":["A Web Application Firewall (WAF) integrated with a CDN inspects HTTP traffic at the edge, blocking malicious requests before they reach the origin.","WAF protects against: SQL injection, XSS (Cross-Site Scripting), path traversal, command injection, CSRF, file inclusion, and OWASP Top 10 threats.","CDN WAF integrates seamlessly with CDN caching and routing — malicious requests are blocked at the edge, while legitimate traffic is cached and served normally.","Modern CDN WAFs use managed rule sets (OWASP, vendor-specific), custom rules, rate limiting, and machine learning for anomaly detection."],"laymanDefinition":"WAF integrated with a CDN is like having a security checkpoint at the entrance of a building, not just at each office door. The security guard checks for weapons, suspicious packages, and known threats before anyone enters. If someone looks suspicious, they are stopped at the entrance, never reaching the offices (origin).","deepDive":[{"heading":"WAF at Edge vs Origin","text":"Edge WAF: inspects at CDN edge, blocks before origin. Zero origin load from blocked requests. Lower latency (no origin trip). Origin WAF: inspects at application server. More context-aware but consumes origin resources. CDN WAF is the industry standard."},{"heading":"Managed Rule Sets","text":"Pre-built rule sets maintained by CDN vendor. OWASP Top 10 rules (CRS - Core Rule Set). Vendor-specific: Cloudflare Managed, AWS Managed, Fastly Signal Sciences. Regular rule updates from vendor. Customizable (paranoia levels, anomaly thresholds)."},{"heading":"Custom WAF Rules","text":"User-defined rules for application-specific threats. Match on: URI, headers, body, cookies, IP, country, device. Actions: block, challenge, log, rate limit, bypass. Use regex or DSL (VCL, Lua). Priority ordering matters. Rule testing and dry-run modes available."},{"heading":"WAF Logging and Analytics","text":"Comprehensive logging of blocked/allowed requests. Attack analytics dashboard. Top attack vectors, sources, and targets. Real-time alerts for spikes in blocked traffic. Logs stored for compliance (SIEM integration via log streaming)."},{"heading":"WAF Performance Considerations","text":"Edge WAF adds minimal latency (microseconds to low milliseconds). Rule count and complexity affect performance. Heavy regex can slow processing. WAF bypass for static cached resources (images, CSS) reduces unnecessary inspection. Parallel vs sequential rule evaluation."}],"interviewAnswer":"CDN WAF inspects HTTP traffic at the edge against managed and custom rules, blocking SQLi, XSS, and OWASP Top 10 threats before they reach origin. It offers managed rule sets, custom rules, rate limiting, ML-based detection, and comprehensive logging.","interviewQuestions":[{"question":"What does WAF stand for?","answer":"Web Application Firewall."},{"question":"What attacks does WAF protect against?","answer":"SQL injection, XSS, path traversal, command injection, OWASP Top 10."},{"question":"Where is the WAF in a CDN architecture?","answer":"At the CDN edge, inspecting traffic before it reaches the origin."},{"question":"What is a managed rule set?","answer":"Pre-built WAF rules maintained by the CDN vendor (e.g., OWASP CRS)."},{"question":"What is a custom WAF rule?","answer":"User-defined rule for application-specific threats using match criteria and actions."},{"question":"What is WAF paranoia level?","answer":"Configurable sensitivity level in OWASP CRS (1-4, higher = more strict)."},{"question":"What is WAF bypass?","answer":"Skipping WAF inspection for certain paths or resource types for performance."},{"question":"How does WAF impact latency?","answer":"Minimal (microseconds to low milliseconds) when processing at edge."},{"question":"What is OWASP CRS?","answer":"Open Web Application Security Project Core Rule Set — standard WAF rules."},{"question":"Can WAF block legitimate traffic?","answer":"Yes, false positives are possible. Tuning with log/traffic analysis is essential."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">WAF Integration</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">User</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Sends request</text><rect x=\"350\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"405\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Malicious User</text><text x=\"405\" y=\"43\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">SQL injection payloa</text><text x=\"405\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">d</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"460\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"180\" height=\"50\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"250\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CDN Edge WAF</text><text x=\"250\" y=\"57\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Inspect: URI, headers, body, coo</text><text x=\"250\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">kies. Check: managed rules, cust</text><text x=\"250\" y=\"79\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">om rules, rate limits.</text><line x1=\"340\" y1=\"60\" x2=\"400\" y2=\"60\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"410\" y=\"35\" width=\"80\" height=\"50\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"450\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">WAF Action</text><text x=\"450\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Allowed? Block</text><text x=\"450\" y=\"79\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">? Challenge?</text><line x1=\"490\" y1=\"60\" x2=\"510\" y2=\"60\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"490\" y1=\"60\" x2=\"160\" y2=\"85\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"95\" width=\"170\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"235\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Origin (Protected)</text><text x=\"235\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Legitimate traffic only</text><rect x=\"160\" y=\"130\" width=\"170\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"245\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Blocked (at edge)</text><text x=\"245\" y=\"149\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">403 Forbidden</text><text x=\"240\" y=\"180\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">WAF Integration: Edge-based Web Application Firewa</text><text x=\"240\" y=\"192\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ll blocks OWASP Top 10 threats before reaching ori</text><text x=\"240\" y=\"204\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">gin.</text></svg>","codeExamples":[{"title":"Cloudflare WAF Managed Rules","useCase":"Enabling Cloudflare managed WAF rules.","code":"# Dashboard: Security -> WAF -> Managed Rules\n\n# Enable OWASP CRS:\n# - Paranoia Level: 1 (low) to 4 (high)\n# - Anomaly Threshold: 5-100 (lower = strict)\n# - Recommended: Level 2, threshold 10\n\n# Enable Cloudflare Managed Ruleset:\n# - Contains rules for common attacks\n# - Updated automatically by Cloudflare\n# - Log mode first to identify false positives\n\n# Via API:\ncurl -X PUT \"https://api.cloudflare.com/client/v4/zones/$ZONE_ID/rulesets/phases/http_request_firewall_custom\" \\\n  -H \"Authorization: Bearer $TOKEN\" \\\n  -d '{\"rules\": [{\"action\": \"block\", \"expression\": \"(http.request.uri.path contains \\\"admin\\\")\"}]'","description":"Cloudflare managed WAF rules including OWASP CRS with configurable paranoia levels."},{"title":"AWS WAF with CloudFront","useCase":"Integrating AWS WAF with CloudFront.","code":"# Create Web ACL:\naws wafv2 create-web-acl --name \"cdn-acl\" --scope CLOUDFRONT \\\n  --default-action \"Allow={}\" \\\n  --rules '[\n    {\n      \"Name\": \"AWS-AWSManagedRulesCommonRuleSet\",\n      \"Priority\": 0,\n      \"Statement\": { \"ManagedRuleGroupStatement\": {\n        \"VendorName\": \"AWS\", \"Name\": \"AWSManagedRulesCommonRuleSet\"\n      }},\n      \"OverrideAction\": { \"None\": {} }\n    }\n  ]'\n\n# Associate with CloudFront:\naws cloudfront associate-web-acl --distribution-id E123456789ABCD \\\n  --web-acl-id \"arn:aws:wafv2:us-east-1:123456789:global/webacl/cdn-acl/abc123\"\n\n# AWS WAF managed rule groups:\n# - CommonRuleSet (SQLi, XSS, LFI)\n# - AdminProtection (admin area access)\n# - KnownBadInputs (probe patterns)\n# - AmazonIPReputationList (bot/spam IPs)","description":"AWS WAF with CloudFront using managed rule groups for comprehensive protection."},{"title":"Custom WAF Rule (Cloudflare)","useCase":"Creating custom WAF rules.","code":"# Custom rule: Block requests with suspicious query strings\nexpression: \n  (starts_with(lower(http.request.uri.query), \"select\") or \n   starts_with(lower(http.request.uri.query), \"union\") or \n   starts_with(lower(http.request.uri.query), \"drop\") or \n   starts_with(lower(http.request.uri.query), \"delete\"))\naction: block\n\n# Custom rule: Challenge login page from unknown IPs\nexpression: \n  (http.request.uri.path eq \"/login\") and \n  (not ip.src in {\"203.0.113.0/24\" \"10.0.0.0/8\"})\naction: managed_challenge\n\n# Test custom rules in Log mode first!\n# Monitor Security Events before enabling Block","description":"Custom WAF rules for SQL injection detection and login page protection."},{"title":"Fastly Signal Sciences WAF","useCase":"Fastly WAF (Signal Sciences) integration.","code":"# Fastly WAF (Signal Sciences) features:\n# - ML-based attack detection\n# - Custom rules and signals\n# - Agent-based or edge-based deployment\n# - Covers OWASP Top 10 + API security\n\n# VCL integration example:\nsub vcl_recv {\n  if (req.http.Fastly-SigSci-Attack) {\n    error 403 \"Blocked by WAF\";\n  }\n}\n\n# Custom signal:\n# Dashboard -> WAF -> Custom Signals\n# Signal: high_rate_login_attempts\n# Condition: >20 POST to /login in 1 min\n# Action: block for 5 minutes\n\n# Signal Sciences agent-side:\n# Installed on origin, sends telemetry to Fastly\n# Edge blocks based on agent + edge signals","description":"Fastly Signal Sciences WAF with ML detection and custom signals."},{"title":"WAF Logging and Analysis","useCase":"Monitoring WAF events.","code":"# Cloudflare Security Events:\n# Dashboard: Security -> Events\n# Filter by action: block, challenge, log\n# View top attack sources, paths, payloads\n\n# Log streaming to SIEM:\n# Dashboard: Analytics & Logs -> Logpush\n# Destination: S3, Datadog, Splunk, Sumo Logic\n\n# AWS WAF logging:\naws wafv2 put-logging-configuration \\\n  --logging-configuration '{\"ResourceArn\": \"arn:aws:wafv2:...\", \"LogDestinationConfigs\": [\"arn:aws:firehose:...\"]}'\n\n# Analyze logs:\ncurl -s \"https://api.cloudflare.com/client/v4/zones/$ZONE_ID/security/events\" \\\n  | jq \".result[] | select(.action == \"blocked\") | .ray_id, .source, .rule_id\"\n\n# Set up alerts for WAF blocks exceeding threshold","description":"WAF logging and analysis with SIEM integration for monitoring blocked traffic."}],"mcqQuestions":[{"question":"What does a WAF protect against?","options":["Only DDoS","SQL injection, XSS, and OWASP Top 10","Only brute force","Only bot traffic"],"answer":1,"explanation":"WAF protects against SQLi, XSS, and other OWASP Top 10 threats."},{"question":"Where is the WAF located in a CDN?","options":["At the origin server","At the CDN edge","At the client browser","At the DNS server"],"answer":1,"explanation":"CDN WAF is at the edge, inspecting traffic before origin."},{"question":"What is OWASP CRS?","options":["Caching rule system","Core Rule Set for WAF","Content routing service","Certificate revocation system"],"answer":1,"explanation":"OWASP CRS is the Core Rule Set for WAF."},{"question":"What is WAF paranoia level?","options":["Server location","Sensitivity level (1-4)","Cache level","Security level"],"answer":1,"explanation":"Paranoia level controls WAF sensitivity from 1 (low) to 4 (high)."},{"question":"What should you do before enabling custom WAF rules?","options":["Enable immediately","Test in log mode first","Disable other rules","Contact support"],"answer":1,"explanation":"Always test custom rules in log mode before enabling blocking."},{"question":"What is a WAF bypass?","options":["Skipping WAF for certain paths","Bypassing origin","Bypassing cache","Bypassing DNS"],"answer":0,"explanation":"WAF bypass skips inspection for specific paths or resource types."}]};
TOPICS_DATA["cdn"]["cdn-signed-urls"] = {"id":"cdn-signed-urls","title":"Signed URLs","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Signed URLs provide time-limited, authenticated access to private content. They are URLs with a cryptographic signature, expiration time, and optional IP/country restrictions.","A signed URL grants temporary access to a specific resource (or path prefix). The CDN validates the signature and expiration before serving the content.","Use cases: streaming paywalled video, private file downloads, software package distribution, pay-per-view content, and any time-limited access scenario.","Popular CDNs supporting signed URLs: CloudFront, Cloudflare, Fastly, Akamai. Google Cloud CDN, Azure CDN. Implementation varies slightly but the concept is universal."],"laymanDefinition":"A signed URL is like a VIP ticket with an expiry time. The ticket includes a special stamp (signature) that proves it's authentic. When you show the ticket at the venue (CDN), the bouncer checks the stamp and the date. If it's valid and not expired, you're let in. Anyone who could forge the stamp is kept out.","deepDive":[{"heading":"How Signed URLs Work","text":"1) Private key held by content provider. 2) Policy created (resource, expiration, optional conditions). 3) Policy signed with private key. 4) Signature appended to URL as query parameter. 5) CDN validates signature with public key. 6) Serves or denies content."},{"heading":"Policy and Conditions","text":"Policy (JSON document) specifies: Resource URL or path prefix. Expiration time (absolute epoch). Optional: IP range allowed, date range, user agent pattern. Policy is base64-encoded and signed."},{"heading":"Key Pair Management","text":"CloudFront: uses key pairs (public/private). Cloudflare: uses token keys. Fastly: platform-managed or custom keys. Key rotation: regularly rotate private keys. Secure storage: HSM or secrets manager. Multiple key pairs for different access levels."},{"heading":"Signed URL vs Signed Cookie","text":"Signed URL: per-file, granular. Signed Cookie: session-based, covers paths. Signed URL: good for direct file links. Signed Cookie: good for HTML pages with embedded resources (downloading multiple files)."},{"heading":"Security Best Practices","text":"Short expiration times (minutes to hours, not days). Lock to specific IP if possible (adds security for stolen URLs). Use HTTPS to prevent URL interception. Rotate keys regularly. Monitor access logs for abuse. Rate limit signed URL requests."}],"interviewAnswer":"Signed URLs provide time-limited, authenticated access to private CDN content. A cryptographic signature is appended as a query parameter. The CDN validates the signature, expiration, and optional conditions before serving the content.","interviewQuestions":[{"question":"What is a signed URL?","answer":"A time-limited URL with a cryptographic signature for authenticated content access."},{"question":"What does a signed URL contain?","answer":"Resource URL, expiration time, cryptographic signature, optional conditions."},{"question":"How does the CDN validate a signed URL?","answer":"It verifies the signature using the public key and checks expiration/conditions."},{"question":"What is a policy in signed URLs?","answer":"A JSON document specifying the resource, expiration, and conditions for access."},{"question":"What is the difference between signed URL and signed cookie?","answer":"Signed URL = per-file; Signed Cookie = session-based, covers paths."},{"question":"What security best practices apply to signed URLs?","answer":"Short expiration, IP locking, HTTPS, key rotation, access monitoring."},{"question":"Which CDNs support signed URLs?","answer":"CloudFront, Cloudflare, Fastly, Akamai, Google Cloud CDN, Azure CDN."},{"question":"What is key pair management?","answer":"Managing public/private keys used to sign and validate signed URLs."},{"question":"When should you use signed URLs?","answer":"For direct file downloads, streaming video, paywalled content, software packages."},{"question":"What happens if a signed URL expires?","answer":"The CDN returns a 403 Forbidden response."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Signed URLs</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Client</text><text x=\"65\" y=\"43\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Gets signed URL from</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\"> app server</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">App Server</text><text x=\"65\" y=\"73\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Creates policy, sign</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">s with private key</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Client</text><text x=\"65\" y=\"103\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Requests content wit</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">h signed URL</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"160\" height=\"75\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"240\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CDN Edge</text><text x=\"240\" y=\"82\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Validates signature with publ</text><text x=\"240\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ic key. Checks expiration + c</text><text x=\"240\" y=\"104\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">onditions.</text><line x1=\"320\" y1=\"70\" x2=\"350\" y2=\"55\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"320\" y1=\"70\" x2=\"350\" y2=\"85\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"360\" y=\"40\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"410\" y=\"56\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">200 OK</text><text x=\"410\" y=\"59\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Serves content</text><rect x=\"360\" y=\"70\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"410\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">403</text><text x=\"410\" y=\"89\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Denied</text><text x=\"240\" y=\"200\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Signed URLs: Cryptographic time-limited access. Ap</text><text x=\"240\" y=\"212\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">p signs, CDN validates. 200 OK or 403.</text></svg>","codeExamples":[{"title":"CloudFront Signed URL Generation (Node.js)","useCase":"Generating CloudFront signed URLs.","code":"const crypto = require(\"crypto\");\nconst fs = require(\"fs\");\n\nconst privateKey = fs.readFileSync(\"./pk-ABC123456789.pem\", \"utf8\");\nconst keyPairId = \"ABC123456789\";\nconst resource = \"https://d123.cloudfront.net/private/video.mp4\";\n\n// Create policy\nconst expiration = Math.floor(Date.now() / 1000) + 3600; // 1 hour\nconst policy = JSON.stringify({\n  Statement: [{\n    Resource: resource,\n    Condition: { DateLessThan: { \"AWS:EpochTime\": expiration } }\n  }]\n});\n\n// Sign policy\nconst signer = crypto.createSign(\"RSA-SHA1\");\nsigner.update(policy);\nconst signature = signer.sign(privateKey, \"base64\");\n\n// Build signed URL\nconst signedUrl = `${resource}?Expires=${expiration}&Signature=${encodeURIComponent(signature)}&Key-Pair-Id=${keyPairId}`;\nconsole.log(\"Signed URL:\", signedUrl);","description":"CloudFront signed URL generation using RSA-SHA1 and a custom policy with expiration."},{"title":"CloudFront Signed URL with IP Restriction","useCase":"Adding IP restriction to signed URLs.","code":"const clientIP = \"203.0.113.50\";\nconst expiration = Math.floor(Date.now() / 1000) + 3600;\n\n// Policy with IP restriction\nconst policy = JSON.stringify({\n  Statement: [{\n    Resource: \"https://d123.cloudfront.net/private/*\",\n    Condition: {\n      DateLessThan: { \"AWS:EpochTime\": expiration },\n      IpAddress: { \"AWS:SourceIp\": `${clientIP}/32` }\n    }\n  }]\n});\n\n// Sign as before...\n// The signed URL only works from 203.0.113.50\n// If URL is intercepted, different IP = 403","description":"CloudFront signed URL with IP restriction to prevent URL sharing."},{"title":"Cloudflare Signed URL (Token Authentication)","useCase":"Cloudflare token-based signed URLs.","code":"# Dashboard: Speed -> Optimization ->\n# Token Authentication -> Enable\n\n# Generate token with token key:\n# Use Cloudflare Worker or app server\n\n# Example token generation (Node.js):\nconst crypto = require(\"crypto\");\nconst tokenKey = \"your_token_key\";\nconst path = \"/private/video.mp4\";\nconst expires = Math.floor(Date.now() / 1000) + 3600;\nconst tokenBody = `${expires}${path}`;\nconst token = crypto.createHmac(\"sha256\", tokenKey).update(tokenBody).digest(\"hex\");\n\n# URL format:\n# /cdn-cgi/media/expires=${expires}/token=${token}/${path}\n\n# Validation:\n# Cloudflare derives the same token and compares\n# Rejects if expired or invalid token","description":"Cloudflare token authentication for signed URLs using HMAC-SHA256."},{"title":"Fastly Signed URL with VCL","useCase":"Fastly signed URL implementation.","code":"# Fastly has a \"Signed Fetch\" feature\n# Surrogate key + base64 encoded policy\n\n# VCL to validate signed fetch:\nsub vcl_recv {\n  if (req.url ~ \"^/private/\") {\n    # Require signed fetch header\n    if (!req.http.Fastly-Signed-Fetch) {\n      error 403 \"Signed fetch required\";\n    }\n    # Optionally validate custom signature in query string\n    if (!req.url.qs == \"\") {\n      set req.http.X-Expires = querystring.get(req.url, \"expires\");\n      if (std.time(now, 0) > std.time(req.http.X-Expires, 0)) {\n        error 410 \"Expired\";\n      }\n    }\n  }\n}","description":"Fastly signed URL with VCL validation and expiration checking."},{"title":"CloudFront Signed URL Using AWS CLI","useCase":"Generating signed URLs with AWS CLI.","code":"# Requires CloudFront key pair configured\n# Key pair ID: K123456789ABC\n# Private key file: pk-K123456789ABC.pem\n\n# Generate signed URL with cloudfront-signer (Python):\npip install cloudfront-signer\n\nfrom cloudfront_signer import CloudFrontSigner\nimport rsa\n\nwith open(\"pk-K123456789ABC.pem\", \"rb\") as f:\n    private_key = rsa.PrivateKey.load_pkcs1(f.read())\n\nsigner = CloudFrontSigner(\"K123456789ABC\", lambda m: rsa.sign(m, private_key, \"SHA-1\"))\nurl = signer.generate_signed_url(\n    {\"url\": \"https://d123.cloudfront.net/private/file.pdf\", \"date_less_than\": \"2025-12-31\"})\nprint(f\"Signed URL: {url}\")","description":"CloudFront signed URL generation using Python cloudfront-signer library."}],"mcqQuestions":[{"question":"What is a signed URL?","options":["A public URL","A time-limited authenticated URL","A cached URL","A compressed URL"],"answer":1,"explanation":"A signed URL is time-limited with cryptographic authentication."},{"question":"What happens when a signed URL expires?","options":["Content is compressed","CDN returns 403","CDN returns 404","CDN redirects"],"answer":1,"explanation":"An expired signed URL returns a 403 Forbidden."},{"question":"What algorithm does CloudFront use for signed URLs?","options":["HMAC-SHA256","RSA-SHA1","AES256","MD5"],"answer":1,"explanation":"CloudFront uses RSA-SHA1 for signing."},{"question":"What is a signed URL policy?","options":["URL format","JSON doc with resource, expiration, conditions","Cache policy","Security policy"],"answer":1,"explanation":"A policy is a JSON document specifying resource, expiration, and conditions."},{"question":"What is the difference between signed URL and signed cookie?","options":["Same thing","Signed URL = per-file; Signed Cookie = session-based","Cookie is faster","URL is more secure"],"answer":1,"explanation":"Signed URL is per-file, signed cookie is session-based covering paths."},{"question":"What type of key does signed URL use?","options":["Symmetric key","Asymmetric key pair (public/private)","Session key","Temporary key"],"answer":1,"explanation":"Signed URLs use asymmetric key pairs for signing and validation."}]};
TOPICS_DATA["cdn"]["cdn-signed-cookies"] = {"id":"cdn-signed-cookies","title":"Signed Cookies","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Signed cookies allow session-based access to private CDN content. Unlike signed URLs (per-file), signed cookies provide access to multiple resources within a path.","A signed cookie is set by the application server containing a policy and signature. The CDN reads the cookie and validates it before serving any content request.","Use cases: websites serving multiple private files (PDFs, images, videos), member-only content galleries, subscription services, paywalled content sites.","CloudFront is the primary CDN supporting signed cookies. Other CDNs use token authentication (Cloudflare) or edge worker logic to implement equivalent functionality."],"laymanDefinition":"A signed cookie is like a backstage pass at a concert that gives you access to all areas you're allowed in. Instead of showing a separate ticket for each room (signed URL), you show your all-access pass once (cookie), and it lets you into every authorized area.","deepDive":[{"heading":"How Signed Cookies Work","text":"1) User authenticates with app server. 2) App server creates policy (resource path, expiration, conditions). 3) Policy signed with private key. 4) Response includes Set-Cookie header with signed cookie. 5) User\\'s browser sends cookie with all subsequent requests. 6) CDN validates cookie, serves or denies content."},{"heading":"Cookie Format (CloudFront)","text":"Three cookies: CloudFront-Policy (base64 policy), CloudFront-Signature (signature), CloudFront-Key-Pair-Id (key pair ID). All cookies set for domain .d123.cloudfront.net. Path set to /private/. Cookies are HTTP-only (not accessible via JS)."},{"heading":"Signed Cookie vs Signed URL Comparison","text":"Signed Cookie: session-based, covers multiple files, good for pages with embedded resources. Signed URL: per-file, granular, good for direct download links. Signed Cookie: fewer URL tokens to manage. Signed URL: easier to share (single URL). Use signed cookies for secure websites, signed URLs for APIs/downloads."},{"heading":"Security Considerations","text":"Cookies sent with every request: ensure path restriction limits scope. Expiration should be short (matching session duration). Use Secure and HttpOnly flags. Consider SameSite attribute. Cookies can be stolen via XSS — combine with Content-Security-Policy."},{"heading":"Implementation Steps (CloudFront)","text":"Generate policy JSON. Base64-encode policy (URL-safe). Sign policy with RSA-SHA1 using private key. Base64-encode signature. Set three cookies in response. Configure CloudFront to trust cookies (forward cookies or whitelist CloudFront-* cookies)."}],"interviewAnswer":"Signed cookies provide session-based CDN authentication. The app server sets cookies with an encrypted policy and signature. The CDN validates these cookies before serving any private content, enabling seamless access to multiple files in a session.","interviewQuestions":[{"question":"What is a signed cookie?","answer":"A cookie containing a signed policy for session-based CDN content access."},{"question":"How does a signed cookie differ from signed URL?","answer":"Signed cookie covers multiple files (session), signed URL is per-file."},{"question":"What cookies does CloudFront use for signed cookies?","answer":"CloudFront-Policy, CloudFront-Signature, CloudFront-Key-Pair-Id."},{"question":"When should you use signed cookies?","answer":"When serving multiple private files in a web page (images, PDFs, videos)."},{"question":"How does the CDN validate a signed cookie?","answer":"It reads the cookie, decodes the policy, verifies the signature, checks expiration."},{"question":"What flags should signed cookies have?","answer":"Secure, HttpOnly, and appropriate Path/SameSite attributes."},{"question":"Can signed cookies be stolen?","answer":"Yes, via XSS. Protect with CSP, HttpOnly, and short expiration."},{"question":"Which CDNs support signed cookies natively?","answer":"CloudFront. Other CDNs use token auth or edge workers."},{"question":"What path should signed cookies use?","answer":"The path prefix of the private content (e.g., /private/)."},{"question":"What happens when the cookie expires?","answer":"The CDN returns 403; user needs to re-authenticate with the app server."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Signed Cookies</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">User</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Logs in to app</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">App Server</text><text x=\"65\" y=\"73\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Authenticates, creat</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">es signed cookie</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"160\" height=\"50\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"240\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">User Browser</text><text x=\"240\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Stores CloudFront-Policy, -Si</text><text x=\"240\" y=\"79\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">gnature, -Key-Pair-Id cookies</text><line x1=\"320\" y1=\"60\" x2=\"360\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"320\" y1=\"60\" x2=\"360\" y2=\"72\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"370\" y=\"35\" width=\"100\" height=\"50\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"420\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CDN Edge</text><text x=\"420\" y=\"57\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Validates cookies </text><text x=\"420\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">with public key. C</text><text x=\"420\" y=\"79\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">hecks expiration.</text><line x1=\"470\" y1=\"60\" x2=\"490\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"470\" y1=\"60\" x2=\"490\" y2=\"72\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"500\" y=\"25\" width=\"90\" height=\"50\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"545\" y=\"41\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Content</text><text x=\"545\" y=\"58\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">200 OK for all r</text><text x=\"545\" y=\"69\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">equests</text><rect x=\"500\" y=\"75\" width=\"90\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"545\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">403</text><text x=\"545\" y=\"94\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Denied</text><text x=\"240\" y=\"200\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Signed Cookies: Session-based CDN auth. Single coo</text><text x=\"240\" y=\"212\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">kie set allows access to multiple private files.</text></svg>","codeExamples":[{"title":"CloudFront Signed Cookie Setup (Node.js)","useCase":"Generating CloudFront signed cookies.","code":"const crypto = require(\"crypto\");\nconst fs = require(\"fs\");\n\nconst privateKey = fs.readFileSync(\"./pk-ABC123456789.pem\", \"utf8\");\nconst keyPairId = \"ABC123456789\";\nconst resource = \"https://d123.cloudfront.net/private/*\";\nconst expiration = Math.floor(Date.now() / 1000) + 3600;\n\n// Create policy\nconst policy = JSON.stringify({\n  Statement: [{\n    Resource: resource,\n    Condition: { DateLessThan: { \"AWS:EpochTime\": expiration } }\n  }]\n});\n\n// Base64 encode policy (URL safe)\nconst encodedPolicy = Buffer.from(policy).toString(\"base64\")\n  .replace(/\\+/g, \"-\").replace(/\\//g, \"_\").replace(/=+$/, \"\");\n\n// Sign\nconst signer = crypto.createSign(\"RSA-SHA1\");\nsigner.update(policy);\nconst signature = signer.sign(privateKey, \"base64\")\n  .replace(/\\+/g, \"-\").replace(/\\//g, \"_\").replace(/=+$/, \"\");\n\n// Set-Cookie headers (sent as response to authenticated request)\n// Set-Cookie: CloudFront-Policy=${encodedPolicy}; Domain=.d123.cloudfront.net; Path=/private/; Secure; HttpOnly\n// Set-Cookie: CloudFront-Signature=${signature}; Domain=.d123.cloudfront.net; Path=/private/; Secure; HttpOnly\n// Set-Cookie: CloudFront-Key-Pair-Id=${keyPairId}; Domain=.d123.cloudfront.net; Path=/private/; Secure; HttpOnly","description":"CloudFront signed cookie generation with three cookies for private content access."},{"title":"Express.js Signed Cookie Middleware","useCase":"Signed cookies in an Express app.","code":"const crypto = require(\"crypto\");\nconst fs = require(\"fs\");\n\nconst privateKey = fs.readFileSync(\"./pk-ABC123456789.pem\");\nconst keyPairId = \"ABC123456789\";\n\nfunction setCloudFrontCookies(req, res, next) {\n  if (!req.user) return res.status(401).send(\"Login required\");\n  const resource = \"https://d123.cloudfront.net/private/*\";\n  const expiration = Math.floor(Date.now() / 1000) + 3600;\n  const policy = JSON.stringify({\n    Statement: [{ Resource: resource, Condition: { DateLessThan: { \"AWS:EpochTime\": expiration } } }]\n  });\n  const b64 = (s) => Buffer.from(s).toString(\"base64\").replace(/\\+/g, \"-\").replace(/\\//g, \"_\").replace(/=+$/, \"\");\n  const signer = crypto.createSign(\"RSA-SHA1\");\n  signer.update(policy);\n  const sig = b64(signer.sign(privateKey, \"base64\"));\n  res.setHeader(\"Set-Cookie\", [\n    `CloudFront-Policy=${b64(policy)}; Domain=.d123.cloudfront.net; Path=/private/; Secure; HttpOnly`,\n    `CloudFront-Signature=${sig}; Domain=.d123.cloudfront.net; Path=/private/; Secure; HttpOnly`,\n    `CloudFront-Key-Pair-Id=${keyPairId}; Domain=.d123.cloudfront.net; Path=/private/; Secure; HttpOnly`\n  ]);\n  next();\n}\n\napp.get(\"/login\", authenticateUser, setCloudFrontCookies, (req, res) => {\n  res.redirect(\"/private/dashboard.html\");\n});","description":"Express.js middleware generating CloudFront signed cookies after user authentication."},{"title":"CloudFront Cookie Forwarding","useCase":"Configuring CloudFront to forward cookies.","code":"# CloudFront must forward the signed cookies\n# to validate them at the edge.\n\n# Option 1: Forward all cookies\naws cloudfront update-distribution \\\n  --id E123456789ABCD \\\n  --default-cache-behavior \"ForwardedValues={Cookies={Forward=all}}\"\n\n# Option 2: Whitelist CloudFront cookies (recommended)\naws cloudfront update-distribution \\\n  --id E123456789ABCD \\\n  --default-cache-behavior \"ForwardedValues={Cookies={Forward=whitelist,WhitelistedNames=[CloudFront-Policy,CloudFront-Signature,CloudFront-Key-Pair-Id]}}\"\n\n# Important: Whitelist approach is more secure\n# Only CloudFront cookies are forwarded to origin\n# All other cookies are stripped from requests","description":"CloudFront cookie forwarding configuration for signed cookie validation."},{"title":"Cloudflare Signed Cookie Equivalent (Token)","useCase":"Implementing signed cookies on Cloudflare.","code":"# Cloudflare does not have native signed cookies,\n# but you can implement using Workers:\n\n// Service Worker for token validation\naddEventListener(\"fetch\", event => {\n  event.respondWith(handleRequest(event.request));\n})\n\nasync function handleRequest(request) {\n  const cookie = request.headers.get(\"Cookie\") || \"\";\n  const tokenMatch = cookie.match(/cf_token=([^;]+)/);\n  if (!tokenMatch) return new Response(\"Forbidden\", { status: 403 });\n  const token = tokenMatch[1];\n  const tokenKey = \"your_hmac_key\";\n  const [expires, hash] = token.split(\".\");\n  if (Date.now() / 1000 > parseInt(expires)) {\n    return new Response(\"Expired\", { status: 403 });\n  }\n  const expected = await crypto.subtle.sign(\"HMAC\", tokenKey, new TextEncoder().encode(expires));\n  // Validate hash...\n  return fetch(request);\n}","description":"Cloudflare Worker implementing signed cookie equivalent via HMAC token validation."},{"title":"Signed Cookie Security Best Practices","useCase":"Securing signed cookies.","code":"# 1. Set Secure flag (HTTPS only)\nSet-Cookie: CloudFront-Policy=...; Secure; HttpOnly\n\n# 2. Set HttpOnly (not accessible via JavaScript)\nSet-Cookie: CloudFront-Signature=...; HttpOnly\n\n# 3. Restrict Path\nSet-Cookie: CloudFront-Key-Pair-Id=...; Path=/private/\n\n# 4. Consider SameSite=Lax or Strict\nSet-Cookie: CloudFront-Policy=...; SameSite=Lax\n\n# 5. Short expiration (match session TTL)\n# 6. Use CSP headers to prevent XSS\nContent-Security-Policy: default-src 'self'\n\n# 7. Rotate key pairs periodically\n# 8. Monitor CloudFront access logs for unusual patterns","description":"Security best practices for signed cookies including flags, CSP, and key rotation."}],"mcqQuestions":[{"question":"What is a signed cookie?","options":["A cookie with user preferences","Session-based CDN auth cookie","A session token","An encrypted cookie"],"answer":1,"explanation":"Signed cookie provides session-based CDN authentication."},{"question":"What cookies does CloudFront use for signed cookies?","options":["CloudFront-ID, CloudFront-Token","CloudFront-Policy, -Signature, -Key-Pair-Id","AWS-Session, AWS-Token","CF-User, CF-Auth"],"answer":1,"explanation":"CloudFront uses three cookies: Policy, Signature, Key-Pair-Id."},{"question":"When should you use signed cookies over signed URLs?","options":["For single file downloads","When serving multiple files in a page","For API calls","For public content"],"answer":1,"explanation":"Use signed cookies when serving multiple private files in a web page."},{"question":"What flags should signed cookies use?","options":["Only Expires","Secure, HttpOnly, Path","Only Domain","Only SameSite"],"answer":1,"explanation":"Signed cookies should use Secure, HttpOnly, and Path flags."},{"question":"How does the CDN validate a signed cookie?","options":["Sends to origin","Validates signature and expiration at edge","Forwards to DNS","Checks with IAM"],"answer":1,"explanation":"The CDN validates the signed cookie at the edge using the public key."},{"question":"Can signed cookies be stolen?","options":["No, they're secure","Yes, via XSS","No, they're encrypted","Only via physical access"],"answer":1,"explanation":"Signed cookies can be stolen via XSS; protect with HttpOnly and CSP."}]};
TOPICS_DATA["cdn"]["cdn-cloudflare"] = {"id":"cdn-cloudflare","title":"Cloudflare","difficulty":"beginner","estimatedMinutes":15,"tldr":["Cloudflare is a leading CDN, DNS, DDoS protection, and security platform. Founded in 2009, it serves over 20% of all websites globally.","Unique features: Anycast network with 310+ edge PoPs, reverse proxy architecture, integrated WAF, DDoS mitigation, Workers (serverless), and Argo Smart Routing.","All Cloudflare plans include: CDN caching, SSL/TLS, DDoS protection, DNS management, WAF (basic rules on free plan), and analytics.","Cloudflare operates a reverse proxy model — it terminates traffic at the edge, inspects it, and forwards to origin. This provides both performance and security benefits."],"laymanDefinition":"Cloudflare is the \"do-it-all\" security and performance platform for websites. Think of it as a security guard (DDoS/WAF), fast delivery driver (CDN), and building manager (DNS) all in one. It stands in front of your server, handling visitors efficiently and keeping troublemakers out.","deepDive":[{"heading":"Anycast Network Architecture","text":"Cloudflare uses Anycast — all 310+ PoPs share the same IP addresses. BGP routes users to the nearest PoP. This provides natural load balancing and DDoS absorption. Traffic is always routed to the fastest available PoP."},{"heading":"Reverse Proxy Model","text":"Cloudflare terminates all user connections at the edge. TLS is decrypted at edge. WAF inspects at edge. Only safe/legitimate requests are proxied to origin. Origin IP is hidden from visitors. Origin only sees Cloudflare IPs."},{"heading":"Cloudflare Workers (Serverless)","text":"Serverless compute at the 310+ edge PoPs. JavaScript/WASM execution at edge. Intercept and modify requests/responses. Use cases: A/B testing, API gateways, JWT validation, custom auth, edge redirects, image optimization. Sub-millisecond startup."},{"heading":"Security Suite","text":"DDoS: automatic, unlimited, absorbs multi-Tbps attacks. WAF: managed rules (OWASP, Cloudflare), custom rules, rate limiting, bot management. SSL/TLS: flexible (end-to-end, flexible, full, strict). Zero Trust: Cloudflare Access replaces VPNs. Page Shield: monitors 3rd-party scripts."},{"heading":"Performance Features","text":"Argo Smart Routing: finds fastest internet path (30% avg improvement). Railgun: WAN compression for dynamic content. Mirage: smart image loading for mobile. Polish: server-side image optimization. Brotli compression. Early Hints (103). HTTP/3 enabled by default."}],"interviewAnswer":"Cloudflare is a reverse proxy CDN with Anycast network, integrated security (DDoS, WAF, SSL), serverless Workers, and performance optimizations. It serves 20%+ of websites with features across all plans, from free to enterprise.","interviewQuestions":[{"question":"What makes Cloudflare unique?","answer":"Anycast network, reverse proxy model, serverless Workers, all-in-one platform."},{"question":"How many PoPs does Cloudflare have?","answer":"310+ PoPs globally on Anycast network."},{"question":"What is Cloudflare\\'s business model?","answer":"Freemium: free plan with basic features, paid plans for advanced features."},{"question":"What is a Cloudflare Worker?","answer":"Serverless JavaScript/WASM execution at CDN edge."},{"question":"What is Argo Smart Routing?","answer":"Real-time traffic optimization finding faster internet paths."},{"question":"What does \"orange-clouded\" mean?","answer":"Proxied through Cloudflare (vs gray-clouded = DNS-only)."},{"question":"What is Cloudflare Access?","answer":"Zero Trust replacement for VPNs, authenticating users before they reach applications."},{"question":"What is Railgun?","answer":"WAN compression technology for dynamic content (deprecated, replaced by Argo)."},{"question":"Does Cloudflare support HTTP/3?","answer":"Yes, HTTP/3 is enabled by default on all plans."},{"question":"What is the Cloudflare Global Network?","answer":"The worldwide network of 310+ edge data centers providing CDN, DNS, and security services."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Cloudflare</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Visitor</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Browser request</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DNS</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cloudflare DNS</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"160\" height=\"50\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"240\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cloudflare Edge</text><text x=\"240\" y=\"57\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Anycast PoP. Reverse proxy. W</text><text x=\"240\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">AF, DDoS, SSL, Workers, Cache</text><text x=\"240\" y=\"79\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">, Argo.</text><line x1=\"320\" y1=\"60\" x2=\"360\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"320\" y1=\"60\" x2=\"360\" y2=\"72\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"370\" y=\"35\" width=\"100\" height=\"50\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"420\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Origin Server</text><text x=\"420\" y=\"35\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Only receives filt</text><text x=\"420\" y=\"46\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ered, safe traffic</text><text x=\"420\" y=\"57\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\"> from Cloudflare I</text><text x=\"420\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Ps. Origin IP hidd</text><text x=\"420\" y=\"79\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">en.</text><text x=\"240\" y=\"200\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Cloudflare: Anycast CDN with reverse proxy, DDoS, </text><text x=\"240\" y=\"212\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">WAF, Workers, Argo, and HTTP/3. All-in-one platfor</text><text x=\"240\" y=\"224\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">m.</text></svg>","codeExamples":[{"title":"Cloudflare DNS Setup","useCase":"Configuring DNS records on Cloudflare.","code":"# Dashboard: DNS -> Records\n\n# Orange cloud (proxied): traffic goes through Cloudflare\n# Gray cloud (DNS only): direct connection\n\n# A Record (proxied - recommended)\n# Type: A   Name: @   Content: 203.0.113.10   Proxy: Proxied\n\n# CNAME Record (proxied)\n# Type: CNAME   Name: www   Content: example.com   Proxy: Proxied\n\n# CNAME Record (DNS only for subdomain without CDN)\n# Type: CNAME   Name: api   Content: api.example.com   Proxy: DNS only\n\n# Verify:\nnslookup example.com\n# Should return Cloudflare IPs (104.x.x.x, 172.x.x.x)","description":"Cloudflare DNS record configuration with proxied vs DNS-only settings."},{"title":"Cloudflare Page Rules","useCase":"Creating page rules for routing/caching.","code":"# Dashboard: Rules -> Page Rules\n\n# Rule 1: Always HTTPS\n# URL: *.example.com/*\n# Setting: Always Use HTTPS -> On\n\n# Rule 2: Cache everything for images\n# URL: *.example.com/wp-content/uploads/*\n# Settings: Cache Level -> Cache Everything\n#           Edge Cache TTL -> 1 month\n#           Browser Cache TTL -> 1 day\n\n# Rule 3: Bypass cache for admin\n# URL: *.example.com/admin/*\n# Settings: Cache Level -> Bypass\n#           Disable Performance -> On\n\n# Note: Up to 3 page rules on free plan","description":"Cloudflare Page Rules for HTTPS, caching, and admin bypass configuration."},{"title":"Cloudflare Workers (Hello World)","useCase":"Deploying a Cloudflare Worker.","code":"# wrangler.toml\nname = \"hello-worker\"\nmain = \"src/index.js\"\ncompatibility_date = \"2024-01-01\"\n\n// src/index.js\nexport default {\n  async fetch(request, env, ctx) {\n    const url = new URL(request.url);\n    const country = request.cf.country;\n    return new Response(`\n      <h1>Hello from Cloudflare!</h1>\n      <p>You visiting from: ${country}</p>\n      <p>Edge: ${request.cf.colo}</p>\n      <p>City: ${request.cf.city}</p>\n    `, { headers: { \"content-type\": \"text/html\" } });\n  }\n}\n\n# Deploy:\nnpx wrangler deploy","description":"Simple Cloudflare Worker returning visitor geolocation and edge information."},{"title":"Cloudflare SSL/TLS Configuration","useCase":"Configuring SSL modes.","code":"# Dashboard: SSL/TLS -> Overview\n\n# SSL modes:\n# 1. Off: no encryption (not recommended)\n# 2. Flexible: edge-to-browser TLS, origin HTTP\n# 3. Full: edge-to-browser TLS, origin TLS (self-signed OK)\n# 4. Full (strict): origin must have valid CA-signed cert\n\n# Recommended: Full (strict) for maximum security\n\n# Edge certificates:\n# Cloudflare provides free SSL certs (wildcard * .example.com)\n# Automatic certificate management\n# Renews automatically\n\n# Minimum TLS Version:\n# Dashboard: Edge Certificates -> Minimum TLS Version\n# Recommended: TLS 1.2 or TLS 1.3","description":"Cloudflare SSL/TLS modes and certificate management configuration."},{"title":"Cloudflare Cache Configuration","useCase":"Configuring caching behavior.","code":"# Dashboard: Caching -> Configuration\n\n# Cache Level:\n# - No query string: cache regardless of query string\n# - Ignore query string: same as above\n# - Standard: cache based on query string\n# - Cache Everything: force cache all static content\n\n# Browser Cache TTL: 4 hours (default)\n# Edge Cache TTL: respects origin Cache-Control\n\n# Purge Cache:\n# - Purge Individual Files\n# - Purge Everything\n# - Custom Purge (by hostname, prefix, tag)\n\n# Custom Cache Key:\n# Cache by: scheme, host, URI, headers, cookie, query string\n\n# Tiered Cache:\n# - Upper tier caches from origin\n# - Lower tiers cache from upper tier\n# - Reduces origin load","description":"Cloudflare caching configuration including cache levels, TTL, and purging."}],"mcqQuestions":[{"question":"What type of network does Cloudflare use?","options":["TCP network","Anycast network","P2P network","Mesh network"],"answer":1,"explanation":"Cloudflare uses an Anycast network."},{"question":"What does orange cloud mean in Cloudflare DNS?","options":["DNS only","Traffic proxied through Cloudflare","Disabled","SSL only"],"answer":1,"explanation":"Orange cloud means traffic is proxied through Cloudflare."},{"question":"What are Cloudflare Workers?","options":["Load balancers","Serverless edge compute in JavaScript/WASM","DNS servers","Cache servers"],"answer":1,"explanation":"Workers are serverless functions at the edge."},{"question":"What is Argo Smart Routing?","options":["Static path routing","Real-time traffic optimization","DNS routing","Cache routing"],"answer":1,"explanation":"Argo finds optimal internet paths in real-time."},{"question":"What SSL mode requires valid origin cert?","options":["Flexible","Full","Full (strict)","Off"],"answer":2,"explanation":"Full (strict) requires a CA-signed certificate on the origin."},{"question":"Is HTTP/3 available on Cloudflare?","options":["No","Yes, by default","Only on enterprise","Only for paid plans"],"answer":1,"explanation":"HTTP/3 is enabled by default on all Cloudflare plans."}]};
TOPICS_DATA["cdn"]["cdn-aws-cloudfront"] = {"id":"cdn-aws-cloudfront","title":"AWS CloudFront","difficulty":"beginner","estimatedMinutes":15,"tldr":["Amazon CloudFront is a fast content delivery network (CDN) service by AWS. It integrates deeply with other AWS services (S3, EC2, ALB, Lambda@Edge, AWS WAF, Shield).","Key features: 450+ edge PoPs, regional edge caches, Lambda@Edge for compute at edge, origin shield, real-time logs, field-level encryption, and continuous deployment support.","CloudFront is pay-as-you-go with no upfront fees. Pricing varies by region (tiered pricing). Data transfer out to internet is the primary cost driver.","CloudFront is deeply integrated with the AWS ecosystem, making it the preferred CDN for workloads already running on AWS."],"laymanDefinition":"AWS CloudFront is like Amazon's global delivery network, deeply linked with the entire Amazon ecosystem (S3, EC2, Lambda). If your website is on AWS, CloudFront is the delivery truck that takes your warehouse goods (S3) and drives them to local depots (edge locations) near your customers.","deepDive":[{"heading":"Global Infrastructure","text":"450+ edge locations (PoPs) in 90+ cities. Regional edge caches (larger capacity, lower egress costs in some regions). Origin shield: additional caching layer to reduce origin load. 13 regional edge cache locations worldwide."},{"heading":"Lambda@Edge","text":"Serverless compute at CloudFront edge. Node.js and Python. Triggers: viewer-request, viewer-response, origin-request, origin-response. Use cases: A/B testing, URL rewrites, header modification, authentication, image transformation. Max 5-second execution. 128-3008 MB memory."},{"heading":"Security Integration","text":"AWS WAF: managed rules, custom rules, rate limiting, bot control. AWS Shield: Standard (free), Advanced ($3k/mo, enhanced protection). Field-level encryption: encrypt sensitive data at edge. Signed URLs and cookies: time-limited access. Origin access control (OAC): secure S3 origins."},{"heading":"Origin Options","text":"S3 bucket (static content, OAC ensures private access). EC2/ALB (dynamic content, custom apps). HTTP/HTTPS origin (external servers). Media Services (MediaPackage, MediaStore for video). Multi-origin with path pattern routing. Origin groups for failover."},{"heading":"Pricing and Cost Optimization","text":"Regional tiered pricing: US/Europe (cheapest), South America/Australia (most expensive). Free tier: 1TB/month for 12 months. Cost factors: data transfer out, request count (HTTP/HTTPS), regional edge cache. Savings: use reserved capacity pricing for predictable traffic."}],"interviewAnswer":"AWS CloudFront is a global CDN with deep AWS integration. Features include Lambda@Edge, AWS WAF/Shield, 450+ edge PoPs, origin shield, signed URLs, and flexible origin options. Pricing is pay-as-you-go with regional tiering.","interviewQuestions":[{"question":"What is AWS CloudFront?","answer":"AWS\\'s global content delivery network (CDN) service."},{"question":"How many edge locations does CloudFront have?","answer":"450+ edge locations in 90+ cities globally."},{"question":"What is Lambda@Edge?","answer":"Serverless compute at CloudFront edge locations for request/response modification."},{"question":"How does CloudFront integrate with S3?","answer":"S3 as origin with Origin Access Control (OAC) for secure private access."},{"question":"What is Origin Shield?","answer":"Additional caching layer that reduces load on the origin server."},{"question":"What is AWS Shield?","answer":"DDoS protection service — Standard (free) or Advanced ($3k/month)."},{"question":"How does CloudFront pricing work?","answer":"Pay-as-you-go with regional tiered pricing. Free tier: 1TB/month."},{"question":"What is field-level encryption?","answer":"Encrypting sensitive data fields at the CloudFront edge."},{"question":"What are CloudFront origin groups?","answer":"Group of origins for failover — primary + secondary origin."},{"question":"What is CloudFront OAC?","answer":"Origin Access Control — restricts S3 access to only CloudFront."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">AWS CloudFront</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">User</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Browser</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Edge PoP</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">450+ locations</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Regional Cache</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">13 globally</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"160\" height=\"50\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"240\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Lambda@Edge</text><text x=\"240\" y=\"68\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Compute at edge: Node.js, Pyt</text><text x=\"240\" y=\"79\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">hon</text><rect x=\"160\" y=\"95\" width=\"160\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"240\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Origin Shield</text><text x=\"240\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cache layer</text><line x1=\"320\" y1=\"60\" x2=\"370\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"320\" y1=\"60\" x2=\"370\" y2=\"72\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"320\" y1=\"108\" x2=\"370\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"380\" y=\"35\" width=\"100\" height=\"80\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"430\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">AWS WAF</text><text x=\"430\" y=\"109\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">+ Shield</text><rect x=\"380\" y=\"130\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"430\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">S3/EC2/ALB</text><text x=\"430\" y=\"149\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Origin</text><text x=\"240\" y=\"200\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">CloudFront: AWS CDN with Lambda@Edge, WAF/Shield, </text><text x=\"240\" y=\"212\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">450+ PoPs, S3/EC2/ALB origins, OAC.</text></svg>","codeExamples":[{"title":"Creating a CloudFront Distribution","useCase":"AWS CLI creation of CloudFront distribution.","code":"# Create CloudFront distribution for S3 origin:\naws cloudfront create-distribution \\\n  --distribution-config '{\n    \"CallerReference\": \"my-distribution-1\",\n    \"Origins\": {\n      \"Quantity\": 1,\n      \"Items\": [{\n        \"Id\": \"myS3Origin\",\n        \"DomainName\": \"my-bucket.s3.amazonaws.com\",\n        \"S3OriginConfig\": { \"OriginAccessIdentity\": \"\" }\n      }]\n    },\n    \"DefaultCacheBehavior\": {\n      \"TargetOriginId\": \"myS3Origin\",\n      \"ViewerProtocolPolicy\": \"redirect-to-https\",\n      \"AllowedMethods\": { \"Quantity\": 2, \"Items\": [\"GET\", \"HEAD\"] }\n    },\n    \"Enabled\": true,\n    \"PriceClass\": \"PriceClass_100\"\n  }'\n\n# PriceClass: PriceClass_100 (US/Europe only, cheapest)\n#            PriceClass_200 (most regions)\n#            PriceClass_All (all edge locations)","description":"AWS CLI command to create a CloudFront distribution for an S3 origin."},{"title":"Lambda@Edge for URL Rewrites","useCase":"Adding Lambda@Edge to CloudFront.","code":"// lambda-edge-url-rewrite.js\nexports.handler = async (event) => {\n  const request = event.Records[0].cf.request;\n  const uri = request.uri;\n\n  // Rewrite /articles/123 to /index.html?article=123\n  const match = uri.match(/^\\/articles\\/(\\d+)$/);\n  if (match) {\n    request.uri = \"/index.html\";\n    request.querystring = `article=${match[1]}`;\n  }\n\n  // Add security headers\n  request.headers[\"x-forwarded-for\"] = [{\n    key: \"X-Forwarded-For\",\n    value: request.clientIp\n  }];\n\n  return request;\n};\n\n# Deploy to us-east-1 (required) and associate with CloudFront\naws lambda create-function --function-name url-rewrite --runtime nodejs18.x --handler index.handler --zip-file fileb://function.zip","description":"Lambda@Edge function for URL rewriting and header modification at CloudFront edge."},{"title":"CloudFront with S3 Origin (Static Site)","useCase":"Static site hosting with CloudFront.","code":"# 1. Create S3 bucket (must match domain name)\naws s3 mb s3://www.example.com --region us-east-1\n\n# 2. Upload static files\naws s3 sync ./build/ s3://www.example.com/\n\n# 3. Create CloudFront OAC\naws cloudfront create-origin-access-control \\\n  --origin-access-control-config '{\"Name\":\"my-oac\",\"Description\":\"\",\"SigningProtocol\":\"sigv4\",\"SigningBehavior\":\"always\",\"OriginAccessControlOriginType\":\"s3\"}'\n\n# 4. Create distribution (enable OAC)\n# 5. Update S3 bucket policy to allow CloudFront\naws s3api put-bucket-policy --bucket www.example.com --policy '{\"Version\":\"2012-10-17\",\"Statement\":[{\"Effect\":\"Allow\",\"Principal\":{\"Service\":\"cloudfront.amazonaws.com\"},\"Action\":\"s3:GetObject\",\"Resource\":\"arn:aws:s3:::www.example.com/*\",\"Condition\":{\"StringEquals\":{\"AWS:SourceArn\":\"arn:aws:cloudfront::123456789:distribution/E123456789ABCD\"}}}]}'\n\n# 6. Set Route53 alias to CloudFront domain","description":"Complete setup of static site with S3 + CloudFront + OAC."},{"title":"CloudFront Origin Failover","useCase":"Configuring origin groups for failover.","code":"# Create origin group with primary + secondary:\naws cloudfront update-distribution \\\n  --id E123456789ABCD \\\n  --distribution-config '{\n    \"OriginGroups\": {\n      \"Quantity\": 1,\n      \"Items\": [{\n        \"Id\": \"my-origin-group\",\n        \"FailoverCriteria\": { \"StatusCodes\": { \"Quantity\": 4, \"Items\": [500,502,503,504] } },\n        \"Members\": {\n          \"Quantity\": 2,\n          \"Items\": [\n            { \"OriginId\": \"primary-us-east-1\" },\n            { \"OriginId\": \"secondary-eu-west-1\" }\n          ]\n        }\n      }]\n    }\n  }'\n\n# When primary returns 5xx, CloudFront automatically\n# fails over to the secondary origin.\n# Seamless for end users.","description":"CloudFront origin group for automatic failover with status code monitoring."},{"title":"CloudFront Real-Time Logs","useCase":"Setting up real-time log streaming.","code":"# Enable real-time log configuration:\naws cloudfront create-realtime-log-config \\\n  --name \"cdn-logs\" \\\n  --sampling-rate 100 \\\n  --end-point '{\n    \"StreamType\": \"Kinesis\",\n    \"KinesisStreamConfig\": {\n      \"RoleArn\": \"arn:aws:iam::123456789:role/cloudfront-logs\",\n      \"StreamArn\": \"arn:aws:kinesis:us-east-1:123456789:stream/cdn-logs\"\n    }\n  }' \\\n  --fields \"timestamp, c-ip, sc-status, cs-uri-stem, cs-user-agent, x-edge-location, cs-referer, sc-content-type, sc-content-len\"\n\n# Attach to distribution behavior:\naws cloudfront update-distribution \\\n  --id E123456789ABCD \\\n  --default-cache-behavior \"RealtimeLogConfigArn=arn:aws:cloudfront::123456789:realtime-log-config/cdn-logs\"","description":"CloudFront real-time log configuration with Kinesis stream for monitoring."}],"mcqQuestions":[{"question":"What is AWS CloudFront?","options":["AWS DNS service","AWS CDN service","AWS compute service","AWS storage service"],"answer":1,"explanation":"CloudFront is AWS\\'s content delivery network service."},{"question":"How many edge locations does CloudFront have?","options":["100","250","450+","1000+"],"answer":2,"explanation":"CloudFront has 450+ edge locations in 90+ cities."},{"question":"What is Lambda@Edge?","options":["AWS Lambda for edge compute","AWS Lambda for serverless","Edge caching","Edge DNS"],"answer":0,"explanation":"Lambda@Edge runs serverless functions at CloudFront edge locations."},{"question":"What is CloudFront OAC?","options":["Origin Access Control for S3","Origin authentication","Access control list","Origin audit"],"answer":0,"explanation":"OAC restricts S3 access to CloudFront only."},{"question":"What is Origin Shield?","options":["DDoS protection","Additional caching layer","WAF service","DNS service"],"answer":1,"explanation":"Origin Shield is an additional caching layer."},{"question":"What does PriceClass_100 mean?","options":["100 edge locations","US and Europe only (cheapest)","All locations","100 cheapest locations"],"answer":1,"explanation":"PriceClass_100 uses only US/Europe edge locations."}]};
TOPICS_DATA["cdn"]["cdn-azure-cdn"] = {"id":"cdn-azure-cdn","title":"Azure CDN","difficulty":"beginner","estimatedMinutes":15,"tldr":["Azure CDN is Microsoft's content delivery network service, integrated with Azure services. It offers multiple product tiers: Azure CDN Standard (Microsoft), Standard (Akamai), Standard/Premium (Verizon).","Key features: global edge network (Microsoft: 200+ PoPs, Akamai: 2500+, Verizon: 150+), integration with Azure services (Blob Storage, Web Apps, Media Services), custom rules engine, and DDoS protection.","Azure CDN supports dynamic site acceleration (DSA), media streaming optimization, large file optimization, and HTTPS custom domains with managed certificates.","Pricing is pay-as-you-use with regional tiering. Each tier has different features, performance characteristics, and pricing."],"laymanDefinition":"Azure CDN is like Microsoft's answer to fast content delivery, offering a choice of delivery partners: Microsoft's own integrated network, Akamai's massive global network, or Verizon's reliable infrastructure. You choose your delivery fleet based on your needs and budget.","deepDive":[{"heading":"Azure CDN Product Tiers","text":"Microsoft Standard: 200+ PoPs, integrated with Azure, rules engine. Akamai Standard: 2500+ PoPs, best for media streaming, DSA. Verizon Standard: 150+ PoPs, large file optimization. Verizon Premium: advanced rules engine, analytics, custom reporting."},{"heading":"Rules Engine (Verizon Premium, Microsoft)","text":"URL redirects, rewrites, header modification, cache behavior overrides, compression controls, protocol restrictions. Order-based rule processing. Conditions: URL path, query string, request header, request method, device type, country code."},{"heading":"Dynamic Site Acceleration (DSA)","text":"Route optimization for dynamic/noncacheable content. TCP optimizations, route prefetch, performance monitoring. Available on Akamai tier. Reduces latency for dynamic content by 10-30% via optimized routing."},{"heading":"Azure Integration","text":"Azure Blob Storage origin: direct CDN integration. Azure Web Apps: CDN with custom domain, HTTPS. Azure Media Services: streaming endpoints. CDN endpoint management through Azure Portal, CLI, PowerShell, ARM templates."},{"heading":"Security Features","text":"Geo-filtering: restrict by country. Token authentication: time-limited access. HTTPS: custom domains with Free TLS/SSL (Microsoft-managed or bring your own). DDoS protection: Azure DDoS Basic included. WAF: available with Azure Front Door (modern alternative)."}],"interviewAnswer":"Azure CDN offers three tiers (Microsoft, Akamai, Verizon) integrated with Azure services. Features include rules engine, DSA, geo-filtering, token auth, and HTTPS custom domains. Choose tier based on feature needs, performance, and budget.","interviewQuestions":[{"question":"What are the tiers of Azure CDN?","answer":"Microsoft Standard, Akamai Standard, Verizon Standard, Verizon Premium."},{"question":"How many PoPs does Azure CDN Microsoft tier have?","answer":"200+ PoPs globally."},{"question":"What is DSA in Azure CDN?","answer":"Dynamic Site Acceleration for optimizing non-cacheable dynamic content."},{"question":"What is the Azure CDN rules engine?","answer":"Rules for URL redirect, header modification, cache override (Verizon Premium/Microsoft)."},{"question":"What Azure services can be CDN origins?","answer":"Blob Storage, Web Apps, Media Services, Cloud Services."},{"question":"How does geo-filtering work?","answer":"Allowing or blocking traffic based on country code at the CDN edge."},{"question":"What is token authentication?","answer":"Time-limited access with cryptographic tokens (Verizon tier)."},{"question":"Does Azure CDN support custom domain HTTPS?","answer":"Yes, with managed TLS/SSL certificates (free)."},{"question":"What is Azure Front Door?","answer":"Modern global load balancer + CDN + WAF (successor to traditional CDN)."},{"question":"What is the largest Azure CDN network?","answer":"Akamai tier with 2500+ PoPs globally."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Azure CDN</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Tier: Microsoft</text><text x=\"65\" y=\"43\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">200+ PoPs, Rules eng</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ine</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Tier: Akamai</text><text x=\"65\" y=\"84\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">2500+ PoPs, DSA</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Tier: Verizon</text><text x=\"65\" y=\"114\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">150+ PoPs, Premium</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"140\" height=\"75\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"230\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Azure CDN</text><text x=\"230\" y=\"82\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Rules engine, geo-filteri</text><text x=\"230\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ng, token auth, DSA, HTTP</text><text x=\"230\" y=\"104\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">S custom domains.</text><line x1=\"300\" y1=\"70\" x2=\"350\" y2=\"50\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"300\" y1=\"70\" x2=\"350\" y2=\"90\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"360\" y=\"35\" width=\"100\" height=\"70\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"410\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Azure Origins</text><text x=\"410\" y=\"77\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Blob Storage, Web </text><text x=\"410\" y=\"88\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Apps, Media Servic</text><text x=\"410\" y=\"99\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">es</text><text x=\"240\" y=\"195\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Azure CDN: Three tiers (Microsoft, Akamai, Verizon</text><text x=\"240\" y=\"207\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">) with rules engine, DSA, geo-filtering, token aut</text><text x=\"240\" y=\"219\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">h, Azure integration.</text></svg>","codeExamples":[{"title":"Creating Azure CDN Endpoint (Portal)","useCase":"Azure CDN setup via Portal.","code":"# 1. Create CDN profile:\n#    Azure Portal -> CDN profiles -> Create\n#    Name: my-cdn-profile\n#    Pricing tier: Standard Microsoft / Standard Akamai / Standard Verizon\n#    Resource group: my-rg\n\n# 2. Create endpoint:\n#    CDN profile -> + Endpoint\n#    Name: my-endpoint\n#    Origin type: Storage / Web App / Custom origin\n#    Origin hostname: myblob.blob.core.windows.net\n#    Origin path: /static\n#    Optimized for: General web delivery / Video on demand / Large file / Dynamic site acceleration\n\n# 3. Endpoint URL: my-endpoint.azureedge.net\n#    Custom domain: cdn.example.com\n#    HTTPS: Enable (free managed TLS)","description":"Azure CDN profile and endpoint creation through Azure Portal with origin configuration."},{"title":"Azure CDN with Blob Storage (CLI)","useCase":"Azure CLI CDN setup.","code":"# Create storage account (origin)\naz storage account create --name mystoragecdn --resource-group my-rg --sku Standard_LRS --allow-blob-public-access true\n\n# Enable static website\naz storage blob service-properties update --account-name mystoragecdn --static-website --404-document 404.html --index-document index.html\n\n# Create CDN profile\naz cdn profile create --name my-cdn-profile --resource-group my-rg --sku Standard_Microsoft\n\n# Create CDN endpoint\naz cdn endpoint create --name my-endpoint --profile-name my-cdn-profile --resource-group my-rg --origin mystoragecdn.blob.core.windows.net --origin-host-header mystoragecdn.blob.core.windows.net\n\n# Enable custom domain HTTPS\naz cdn custom-domain enable-https --endpoint-name my-endpoint --profile-name my-cdn-profile --resource-group my-rg --name www-example-com","description":"Azure CLI commands for CDN with Blob Storage static website origin."},{"title":"Azure CDN Rules Engine (Microsoft)","useCase":"Creating cache rules.","code":"# Rule: Cache all images for 30 days\n# Via Azure Portal: CDN Endpoint -> Rules Engine -> Add Rule\n\n# Rule name: \"cache-images-long\"\n# Order: 1\n\n# If: Url Path Extension\n#   Value: .jpg\n#   Operator: Contains\n\n# Conditions (optional):\n#   Country Code: Not \"CN\"\n\n# Actions:\n#   Cache expiration: Override\n#   Set cache duration: 30 days\n#   Set cache behavior: Override origin\n\n# Save and the rule is processed at edge\n# Multiple rules are evaluated in order (lowest number first)\n# Rules engine is available on Microsoft and Verizon Premium tiers","description":"Azure CDN Microsoft tier rules engine configuration for image caching."},{"title":"Azure CDN Geo-Filtering","useCase":"Restricting content by country.","code":"# Geo-filtering via Azure Portal:\n# CDN Endpoint -> Geo-filtering -> Add Rule\n\n# Rule: Allow traffic only from US and Canada\n# Action: Allow\n# Country codes: US, CA\n# Path: /protected/*\n\n# Rule: Block all other countries\n# Action: Block\n# Country codes: *\n# Path: /protected/*\n\n# Via CLI:\naz cdn endpoint update --name my-endpoint --profile-name my-cdn-profile --resource-group my-rg --set geoFilters='[{\"relativePath\":\"/protected/*\",\"action\":\"Allow\",\"countryCodes\":[\"US\",\"CA\"]}]'\n\n# Geo-filtering is available on Verizon Premium\n# and Microsoft Standard tiers","description":"Azure CDN geo-filtering rules for allowing/blocking countries at edge."},{"title":"Azure CDN Token Authentication","useCase":"Time-limited access with tokens.","code":"# Token authentication is available on Verizon Premium tier\n# Steps:\n\n# 1. Generate encryption key (32 chars)\n# 2. Configure token auth in Azure Portal:\n#    Endpoint -> Token Authentication -> Configure\n#    Primary key: your-32-char-key\n#    Algorithm: SHA256\n\n# 3. Generate token URL:\n#    Token format:\n#    https://cdn.example.com/file.pdf?ec_expire=1712345678&ec_key=your-key&ec_hash=base64hash\n\n# 4. Server generates token (C# example):\n// string token = TokenAuth.GenerateToken(\n//     \"your-32-char-key\",\n//     \"/file.pdf\",\n//     DateTime.UtcNow.AddHours(1));\n\n# 5. CDN validates:\n#    - Hash matches (tamper check)\n#    - Expiration not passed\n#    - Returns 403 if invalid","description":"Azure CDN token authentication for time-limited content access on Verizon Premium."}],"mcqQuestions":[{"question":"What are the three Azure CDN tiers?","options":["Basic, Standard, Premium","Microsoft, Akamai, Verizon","Free, Pro, Enterprise","Lite, Standard, Pro"],"answer":1,"explanation":"Azure CDN tiers are Microsoft, Akamai, and Verizon."},{"question":"Which tier has the most PoPs?","options":["Microsoft (200+)","Akamai (2500+)","Verizon (150+)","Equal"],"answer":1,"explanation":"Akamai tier has 2500+ PoPs globally."},{"question":"What is DSA in Azure CDN?","options":["Data storage accelerator","Dynamic Site Acceleration","Direct server access","Data security appliance"],"answer":1,"explanation":"DSA is Dynamic Site Acceleration for non-cacheable content."},{"question":"Which Azure service is commonly used with CDN?","options":["Azure Functions","Blob Storage","Azure DevOps","Azure AD"],"answer":1,"explanation":"Azure Blob Storage is commonly used as CDN origin."},{"question":"What does geo-filtering do?","options":["Block by IP","Block by country","Block by user agent","Block by device"],"answer":1,"explanation":"Geo-filtering restricts content by country code."},{"question":"What is Azure Front Door?","options":["Older CDN product","Modern CDN + WAF + global load balancer","DNS service","Firewall service"],"answer":1,"explanation":"Azure Front Door is the modern successor combining CDN, WAF, and global load balancing."}]};
TOPICS_DATA["cdn"]["cdn-gcp-cdn"] = {"id":"cdn-gcp-cdn","title":"Google Cloud CDN","difficulty":"beginner","estimatedMinutes":15,"tldr":["Google Cloud CDN (Cloud CDN) uses Google's global infrastructure to deliver content with low latency. It integrates with Google Cloud Load Balancing and Google Kubernetes Engine.","Key features: 200+ edge PoPs on Google's network, integration with HTTP(S) Load Balancer, Cloud Storage origins, signed URLs/cookies, and WAF integration via Cloud Armor.","Cloud CDN is designed for applications hosted on Google Cloud (Compute Engine, GKE, Cloud Storage) and uses Google's private fiber network for content delivery.","Pricing: pay-as-you-go with per-GB egress and per-request charges. Cache egress is cheaper than origin egress. No upfront fees or commitments."],"laymanDefinition":"Google Cloud CDN is like having Google's private highway system deliver your content. Instead of taking public roads (public internet), your content travels on Google's own fiber network from the origin to the edge PoP, then the final mile to the user. It's only for content starting within Google Cloud, making it the fastest option for GCP-hosted apps.","deepDive":[{"heading":"Google\\'s Global Network","text":"200+ edge PoPs in 80+ countries. 100,000+ miles of fiber optic cable. Google\\'s network carries 40%+ of internet traffic. Private Tier 1 network means fewer hops. Low latency via B4 SDN network fabric and Google\\'s global backbone."},{"heading":"Cloud CDN Architecture","text":"Cloud CDN is built on Google Cloud HTTP(S) Load Balancer. It\\'s enabled as a checkbox, not a separate product. Integration with: Cloud Storage (cache buckets), Compute Engine (instance groups), GKE (container-native load balancing), and App Engine. Cache hits served from edge; misses go to origin via Google backbone."},{"heading":"Signed URLs and Cookies","text":"Cloud CDN supports signed URLs and signed cookies for time-limited, authenticated access. Uses HMAC-SHA1 or HMAC-SHA256 keys. Keys managed in Cloud Console or via Cloud KMS. Policy includes: URL prefix, expiration, IP ranges."},{"heading":"Cloud Armor (WAF + DDoS)","text":"Cloud Armor integrates with Cloud CDN for edge security. WAF: OWASP rules, SQLi/XSS detection, custom rules. DDoS: automatic L3/L4 protection, configurable L7 protection. Rate limiting: per IP, region, or header. Geo-based access control."},{"heading":"Cache Modes and Policies","text":"Cache modes: Use origin headers (respect Cache-Control), Force cache all (ignore Set-Cookie), Force cache all with origin headers override. Cache keys: protocol, host, query string parameters, headers. Negative caching (for error responses, 404, 500). TTL: minimum/maximum overrides."},{"heading":"Optimization Features","text":"Cache bypass on cookie: for personalized content. Cache hit ratio optimization via query parameter normalization. Compression: Cloud CDN compresses responses with gzip/brotli. Request collapsing: multiple same requests collapsed to one origin call. Negative caching: cache 404/500 responses to reduce origin load."}],"interviewAnswer":"Google Cloud CDN leverages Google's private fiber network for fast content delivery. Integrated with HTTP(S) Load Balancer, Cloud Storage, and GKE. Supports signed URLs/cookies, Cloud Armor WAF/DDoS, cache modes for flexibility, and request collapsing for efficient caching.","interviewQuestions":[{"question":"What is Google Cloud CDN?","answer":"Google\\'s CDN built on their global network, integrated with GCP load balancers."},{"question":"How many edge PoPs does Cloud CDN have?","answer":"200+ globally on Google\\'s private network."},{"question":"What is unique about Google\\'s network?","answer":"Private Tier 1 fiber network — content stays on Google backbone."},{"question":"What is Cloud Armor?","answer":"Google\\'s WAF and DDoS protection service integrated with Cloud CDN."},{"question":"What origins does Cloud CDN support?","answer":"Cloud Storage, Compute Engine, GKE, App Engine, HTTP(S) Load Balancer."},{"question":"What is request collapsing?","answer":"Multiple same requests collapsed to one origin call at the same edge."},{"question":"What algorithms does Cloud CDN signing use?","answer":"HMAC-SHA1 and HMAC-SHA256."},{"question":"What is cache bypass on cookie?","answer":"Skip cache for requests with specific cookies (personalized content)."},{"question":"Does Cloud CDN support compression?","answer":"Yes, gzip and brotli compression at edge."},{"question":"How is Cloud CDN priced?","answer":"Pay-as-you-go: per-GB egress + per-request fees. Cache egress cheaper than origin."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Google Cloud CDN</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">User</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Browser</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"225\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CDN Edge</text><text x=\"225\" y=\"43\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">200+ PoPs on Google fib</text><text x=\"225\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">er</text><line x1=\"290\" y1=\"48\" x2=\"320\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"330\" y=\"35\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"395\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cloud Armor</text><text x=\"395\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">WAF + DDoS protection</text><line x1=\"460\" y1=\"48\" x2=\"480\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"490\" y=\"35\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"540\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">LB</text><text x=\"540\" y=\"43\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">HTTP(S) Load Balan</text><text x=\"540\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">cer</text><line x1=\"590\" y1=\"48\" x2=\"320\" y2=\"70\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"75\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1.5\"/><text x=\"225\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cloud Storage</text><text x=\"225\" y=\"94\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Bucket origin</text><rect x=\"300\" y=\"75\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"365\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GKE/Compute</text><text x=\"365\" y=\"94\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Instance group origin</text><rect x=\"440\" y=\"75\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"505\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">App Engine</text><text x=\"505\" y=\"94\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">App origin</text><text x=\"240\" y=\"195\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Google Cloud CDN: Google private fiber network + C</text><text x=\"240\" y=\"207\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">loud Armor WAF + Load Balancer + GCP origins.</text></svg>","codeExamples":[{"title":"Enabling Cloud CDN via gcloud","useCase":"Setup Cloud CDN on a backend service.","code":"# 1. Create an external HTTP(S) Load Balancer\n#    (or use existing one)\n\n# 2. Create backend bucket (Cloud Storage origin)\ngcloud compute backend-buckets create my-backend-bucket \\\n  --gcs-bucket-name=my-bucket --enable-cdn\n\n# Or enable CDN on existing backend service:\ngcloud compute backend-services update my-service \\\n  --enable-cdn --cache-mode=FORCE_CACHE_ALL\n\n# Cache modes:\n#   USE_ORIGIN_HEADERS (default, respects Cache-Control)\n#   FORCE_CACHE_ALL (cache everything, ignore Set-Cookie)\n#   FORCE_CACHE_ALL_ORIGIN_HEADERS (cache all, respect origin headers)\n\n# 3. Create URL map and target proxy\ngcloud compute url-maps create my-url-map \\\n  --default-backend-bucket=my-backend-bucket","description":"gcloud commands to enable Cloud CDN on a backend bucket or service."},{"title":"Cloud CDN Signed URL Generation","useCase":"Generate HMAC-signed URLs for Cloud CDN.","code":"# 1. Create signing key:\ngcloud compute backend-services add-signed-url-key my-service \\\n  --key-name my-key --key-file ./cdn.key\n\n# 2. Generate random HMAC key (32 bytes):\nopenssl rand 32 > cdn.key\n\n# 3. Generate signed URL (Python example):\nimport base64, hashlib, hmac, time\n\nkey = open(\"cdn.key\", \"rb\").read()\nurl_prefix = \"https://cdn.example.com/private/\"\nexpires = int(time.time()) + 3600\n\n# Create signature input:\nsign_input = f\"{url_prefix}{expires}\"\n\n# Sign with HMAC-SHA256:\nsig = hmac.new(key, sign_input.encode(), hashlib.sha256).digest()\nsig_b64 = base64.urlsafe_b64encode(sig).rstrip(b\"=\").decode()\n\n# Signed URL:\nsigned_url = f\"{url_prefix}?Expires={expires}&KeyName=my-key&Signature={sig_b64}\"","description":"Cloud CDN signed URL generation with HMAC-SHA256 and gcloud key setup."},{"title":"Cloud Armor WAF Policy","useCase":"Create Cloud Armor security policy.","code":"# Create security policy:\ngcloud compute security-policies create my-waf-policy\n\n# Add rule: Block SQL injection\ngcloud compute security-policies rules create 1000 \\\n  --action=deny-403 \\\n  --security-policy=my-waf-policy \\\n  --expression='evaluatePreconfiguredWaf(\"sqli-canary\")\n\n# Add rule: Rate limit per IP (100 req/min)\ngcloud compute security-policies rules create 500 \\\n  --action=rate-based-ban \\\n  --security-policy=my-waf-policy \\\n  --rate-limit-threshold-count=100 \\\n  --rate-limit-threshold-interval-sec=60 \\\n  --conform-action=allow \\\n  --exceed-action=deny-429 \\\n  --expression='true' \\\n\n# Attach to backend service:\ngcloud compute backend-services update my-service \\\n  --security-policy=my-waf-policy","description":"Cloud Armor WAF policy with SQL injection and rate limiting rules attached to backend service."},{"title":"Cloud CDN Cache Invalidation","useCase":"How to purge cached content.","code":"# Invalidate specific URLs:\ngcloud compute url-maps invalidate-cdn-cache my-url-map \\\n  --path \"/images/*\" --async\n\n# Invalidate multiple paths:\nfor path in \"/images/*\" \"/css/*\" \"/js/*\"; do\n  gcloud compute url-maps invalidate-cdn-cache my-url-map --path \"$path\" --async\ndone\n\n# Invalidate all cached content (host-wide):\ngcloud compute url-maps invalidate-cdn-cache my-url-map \\\n  --path \"/*\"\n\n# Cache invalidation limits:\n# - 1000 invalidations per URL map per month (free)\n# - Additional invalidations are billed\n# - Invalidation propagates to all edges within minutes","description":"Cloud CDN cache invalidation commands for purging cached content."},{"title":"Cloud CDN Request Collapsing","useCase":"How request collapsing reduces origin load.","code":"# Request collapsing is enabled by default on Cloud CDN\n\n# Scenario: 100 users request the same uncached resource\n# Without collapsing: 100 requests hit the origin\n# With collapsing: 1 request hits the origin\n\n# How it works:\n# 1. First request for resource arrives at edge\n# 2. Edge forwards to origin (cache miss)\n# 3. While waiting for origin, additional same requests arrive\n# 4. Edge waits for first request to complete\n# 5. All 100 users get response from the single origin call\n\n# Benefits:\n# - Reduces origin load significantly\n# - Improves overall latency for subsequent users\n# - No additional configuration needed","description":"Cloud CDN request collapsing mechanism for reducing origin load on cache misses."}],"mcqQuestions":[{"question":"What is Google Cloud CDN built on?","options":["Cloud Functions","HTTP(S) Load Balancer","Cloud Run","Cloud Storage"],"answer":1,"explanation":"Cloud CDN is built on the HTTP(S) Load Balancer."},{"question":"How is Google\\'s network unique?","options":["Largest CDN","Private Tier 1 fiber network","Cheapest CDN","Oldest CDN"],"answer":1,"explanation":"Google\\'s private fiber network reduces hops and latency."},{"question":"What is Cloud Armor?","options":["Cloud storage","WAF + DDoS protection","Load balancer","DNS service"],"answer":1,"explanation":"Cloud Armor provides WAF and DDoS protection for Cloud CDN."},{"question":"What signing algorithms does Cloud CDN support?","options":["RSA-SHA1","HMAC-SHA1 and HMAC-SHA256","AES256","MD5"],"answer":1,"explanation":"Cloud CDN uses HMAC-SHA1 or HMAC-SHA256 for signed URLs."},{"question":"What is request collapsing?","options":["Serving stale content","Merging same requests to one origin call","Compressing requests","Caching requests"],"answer":1,"explanation":"Request collapsing merges multiple same requests into one origin call."},{"question":"What is a cache mode?","options":["Cache layer","How CDN decides what to cache","Cache location","Cache size"],"answer":1,"explanation":"Cache modes control caching behavior (respect origin, force cache, etc)."}]};
TOPICS_DATA["cdn"]["cdn-fastly"] = {"id":"cdn-fastly","title":"Fastly","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Fastly is a high-performance CDN known for its programmable edge via Varnish Configuration Language (VCL) and edge compute platform (Compute@Edge).","Key features: instant cache purge (full cache in <150ms), VCL-based edge logic, Compute@Edge (Rust/JS), image optimization, real-time analytics, and DDoS protection.","Fastly's architecture is based on a modified Varnish cache, giving customers unprecedented control over request/response processing at the edge.","Fastly is preferred for dynamic content, API acceleration, and use cases requiring fine-grained edge logic control."],"laymanDefinition":"Fastly is like a programmable delivery drone. While other CDNs give you preset routes and options, Fastly lets you write your own flight instructions (VCL) for every package. Want boxes to fly differently at night? Want special handling for fragile items? You can program it all yourself.","deepDive":[{"heading":"VCL (Varnish Configuration Language)","text":"Fastly\\'s core differentiator. Subroutines: vcl_recv (incoming request), vcl_fetch (from origin), vcl_deliver (to client), vcl_error (error handling), vcl_hash (cache key), vcl_pass (skip cache), vcl_pipe (streaming), vcl_log (logging), vcl_synth (synthetic response). Full traffic manipulation flexibility."},{"heading":"Instant Purge","text":"Cache invalidation across all edge nodes in <150 milliseconds (typically 30-50ms). Soft purge: mark stale, serve stale while fetching new. Hard purge: remove from cache immediately. Purge by URL, surrogate key (tag-based), or service-wide. Streaming purge validation."},{"heading":"Compute@Edge","text":"Serverless at edge with Rust (primary), JavaScript, AssemblyScript, Go. Compiles to WebAssembly. Sub-millisecond cold starts. Access to Fastly cache. Use cases: API gateways, authentication, image processing, A/B testing. Faster than Lambda@Edge for Rust workloads."},{"heading":"Image Optimization","text":"Server-side image transformation at edge. Resize, crop, format conversion (WebP, AVIF), quality adjustment, compression. Sentinels: detect optimal image format from browser Accept header. DPR handling (device pixel ratio). Real-time transformation via URL parameters."},{"heading":"DDoS and Security","text":"DDoS: automatic L3/L4 mitigation, L7 rate limiting, software load balancers absorb attacks. WAF: Signal Sciences (Fastly acquired) — ML-based. TLS: custom certificates, automated renewal. Access control: IP blacklist/whitelist, basic auth at edge. Secret Store: secure key management."}],"interviewAnswer":"Fastly is a programmable CDN with VCL-based edge logic, instant cache purge (<150ms), Compute@Edge (WebAssembly), image optimization, and real-time analytics. It offers deep configurability for dynamic content and API acceleration.","interviewQuestions":[{"question":"What is Fastly known for?","answer":"Programmable edge with VCL, instant purge, Compute@Edge."},{"question":"What is VCL?","answer":"Varnish Configuration Language — Fastly\\'s edge programming language."},{"question":"How fast is Fastly\\'s cache purge?","answer":"<150ms (typically 30-50ms) across all edge nodes."},{"question":"What is Compute@Edge?","answer":"Fastly\\'s serverless edge compute platform using WebAssembly (Rust, JS, Go)."},{"question":"What is a surrogate key?","answer":"Tags for cache objects allowing tag-based purging."},{"question":"What is soft purge?","answer":"Marking cache as stale but serving while fetching fresh content."},{"question":"What is Sentinel in image optimization?","answer":"Feature detecting optimal image format from browser Accept header."},{"question":"What WAF does Fastly offer?","answer":"Signal Sciences (acquired by Fastly) — ML-based WAF."},{"question":"What is Fastly\\'s origin?","answer":"Former Varnish developers, founded 2011."},{"question":"What is Fastly\\'s Instant Purge API?","answer":"API to purge cache by URL, key, or service in <150ms."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Fastly</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">User</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Request</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"225\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Edge Node</text><text x=\"225\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">VCL processing</text><line x1=\"290\" y1=\"48\" x2=\"320\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"330\" y=\"35\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"395\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Compute@Edge</text><text x=\"395\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">WebAssembly</text><line x1=\"460\" y1=\"48\" x2=\"480\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"490\" y=\"35\" width=\"100\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"540\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Origin</text><text x=\"540\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Dynamic content</text><text x=\"240\" y=\"180\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Fastly: Programmable CDN with VCL, instant purge (</text><text x=\"240\" y=\"192\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\"><150ms), Compute@Edge (WASM), Signal Sciences WAF.</text></svg>","codeExamples":[{"title":"Fastly VCL Cache Override","useCase":"Custom caching logic with VCL.","code":"sub vcl_recv {\n  # Cache API responses for 1 hour\n  if (req.url ~ \"^/api/\") {\n    set req.ttl = 3600s;\n    set req.grace = 86400s;\n  }\n\n  # Bypass cache for admin\n  if (req.url ~ \"^/admin/\") {\n    set req.http.X-Cache-Type = \"pass\";\n    return(pass);\n  }\n\n  # Remove cookies from static assets (better caching)\n  if (req.url ~ \"\\.(css|js|png|jpg|svg|woff2)$\") {\n    unset req.http.Cookie;\n  }\n}\n\nsub vcl_deliver {\n  # Add debug headers\n  if (fastly.ff.visits_this_service == 0) {\n    set resp.http.X-Cache = \"MISS\";\n  } else {\n    set resp.http.X-Cache = \"HIT\";\n  }\n}","description":"Fastly VCL for custom cache TTL, admin bypass, cookie stripping, and debug headers."},{"title":"Fastly Surrogate Key Purging","useCase":"Tag-based cache purging.","code":"# Backend sets Surrogate-Key headers:\nsurrogate_key: \"article:123 category:tech author:456\"\n\n# Client receives header (hidden via VCL):\n# set resp.http.Surrogate-Key = req.http.Surrogate-Key;\n\n# Purge by key via API:\ncurl -X POST \"https://api.fastly.com/service/$SERVICE_ID/purge/article:123\" \\\n  -H \"Fastly-Key: $API_TOKEN\"\n\n# Purge multiple keys:\ncurl -X POST \"https://api.fastly.com/service/$SERVICE_ID/purge\" \\\n  -H \"Fastly-Key: $API_TOKEN\" \\\n  -H \"Surrogate-Key: article:123 category:tech\"\n\n# Purge all:\ncurl -X POST \"https://api.fastly.com/service/$SERVICE_ID/purge_all\" \\\n  -H \"Fastly-Key: $API_TOKEN\"","description":"Fastly surrogate key purging for tag-based cache invalidation."},{"title":"Compute@Edge (Rust)","useCase":"Basic Compute@Edge service.","code":"// Cargo.toml\n[package]\nname = \"hello-fastly\"\nversion = \"0.1.0\"\n\n[dependencies]\nfastly = \"^0.10\"\n\n// src/main.rs\nuse fastly::{{Request, Response}};\n\n#[fastly::main]\nfn main(req: Request) -> Response {\n    let country = req.get_client_ip_addr();\n    let path = req.get_path();\n\n    // Redirect based on user agent\n    let ua = req.get_header_str(\"User-Agent\").unwrap_or(\"\");\n    if ua.contains(\"Mobile\") {\n        return Response::from_status(302)\n            .with_header(\"Location\", format!(\"/mobile{path}\"));\n    }\n\n    // Fetch from origin or generate synthetic response\n    let backend = format!(\"backend_{}\", req.get_url().host_str().unwrap_or(\"default\"));\n    let beresp = req.send(backend).unwrap();\n    beresp\n}","description":"Fastly Compute@Edge in Rust with redirects and backend forwarding."},{"title":"Fastly Image Optimization","useCase":"On-the-fly image transformation.","code":"# Image optimization via URL parameters:\n# /image.jpg?width=400&height=300&format=webp&quality=80\n\n# VCL to enable image optimization:\nsub vcl_recv {\n  if (req.url ~ \"\\.(jpg|jpeg|png|gif|webp)$\") {\n    set req.http.X-Fastly-Imageopto-Auto = \"webp\";\n    set req.http.X-Fastly-Imageopto-Resize = \"400x300\";\n  }\n}\n\n# OR use query parameters:\n# ?width=400 (max width)\n# ?height=300 (max height)\n# ?format=webp|jpeg|png|avif (format conversion)\n# ?quality=1-100 (compression quality)\n# ?crop=1600,900 (crop dimensions)\n\n# Auto format selection via Sentinel:\n# Browser sends Accept: image/avif,image/webp\n# Fastly serves best format automatically","description":"Fastly image optimization with VCL and URL parameter configuration."},{"title":"Fastly Real-Time Log Streaming","useCase":"Streaming logs to external destinations.","code":"# Create logging endpoint via API:\ncurl -X POST \"https://api.fastly.com/service/$SERVICE_ID/version/$VERSION/logging/s3\" \\\n  -H \"Fastly-Key: $API_TOKEN\" \\\n  -d '{\n    \"name\": \"cdn-logs\",\n    \"bucket_name\": \"my-cdn-logs\",\n    \"domain\": \"s3.us-east-1.amazonaws.com\",\n    \"path\": \"/cdn/\",\n    \"format\": \"%{now:%Y-%m-%dT%H:%M:%S%z}t\\t%h\\t%m\\t%U\\t%s\\t%D\",\n    \"period\": 3600,\n    \"gzip_level\": 3\n  }'\n\n# Log format variables:\n# %h — client IP\n# %m — request method\n# %U — URL path\n# %s — status code\n# %D — response time (microseconds)\n# %{Cookie}i — request header\n\n# Supported destinations:\n# S3, GCS, Azure Blob, BigQuery, Elasticsearch,\n# Splunk, Datadog, Sumo Logic, New Relic, Kafka","description":"Fastly real-time log streaming configuration to S3 with format customization."}],"mcqQuestions":[{"question":"What is Fastly known for?","options":["Cheapest CDN","Programmable edge with VCL","Largest CDN","Free CDN"],"answer":1,"explanation":"Fastly is known for its programmable VCL-based edge."},{"question":"How fast is Fastly\\'s cache purge?","options":["1 second","<150ms","5 minutes","Instant"],"answer":1,"explanation":"Fastly purges cache in <150ms across all edges."},{"question":"What is VCL?","options":["Fast, Very CLI","Varnish Configuration Language","Very Complex Logic","Virtual Cache Layer"],"answer":1,"explanation":"VCL is Varnish Configuration Language."},{"question":"What is Compute@Edge?","options":["Edge computing with VCL","WebAssembly-based serverless at edge","Edge cache","Edge DNS"],"answer":1,"explanation":"Compute@Edge runs WebAssembly at the edge using Rust/JS/Go."},{"question":"What is a surrogate key?","options":["Backup cache","Tag for cache object purging","SSL key","API key"],"answer":1,"explanation":"Surrogate keys are tags used for targeted cache purging."},{"question":"What WAF did Fastly acquire?","options":["Cloudflare WAF","Signal Sciences","AWS WAF","PerimeterX"],"answer":1,"explanation":"Fastly acquired Signal Sciences for ML-based WAF."}]};
TOPICS_DATA["cdn"]["cdn-akamai"] = {"id":"cdn-akamai","title":"Akamai","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Akamai is one of the largest and most established CDN providers, founded in 1998 at MIT. It has the most globally distributed edge platform with 4000+ PoPs in 135+ countries.","Key features: 4000+ edge servers, enterprise-grade security (Kona Site Defender, DDoS), media delivery optimization (Adaptive Media Delivery), Image & Video Manager, and sophisticated traffic management.","Akamai operates a massively distributed network with servers embedded within ISPs, providing superior last-mile performance. It is the CDN of choice for large enterprises and media companies.","Akamai uses a DNS-based routing system (not Anycast) with real-time mapping to direct users to the optimal edge server."],"laymanDefinition":"Akamai is the \"veteran\" of the CDN world. Think of it as a delivery network with the largest number of local depots (4000+ PoPs), many tucked inside neighborhoods (ISPs). When a package needs delivering, it checks real-time traffic, road conditions, and depot capacity to choose the best route.","deepDive":[{"heading":"Akamai Intelligent Edge Platform","text":"4000+ PoPs in 135+ countries, embedded in 1600+ ISPs. DNS-based traffic management with real-time mapping. Proprietary SureRoute technology optimizes paths. Edge servers are at the last mile, reducing final latency."},{"heading":"Traffic Management","text":"DNS-based (not Anycast): Akamai\\'s authoritative DNS returns optimal edge server IP. Factors: geographic distance, server load, network health, cache availability. FastDNS: managed authoritative DNS. Global Traffic Management (GTM): load balancing across origins."},{"heading":"Security (Kona Site Defender)","text":"WAF: OWASP CRS, custom rules, positive security model. DDoS: L3/L4/L7 mitigation, edge-based scrubbing. Bot Manager: categorize bots (good/bad), challenge suspicious. Web App Protector: client-side integrity (detect tampering/automation). API Security: protect API endpoints."},{"heading":"Media Delivery Solutions","text":"Adaptive Media Delivery: optimized video streaming, adaptive bitrate. Broadcast Operations Control Center (BOCC): 24/7 monitoring. Media Services Live: live streaming. Download Delivery: large file optimization. Multi-CDN support."},{"heading":"Image & Video Manager","text":"Server-side media transformation. Resize, crop, rotate, format (WebP, AVIF), compression. Policy-based: define transformations as named policies. On-the-fly: transform via URL parameters. Responsive images: auto-generate multiple sizes. Device detection: optimal format per device."},{"heading":"Property Manager (Configuration)","text":"Akamai\\'s configuration interface. Rules-based behaviors: cache, origin, security, performance. Rule trees with match criteria (path, header, cookie, device, geolocation). Behaviors: modify requests, responses at edge. Versioned configuration with activation workflow."}],"interviewAnswer":"Akamai is the largest CDN with 4000+ edge PoPs in 135+ countries. Uses DNS-based routing with real-time mapping. Enterprise security via Kona Site Defender. Optimized for media delivery. Image & Video Manager for transformations. Property Manager for rule-based configuration.","interviewQuestions":[{"question":"How many PoPs does Akamai have?","answer":"4000+ PoPs in 135+ countries, embedded in 1600+ ISPs."},{"question":"What is unique about Akamai\\'s routing?","answer":"DNS-based routing with real-time mapping (not Anycast)."},{"question":"What is Kona Site Defender?","answer":"Akamai\\'s enterprise security suite with WAF, DDoS, bot management."},{"question":"What is Akamai\\'s Image & Video Manager?","answer":"Server-side media transformation with policy-based and on-the-fly options."},{"question":"What is Property Manager?","answer":"Akamai\\'s rule-based configuration interface for CDN behaviors."},{"question":"What is SureRoute?","answer":"Akamai\\'s proprietary route optimization technology for dynamic content."},{"question":"What is Adaptive Media Delivery?","answer":"Akamai\\'s optimized video streaming with adaptive bitrate support."},{"question":"What is the BOCC?","answer":"Broadcast Operations Control Center — 24/7 media monitoring."},{"question":"How does Akamai handle traffic management?","answer":"DNS-based: authoritative DNS returns optimal edge server based on real-time mapping."},{"question":"What is Bot Manager?","answer":"Akamai\\'s bot detection and management — categorizes good/bad bots."}],"diagramSvg":"<svg viewBox=\"0 0 500 300\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><defs><marker id=\"arrow\" viewBox=\"0 0 10 10\" refX=\"9\" refY=\"5\" markerWidth=\"8\" markerHeight=\"8\" orient=\"auto\"><path d=\"M0,0 L10,5 L0,10\" fill=\"#666\" opacity=\"0.7\"/></marker></defs><rect x=\"0\" y=\"0\" width=\"500\" height=\"300\" rx=\"10\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"28\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Akamai</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"5\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1.5\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">User</text><text x=\"65\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Browser</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1.5\"/><text x=\"225\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DNS Mapping</text><text x=\"225\" y=\"43\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Real-time: Akamai autho</text><text x=\"225\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ritative DNS</text><line x1=\"290\" y1=\"48\" x2=\"320\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"330\" y=\"35\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1.5\"/><text x=\"395\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Optimal Edge</text><text x=\"395\" y=\"43\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">4000+ PoPs, 135 countri</text><text x=\"395\" y=\"54\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">es, embedded in ISPs</text><line x1=\"460\" y1=\"48\" x2=\"320\" y2=\"70\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"75\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1.5\"/><text x=\"225\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Kona Site Defender</text><text x=\"225\" y=\"83\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">WAF + DDoS + Bot Manage</text><text x=\"225\" y=\"94\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">r</text><rect x=\"300\" y=\"75\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1.5\"/><text x=\"365\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Media Optim</text><text x=\"365\" y=\"94\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Adaptive Media Delivery</text><rect x=\"440\" y=\"75\" width=\"130\" height=\"25\" rx=\"5\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1.5\"/><text x=\"505\" y=\"91\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Image Manager</text><text x=\"505\" y=\"83\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Policy-based + on-the-f</text><text x=\"505\" y=\"94\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ly</text><text x=\"240\" y=\"195\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Akamai: 4000+ PoPs, DNS-based routing, Kona securi</text><text x=\"240\" y=\"207\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">ty, media delivery, image/video optimization.</text></svg>","codeExamples":[{"title":"Akamai Property Manager Rule","useCase":"Creating cache rules in Property Manager.","code":"# Akamai Property Manager (web console):\n# Create a new property or edit existing\n\n# Rule: Cache static assets for 30 days\n# Match: Path matches (*.css, *.js, *.jpg, *.png, *.svg)\n# Behavior: Caching ->\n#   \"Cache HTTP error responses\": 10s\n#   \"Caching\": \"Force Freshness\"\n#   \"Max Age\": \"30 days\"\n#   \"Enable Must-Revalidate\": true\n\n# Rule: Origin server configuration\n# Behavior: Origin Server ->\n#   \"Origin Server Hostname\": origin.example.com\n#   \"Forward Host Header\": origin.example.com\n#   \"SSL Verify\": true\n\n# Rule: Compress responses\n# Behavior: Response Compression ->\n#   \"Compress\": true\n#   \"Content Types\": text/*, application/json, application/javascript","description":"Akamai Property Manager rules for caching, origin, and compression configuration."},{"title":"Akamai Image Manager Policy","useCase":"Define image transformation policy.","code":"# Akamai Image Manager Policy (JSON):\n{\n  \"policy\": \"my-image-policy\",\n  \"breakpoints\": [320, 640, 1024, 1920],\n  \"output\": {\n    \"format\": \"best\",  // auto-select WebP/AVIF\n    \"quality\": 85,\n    \"compression\": \"auto\"\n  },\n  \"transformations\": [\n    { \"type\": \"resize\", \"width\": \"{{breakpoint}}\", \"height\": \"{{breakpoint * 0.75}}\" },\n    { \"type\": \"crop\", \"width\": 1920, \"height\": 1080, \"gravity\": \"center\" }\n  ]\n}\n\n# Apply in Property Manager:\n# Behavior: Image & Video Manager ->\n#   \"Apply to\": Png, Jpg, Gif, Webp\n#   \"Image Policy\": my-image-policy\n#   \"Video Policy\": my-video-policy (optional)\n\n# On-the-fly URL:\n# /image.jpg?imwidth=400&imformat=webp","description":"Akamai Image Manager policy definition for automatic responsive image transformations."},{"title":"Akamai API (PAPI) Configuration","useCase":"Managing Akamai via API.","code":"# Akamai Property Manager API (PAPI):\n\n# List properties:\ncurl -s \"https://akab-xxxx.luna.akamaiapis.net/papi/v1/properties?contractId=ctr_X&groupId=grp_X\" \\\n  -H \"Authorization: Bearer $AKAMAI_TOKEN\"\n\n# Get property version:\ncurl -s \"https://akab-xxxx.luna.akamaiapis.net/papi/v1/properties/prp_X/versions/latest\" \\\n  -H \"Authorization: Bearer $AKAMAI_TOKEN\"\n\n# Update property rule tree:\ncurl -X PUT \"https://akab-xxxx.luna.akamaiapis.net/papi/v1/properties/prp_X/versions/2/rules\" \\\n  -H \"Authorization: Bearer $AKAMAI_TOKEN\" \\\n  -H \"Content-Type: application/json\" \\\n  -d @updated-rules.json\n\n# Activate property:\ncurl -X POST \"https://akab-xxxx.luna.akamaiapis.net/papi/v1/properties/prp_X/activations\" \\\n  -H \"Authorization: Bearer $AKAMAI_TOKEN\" \\\n  -d '{\"network\": \"STAGING\", \"version\": 2, \"note\": \"Activating v2\"}'","description":"Akamai Property Manager API for listing, updating, and activating CDN configurations."},{"title":"Akamai Kona WAF Rule","useCase":"Configuring Akamai WAF rules.","code":"# Kona Site Defender WAF configuration:\n# Security Center -> WAF -> Custom Rules\n\n# Rule: Block SQL injection in URL\n# Rule Name: \"Block SQLi in URI\"\n# Match: URL Path contains (select|union|drop|delete|insert)\n# Action: Deny with 403\n# Log: true\n\n# Rule: Rate limit login\n# Rule Name: \"Rate Limit Login\"\n# Match: URL Path = /login\n# Rate: 10 requests per minute per IP\n# Action: Deny with 429\n# Challenge: CAPTCHA (optional)\n\n# Rule: Geo-allow (whitelist country)\n# Match: Country = US\n# Action: Allow\n\n# Bot Manager categories:\n# - Allow: Googlebot, Bingbot (verified bots)\n# - Monitor: unknown search engines\n# - Deny: scrapers, bad bots, suspicious","description":"Akamai Kona Site Defender WAF custom rules for SQL injection, rate limiting, and geo-filtering."},{"title":"Akamai Multi-CDN Configuration","useCase":"Setting up multiple CDNs with Akamai.","code":"# Akamai supports multi-CDN via \"CDN Interconnect\"\n# and \"Multi-CDN\" feature (for premium customers)\n\n# Strategy: Primary = Akamai, failover = secondary CDN\n# Akamai monitors secondary CDN health\n# Traffic shifts based on performance\n\n# Multi-CDN configuration:\n# Property Manager -> Add Behavior -> Multi-CDN\n# Secondary providers: CloudFront, Cloudflare, Fastly\n# Criteria: latency, availability, cost, capacity\n\n# OR use DNS-based multi-CDN:\n# Route53/CNS with health checks\n# example.com CNAME to:\n#   akamai.example.com (Akamai)\n#   cloudfront.example.com (CloudFront)\n# Traffic splits based on DNS latency/health\n\n# Benefits: higher availability, geographic optimization,\n# vendor negotiation leverage, disaster recovery","description":"Akamai multi-CDN configuration options for redundancy and geographic optimization."}],"mcqQuestions":[{"question":"How many PoPs does Akamai have?","options":["200+","1000+","4000+","10000+"],"answer":2,"explanation":"Akamai has 4000+ PoPs in 135+ countries."},{"question":"What routing method does Akamai use?","options":["Anycast","DNS-based with real-time mapping","BGP Anycast","HTTP redirects"],"answer":1,"explanation":"Akamai uses DNS-based routing not Anycast."},{"question":"What is Kona Site Defender?","options":["A CDN caching service","Akamai's security suite","A media player","A DNS service"],"answer":1,"explanation":"Kona Site Defender is Akamai\\'s enterprise security suite."},{"question":"What is Akamai\\'s unique positioning?","options":["Cheapest CDN","Largest edge network, enterprise focus","Best for startups","Open source CDN"],"answer":1,"explanation":"Akamai is the largest CDN focused on enterprise customers."},{"question":"What is Property Manager?","options":["Server management","CDN configuration interface","Property listing","Load balancer"],"answer":1,"explanation":"Property Manager is Akamai\\'s rule-based configuration interface."},{"question":"What is Image & Video Manager?","options":["Media player","Server-side transformation service","Video editor","Streaming protocol"],"answer":1,"explanation":"Image & Video Manager is for server-side media transformation."}]};